/* ══════════════════════════════════════════════
   render.js — Road Rash Runner
   All canvas drawing: background, road, game
   objects, particles, HUD overlays, and every
   game screen (splash, intro, shop, HUD …).
══════════════════════════════════════════════ */
/* ── Preloaded game images (base64 embedded, loaded once) ── */
(function(){
  const _li=new Image();
  _li.src='data:image/png;base64,';
  window._LANE_HAVOC_LOGO=_li;
  const _ci=new Image();
  _ci.src='data:image/png;base64,';
  window._SPLASH_CAR=_ci;
})();


/* ══════════════════════════════════════════════
   DRAW — BACKGROUND (flat dark fill)
══════════════════════════════════════════════ */
function drawBackground(){
  ctx.fillStyle='#0a0c14';
  ctx.fillRect(0,0,W,H);
}

function drawWeatherOverlay(){
  if(weatherType==='clear'&&!weatherMsg&&roadworksWarnTimer<=0)return;
  const wAlpha=Math.min(1, weatherTimer/90, (weatherTotalDur-weatherTimer+1)/90+0.01);
  if(weatherType==='rain')      _drawRain(wAlpha);
  else if(weatherType==='fog')  _drawFog(wAlpha);
  else if(weatherType==='dust') _drawDust(wAlpha);
  else if(weatherType==='roadworks') _drawRoadWorks();

  // ── Roadworks lane-4 warning arrows (shown 3s before roadworks starts) ──
  if(roadworksWarnTimer>0 && weatherType!=='roadworks'){
    const wt=roadworksWarnTimer;
    // alpha: fade in 20f, hold, fade out last 20f
    const wa=clamp(Math.min(wt/20,(180-wt+1)/20+0.5),0,1);
    // Pulse the arrows
    const pulse=0.7+fastSin(frameCount*0.22)*0.3;
    ctx.save();ctx.globalAlpha=wa*pulse;

    // Lane 4 (rightmost) danger zone background flash
    ctx.fillStyle='rgba(255,80,0,0.18)';
    ctx.fillRect(310,0,60,H);

    // Animated downward-pointing arrows in lane 4
    const arrowX=340;
    const arrowOff=(frameCount*3)%60; // scroll arrows downward
    for(let ay=arrowOff-60;ay<H+60;ay+=60){
      ctx.save();
      ctx.globalAlpha=wa*pulse*clamp(1-(Math.abs(ay-H/2)/(H*0.55)),0.1,1);
      ctx.fillStyle='#ff6b00';
      ctx.shadowColor='#ff6b00';ctx.shadowBlur=14;
      // Arrow body
      ctx.beginPath();
      ctx.moveTo(arrowX,ay+18);
      ctx.lineTo(arrowX-12,ay);
      ctx.lineTo(arrowX-6,ay);
      ctx.lineTo(arrowX-6,ay-14);
      ctx.lineTo(arrowX+6,ay-14);
      ctx.lineTo(arrowX+6,ay);
      ctx.lineTo(arrowX+12,ay);
      ctx.closePath();
      ctx.fill();
      ctx.restore();
    }

    // Warning label above the lane
    ctx.save();
    ctx.globalAlpha=wa;
    ctx.fillStyle='rgba(6,8,18,0.82)';
    rr(298,36,84,24,6);ctx.fill();
    ctx.strokeStyle='rgba(255,100,0,0.8)';ctx.lineWidth=1.2;
    rr(298,36,84,24,6);ctx.stroke();
    ctx.font="bold 8px 'Orbitron',sans-serif";
    ctx.fillStyle='#ff8c00';ctx.shadowColor='#ff6b00';ctx.shadowBlur=8;
    ctx.textAlign='center';ctx.textBaseline='middle';
    ctx.fillText('⚠ LANE 4',340,48);
    ctx.shadowBlur=0;
    ctx.font="600 7px 'Rajdhani',sans-serif";
    ctx.fillStyle='rgba(255,180,100,0.9)';
    ctx.fillText('BLOCKED SOON',340,58);
    ctx.restore();

    ctx.restore();
  }

  // Weather notification — mid-screen, drifts downward, fades out
  if(weatherMsg){
    // timer counts DOWN from 180 to 0
    const elapsed = 180 - weatherMsg.timer;
    const FADE_IN = 18, FADE_OUT_START = 120;
    let a;
    if(elapsed < FADE_IN)            a = elapsed / FADE_IN;
    else if(weatherMsg.timer > 60)   a = 1;
    else                             a = weatherMsg.timer / 60;
    a = clamp(a, 0, 1);

    // Start at vertical centre, drift down ~30px over full life
    const driftY = H/2 - 10 + (elapsed / 180) * 30;

    ctx.save(); ctx.globalAlpha = a * 0.96;
    ctx.textAlign = 'center'; ctx.textBaseline = 'middle';

    // Pill
    const mW = 230, mH = 44, mX = (W - mW)/2, mY = driftY - mH/2;
    ctx.fillStyle = 'rgba(6,8,20,0.80)';
    rr(mX, mY, mW, mH, 10); ctx.fill();
    ctx.strokeStyle = 'rgba(255,255,255,0.14)'; ctx.lineWidth = 1;
    rr(mX, mY, mW, mH, 10); ctx.stroke();

    // Text — Orbitron for weather name, consistent with game feel
    ctx.shadowColor = 'rgba(200,220,255,0.6)'; ctx.shadowBlur = 14;
    ctx.fillStyle = '#e2e8f0';
    ctx.font = "700 16px 'Orbitron', impact, sans-serif";
    ctx.fillText(weatherMsg.text, W/2, driftY);
    ctx.shadowBlur = 0;
    ctx.restore();
  }
}
function _drawRain(alpha){
  // Wet overlay
  ctx.save();ctx.globalAlpha=0.07*alpha;
  ctx.fillStyle='rgba(130,160,200,1)';ctx.fillRect(0,0,W,H);ctx.restore();
  // Rain streaks
  ctx.save();ctx.strokeStyle=`rgba(160,190,230,${0.50*alpha})`;
  ctx.lineWidth=1;
  for(let i=0;i<_RAIN_POOL._n;i++){
    const d=_RAIN_POOL[i];if(!d._active)continue;
    ctx.beginPath();ctx.moveTo(d.x,d.y);ctx.lineTo(d.x-d.len*0.22,d.y+d.len);ctx.stroke();
  }
  ctx.restore();
  // Puddle ripple hint on road
  ctx.save();ctx.globalAlpha=0.04*alpha;
  ctx.fillStyle='rgba(120,160,200,1)';
  ctx.fillRect(ROAD_L,0,ROAD_W,H);
  ctx.restore();
}
function _drawFog(alpha){
  const fa=alpha*0.75;
  if(!GC.fog){
    const fg=ctx.createLinearGradient(0,0,0,H);
    fg.addColorStop(0,  'rgba(185,200,220,1)');
    fg.addColorStop(0.20,'rgba(185,200,220,0.86)');
    fg.addColorStop(0.45,'rgba(185,200,220,0.47)');
    fg.addColorStop(0.68,'rgba(185,200,220,0.16)');
    fg.addColorStop(1,  'rgba(185,200,220,0)');
    GC.fog=fg;
  }
  ctx.save();ctx.globalAlpha=fa;
  ctx.fillStyle=GC.fog;ctx.fillRect(0,0,W,H);
  ctx.restore();
}
function _drawDust(alpha){
  // Warm tint overlay — reduced so obstacles stay visible
  ctx.save();ctx.globalAlpha=0.09*alpha;
  ctx.fillStyle='rgba(160,110,35,1)';ctx.fillRect(0,0,W,H);ctx.restore();
  // Dust particles — lighter opacity
  ctx.save();
  for(let i=0;i<_DUST_POOL._n;i++){
    const p=_DUST_POOL[i];if(!p._active)continue;
    ctx.globalAlpha=p.life*0.30*alpha;
    ctx.fillStyle=`rgba(${175+p.g},${125+p.g},40,1)`;
    ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);ctx.fill();
  }
  ctx.restore();
  // Horizontal streaks for motion
  ctx.save();ctx.globalAlpha=0.05*alpha;
  ctx.strokeStyle='rgba(180,130,50,1)';ctx.lineWidth=1;
  for(let i=0;i<8;i++){
    const sy=(i+frameCount*0.2)%(H*0.5)+H*0.25;
    ctx.beginPath();ctx.moveTo(0,sy);ctx.lineTo(W,sy+12);ctx.stroke();
  }
  ctx.restore();
}
function _drawRoadWorks(){
  // Striped orange/dark zone on lane 3 area (right quarter of road)
  ctx.save();
  const stripeH=22;
  const stripeOff=(dashOff*1.2)%stripeH;
  // Dim entire lane 3 zone
  ctx.globalAlpha=0.45;
  for(let y=-stripeH+stripeOff;y<H+stripeH;y+=stripeH){
    const even=Math.floor((y+stripeH)/stripeH)%2===0;
    ctx.fillStyle=even?'rgba(220,110,20,0.70)':'rgba(15,15,15,0.55)';
    ctx.fillRect(310,y,60,stripeH);
  }
  // Warning edge line
  ctx.globalAlpha=1;
  ctx.shadowColor='#e67e22';ctx.shadowBlur=8;
  ctx.strokeStyle='#e67e22';ctx.lineWidth=2.5;ctx.setLineDash([16,10]);ctx.lineDashOffset=-dashOff;
  ctx.beginPath();ctx.moveTo(310,0);ctx.lineTo(310,H);ctx.stroke();
  ctx.setLineDash([]);ctx.shadowBlur=0;
  // Traffic cones scrolling down
  for(let cy=((dashOff*0.9)|0)%110;cy<H+20;cy+=110) _drawCone(309,cy);
  // "ROAD WORKS" label
  ctx.fillStyle='rgba(230,120,20,0.92)';
  ctx.font="bold 8px 'Orbitron',sans-serif";ctx.textAlign='center';
  ctx.fillText('ROAD WORKS',340,26);
  ctx.restore();
}
function _drawCone(x,y){
  ctx.fillStyle='#e67e22';
  ctx.beginPath();ctx.moveTo(x,y-18);ctx.lineTo(x-8,y);ctx.lineTo(x+8,y);ctx.closePath();ctx.fill();
  ctx.fillStyle='#f5f5e8';ctx.fillRect(x-6,y-12,12,3);
  ctx.fillStyle='#2a2a2a';ctx.fillRect(x-9,y,18,3);
}

function drawRoad(){
  // ── Side kerb strips — flat dark fill ────────────────────────────────
  ctx.fillStyle='#12151e';
  ctx.fillRect(0,0,ROAD_L,H);
  ctx.fillRect(ROAD_R,0,W-ROAD_R,H);

  // ── Road body — cached gradient ──────────────────────────────────────
  ctx.fillStyle=GC.road;ctx.fillRect(ROAD_L,0,ROAD_W,H);

  // Subtle horizontal speed lines (dark bands)
  ctx.save();ctx.globalAlpha=0.06;ctx.fillStyle='#000';
  const bandH=80,bandOff=dashOff%bandH;
  for(let y=-bandH+bandOff;y<H+bandH;y+=bandH)ctx.fillRect(ROAD_L,y,ROAD_W,bandH*0.45);
  ctx.restore();

  // Kerb edge markers — red/white stripes right at road boundary
  const stripeH=18,stripeOff=Math.floor(dashOff%stripeH);
  for(let y=-stripeH+stripeOff;y<H+stripeH;y+=stripeH){
    const evenRow=Math.floor((y+stripeH)/stripeH)%2===0;
    ctx.fillStyle=evenRow?'#c0392b':'#ecf0f1';
    ctx.fillRect(ROAD_L-6,y,6,stripeH);
    ctx.fillRect(ROAD_R,y,6,stripeH);
  }

  // Edge lines – bright amber with subtle glow
  ctx.save();
  ctx.shadowColor='rgba(245,158,11,0.5)';ctx.shadowBlur=8;
  ctx.strokeStyle='#f59e0b';ctx.lineWidth=2.5;ctx.setLineDash([]);
  ctx.beginPath();ctx.moveTo(ROAD_L,0);ctx.lineTo(ROAD_L,H);ctx.stroke();
  ctx.beginPath();ctx.moveTo(ROAD_R,0);ctx.lineTo(ROAD_R,H);ctx.stroke();
  ctx.restore();

  // Centre lane dashes — high-contrast white (0.80 opacity for speed readability)
  ctx.strokeStyle='rgba(255,255,255,0.80)';ctx.lineWidth=1.8;
  ctx.setLineDash([28,18]);ctx.lineDashOffset=-dashOff;
  [120,200,280].forEach(x=>{
    ctx.beginPath();ctx.moveTo(x,0);ctx.lineTo(x,H);ctx.stroke();
  });
  ctx.setLineDash([]);

  // Road sheen – cached gradient
  ctx.fillStyle=GC.roadSheen;ctx.fillRect(ROAD_L,0,ROAD_W,H);

  // ── Light-source depth overlay — lighter at horizon (top), darker near player (bottom) ──
  // Creates instant depth perception: road recedes into distance at top
  if(!GC.roadDepth){
    const dg=ctx.createLinearGradient(0,0,0,H);
    dg.addColorStop(0,'rgba(255,255,255,0.07)');  // slightly brighter at horizon
    dg.addColorStop(0.35,'rgba(255,255,255,0.01)');
    dg.addColorStop(0.65,'rgba(0,0,0,0.04)');
    dg.addColorStop(1,'rgba(0,0,0,0.13)');         // noticeably darker near player
    GC.roadDepth=dg;
  }
  ctx.fillStyle=GC.roadDepth;ctx.fillRect(ROAD_L,0,ROAD_W,H);
}

/* ══════════════════════════════════════════════
   DRAW — CAR  (gradient body, detailed)
══════════════════════════════════════════════ */
function drawCar(cx,cy,bodyCol,hlCol,isPlayer,dmg,tilt){
  const rgb=hexToRgb(bodyCol);
  // Wider, chunkier sports car proportions — more like reference image
  const bw=42, bh=68;
  const bx=cx-bw/2, by=cy-bh/2;

  if(isPlayer&&ghostTimer>0){ctx.save();ctx.globalAlpha=0.38;}

  // Ground shadow — elongated ellipse under the car
  ctx.save();ctx.globalAlpha=0.32;
  const shG=ctx.createRadialGradient(cx,cy+bh*0.46,2,cx,cy+bh*0.46,bw*0.9);
  shG.addColorStop(0,'rgba(0,0,0,0.7)');shG.addColorStop(1,'transparent');
  ctx.fillStyle=shG;ctx.beginPath();ctx.ellipse(cx,cy+bh*0.46,bw*0.9,10,0,0,Math.PI*2);ctx.fill();
  ctx.restore();

  // Tilt on lane change
  if(isPlayer&&tilt&&Math.abs(tilt)>0.004){ctx.save();ctx.translate(cx,cy);ctx.rotate(tilt);ctx.translate(-cx,-cy);}
  if(dmg>0){ctx.save();ctx.translate(cx,cy);ctx.rotate((Math.random()-0.5)*0.15*clamp(dmg,0,1));ctx.translate(-cx,-cy);}

  // ── WHEEL ARCHES (drawn first, behind body) ──
  // Flared arches give the sporty low-slung look
  ctx.fillStyle=dmg>0?'#2a1a1a':shade(bodyCol,-60);
  // Front arch left & right
  ctx.beginPath();ctx.ellipse(bx+2,by+22,9,6,0,0,Math.PI*2);ctx.fill();
  ctx.beginPath();ctx.ellipse(bx+bw-2,by+22,9,6,0,0,Math.PI*2);ctx.fill();
  // Rear arch left & right
  ctx.beginPath();ctx.ellipse(bx+2,by+bh-22,9,6,0,0,Math.PI*2);ctx.fill();
  ctx.beginPath();ctx.ellipse(bx+bw-2,by+bh-22,9,6,0,0,Math.PI*2);ctx.fill();

  // ── MAIN BODY — trapezoidal (wider at base = more 3D feel) ──
  const _bodyKey=bodyCol+(dmg>0?'_d3':'_3');
  if(!GC['cb3_'+_bodyKey]){
    const bg=ctx.createLinearGradient(bx,0,bx+bw,0);
    if(dmg>0){
      bg.addColorStop(0,`rgba(${rgb.r*.3|0},${rgb.g*.3|0},${rgb.b*.3|0},1)`);
      bg.addColorStop(0.5,`rgba(${rgb.r*.4|0},${rgb.g*.4|0},${rgb.b*.4|0},1)`);
      bg.addColorStop(1,`rgba(${rgb.r*.25|0},${rgb.g*.25|0},${rgb.b*.25|0},1)`);
    } else {
      bg.addColorStop(0,shade(bodyCol,-45));
      bg.addColorStop(0.18,shade(bodyCol,-15));
      bg.addColorStop(0.42,bodyCol);
      bg.addColorStop(0.72,shade(bodyCol,-10));
      bg.addColorStop(1,shade(bodyCol,-55));
    }
    GC['cb3_'+_bodyKey]=bg;
  }
  // Trapezoidal body path — slightly narrower at top
  ctx.fillStyle=GC['cb3_'+_bodyKey];
  ctx.beginPath();
  ctx.moveTo(bx+4,by+14);ctx.lineTo(bx+bw-4,by+14);   // top edge (narrower)
  ctx.lineTo(bx+bw,by+bh-4);ctx.lineTo(bx,by+bh-4);   // bottom edge (full width)
  ctx.closePath();ctx.fill();

  // ── 2px dark outline on enemy cars — makes them chunky and readable at speed ──
  if(!isPlayer){
    ctx.strokeStyle='rgba(0,0,0,0.75)';ctx.lineWidth=2;
    ctx.beginPath();
    ctx.moveTo(bx+4,by+14);ctx.lineTo(bx+bw-4,by+14);
    ctx.lineTo(bx+bw,by+bh-4);ctx.lineTo(bx,by+bh-4);
    ctx.closePath();ctx.stroke();
  }

  // Side panel crease — longitudinal highlight line for depth
  if(dmg===0){
    ctx.save();ctx.globalAlpha=0.22;
    ctx.strokeStyle='#fff';ctx.lineWidth=1.5;
    ctx.beginPath();ctx.moveTo(bx+5,by+22);ctx.lineTo(bx+5,by+bh-26);ctx.stroke();
    ctx.beginPath();ctx.moveTo(bx+bw-5,by+22);ctx.lineTo(bx+bw-5,by+bh-26);ctx.stroke();
    ctx.restore();
  }

  // Damage overlay
  if(dmg>0){
    ctx.save();ctx.globalAlpha=clamp(dmg,0,1)*0.65;ctx.fillStyle='#1a0000';
    ctx.beginPath();ctx.moveTo(bx+4,by+14);ctx.lineTo(bx+bw-4,by+14);ctx.lineTo(bx+bw,by+bh-4);ctx.lineTo(bx,by+bh-4);ctx.closePath();ctx.fill();ctx.restore();
    ctx.strokeStyle='rgba(255,140,0,0.9)';ctx.lineWidth=1.5;
    ctx.beginPath();ctx.moveTo(bx+10,by+18);ctx.lineTo(bx+20,by+38);ctx.lineTo(bx+16,by+54);ctx.stroke();
    ctx.beginPath();ctx.moveTo(bx+bw-11,by+22);ctx.lineTo(bx+bw-20,by+44);ctx.stroke();
  }

  // ── ROOF / CABIN — narrower, domed ──
  const _roofKey3=bodyCol+(dmg>0?'_rd3':'_r3');
  if(!GC['cr3_'+_roofKey3]){
    const rg=ctx.createLinearGradient(0,0,bw-10,0);
    rg.addColorStop(0,shade(bodyCol,dmg>0?-130:-70));
    rg.addColorStop(0.3,shade(bodyCol,dmg>0?-110:-40));
    rg.addColorStop(0.7,shade(bodyCol,dmg>0?-110:-38));
    rg.addColorStop(1,shade(bodyCol,dmg>0?-130:-70));
    GC['cr3_'+_roofKey3]=rg;
  }
  // Roof path — tapered trapezoid
  ctx.fillStyle=GC['cr3_'+_roofKey3];
  ctx.beginPath();
  ctx.moveTo(bx+10,by+13);ctx.lineTo(bx+bw-10,by+13);
  ctx.lineTo(bx+bw-6,by+34);ctx.lineTo(bx+6,by+34);
  ctx.closePath();ctx.fill();

  // ── WINDSHIELD — large, angled, tinted ──
  ctx.save();
  const wsG=ctx.createLinearGradient(bx+12,by+8,bx+12,by+28);
  if(dmg>0){
    wsG.addColorStop(0,'rgba(50,70,90,0.55)');wsG.addColorStop(1,'rgba(30,50,70,0.40)');
  } else {
    wsG.addColorStop(0,'rgba(160,220,255,0.92)');
    wsG.addColorStop(0.35,'rgba(120,200,255,0.80)');
    wsG.addColorStop(1,'rgba(60,140,210,0.55)');
  }
  ctx.fillStyle=wsG;
  ctx.beginPath();
  ctx.moveTo(bx+12,by+14);ctx.lineTo(bx+bw-12,by+14);
  ctx.lineTo(bx+bw-8,by+31);ctx.lineTo(bx+8,by+31);
  ctx.closePath();ctx.fill();
  // Windshield glare streak
  if(dmg===0){
    ctx.globalAlpha=0.30;ctx.fillStyle='#fff';
    ctx.beginPath();ctx.moveTo(bx+14,by+15);ctx.lineTo(bx+20,by+15);ctx.lineTo(bx+16,by+29);ctx.lineTo(bx+11,by+29);ctx.closePath();ctx.fill();
  }
  // Crack
  if(dmg>0){
    ctx.globalAlpha=1;ctx.strokeStyle='rgba(255,255,255,0.7)';ctx.lineWidth=0.8;
    ctx.beginPath();ctx.moveTo(cx,by+15);ctx.lineTo(cx-5,by+23);ctx.lineTo(cx+4,by+30);ctx.stroke();
  }
  ctx.restore();

  // ── SIDE MIRRORS ──
  if(dmg===0){
    ctx.fillStyle=shade(bodyCol,-40);
    ctx.fillRect(bx-5,by+18,5,4);   // left mirror
    ctx.fillRect(bx+bw,by+18,5,4);  // right mirror
  }

  // ── REAR SPOILER (player only — facing player means spoiler at bottom) ──
  if(isPlayer&&dmg===0){
    ctx.fillStyle=shade(bodyCol,-50);
    ctx.fillRect(bx,by+bh-8,bw,4);          // spoiler blade
    ctx.fillStyle=shade(bodyCol,-70);
    ctx.fillRect(bx+6,by+bh-10,4,4);        // left strut
    ctx.fillRect(bx+bw-10,by+bh-10,4,4);   // right strut
  }

  // ── FRONT BUMPER / HOOD (at top for player facing up) ──
  const bumperCol=dmg>0?'#2a1a1a':shade(bodyCol,-35);
  ctx.fillStyle=bumperCol;
  ctx.beginPath();ctx.moveTo(bx+4,by+14);ctx.lineTo(bx+bw-4,by+14);ctx.lineTo(bx+bw-2,by+18);ctx.lineTo(bx+2,by+18);ctx.closePath();ctx.fill();

  // ── HEADLIGHTS — wide LED-style bars ──
  const hlY=by+2;
  const tlY=by+bh-7;
  if(dmg===0){
    // Headlight housing
    ctx.fillStyle='#222230';
    ctx.fillRect(bx+2,hlY,14,7);ctx.fillRect(bx+bw-16,hlY,14,7);
    // LED glow
    ctx.save();ctx.shadowColor=isPlayer?hlCol:'#d0e8ff';ctx.shadowBlur=isPlayer?22:14;
    ctx.globalAlpha=isPlayer?0.85:0.65;ctx.fillStyle=isPlayer?hlCol:'#d0e8ff';
    ctx.fillRect(bx+3,hlY+1,12,5);ctx.fillRect(bx+bw-15,hlY+1,12,5);ctx.restore();
  } else {
    ctx.fillStyle='#3a3a3a';ctx.fillRect(bx+3,hlY+1,12,5);ctx.fillRect(bx+bw-15,hlY+1,12,5);
  }
  // Light cone (player, healthy)
  if(isPlayer&&dmg===0){
    const _lcKey3='lc3_'+hlCol;
    if(!GC[_lcKey3]){
      const lcg=ctx.createLinearGradient(0,0,0,-70);
      lcg.addColorStop(0,hlCol);lcg.addColorStop(0.6,'rgba(255,255,200,0.08)');lcg.addColorStop(1,'transparent');
      GC[_lcKey3]=lcg;
    }
    ctx.save();ctx.globalAlpha=0.07;ctx.translate(bx+9,hlY);ctx.fillStyle=GC[_lcKey3];
    ctx.beginPath();ctx.moveTo(-7,0);ctx.lineTo(7,0);ctx.lineTo(16,-70);ctx.lineTo(-16,-70);ctx.closePath();ctx.fill();
    ctx.translate(bw-18,0);
    ctx.beginPath();ctx.moveTo(-7,0);ctx.lineTo(7,0);ctx.lineTo(16,-70);ctx.lineTo(-16,-70);ctx.closePath();ctx.fill();
    ctx.restore();
  }

  // ── TAIL LIGHTS — wide red/orange bars ──
  ctx.save();
  ctx.fillStyle='#1a0a0a';ctx.fillRect(bx+2,tlY-1,14,8);ctx.fillRect(bx+bw-16,tlY-1,14,8);
  if(isPlayer&&dmg===0){ctx.shadowColor='#ff2222';ctx.shadowBlur=14;}
  ctx.fillStyle=isPlayer?'#ff3333':'#cc1100';
  ctx.fillRect(bx+3,tlY,12,6);ctx.fillRect(bx+bw-15,tlY,12,6);
  // Brake light accent (inner bright strip)
  if(isPlayer&&dmg===0){
    ctx.globalAlpha=0.7;ctx.fillStyle='#ff9999';
    ctx.fillRect(bx+4,tlY+1,10,2);ctx.fillRect(bx+bw-14,tlY+1,10,2);
  }
  ctx.restore();

  // ── WHEELS — wide low-profile tyres with detailed rims ──
  const _wSpin=(isPlayer?spd:4)*frameCount*0.05;
  const wheelDef=[
    [bx-7,by+16,10,14],  // front-left
    [bx+bw-3,by+16,10,14], // front-right
    [bx-7,by+bh-30,10,14], // rear-left
    [bx+bw-3,by+bh-30,10,14]  // rear-right
  ];
  wheelDef.forEach(([wx,wy,ww,wh])=>{
    const wcx=wx+ww/2, wcy=wy+wh/2;
    // Tyre
    ctx.fillStyle='#181820';rr(wx,wy,ww,wh,3);ctx.fill();
    ctx.strokeStyle='#2a2a35';ctx.lineWidth=0.8;rr(wx,wy,ww,wh,3);ctx.stroke();
    // Rim disc
    ctx.save();ctx.beginPath();rr(wx+1,wy+1,ww-2,wh-2,2);ctx.clip();
    ctx.fillStyle='#7a7a90';ctx.fillRect(wx+1,wy+1,ww-2,wh-2);
    // Animated spokes
    ctx.translate(wcx,wcy);ctx.rotate(_wSpin);
    ctx.strokeStyle='#4a4a60';ctx.lineWidth=1;
    for(let s=0;s<5;s++){
      const a=(s/5)*Math.PI*2;
      ctx.beginPath();ctx.moveTo(0,0);ctx.lineTo(Math.cos(a)*4,Math.sin(a)*5);ctx.stroke();
    }
    // Rim highlight
    ctx.strokeStyle='rgba(200,200,220,0.5)';ctx.lineWidth=0.5;
    ctx.beginPath();ctx.ellipse(0,0,3,4,0,0,Math.PI*2);ctx.stroke();
    ctx.restore();
  });

  // ── GUN BARREL + RED GLOW — visible only when player has gun equipped ──
  if(isPlayer && typeof gunActive!=='undefined' && gunActive && dmg===0){
    ctx.save();
    // Red body glow — pulsing outline around entire car
    const _gPulse=0.35+fastSin(frameCount*0.14)*0.15;
    ctx.shadowColor='#ef4444';ctx.shadowBlur=20;
    ctx.strokeStyle=`rgba(239,68,68,${_gPulse})`;ctx.lineWidth=2;
    rr(bx-1,by-1,bw+2,bh+2,7);ctx.stroke();
    ctx.shadowBlur=0;
    // Gun barrel — centered, protrudes from front (top) of car
    const _brlW=5,_brlH=13,_brlX=cx-_brlW/2,_brlY=by-_brlH+3;
    // Barrel body — dark gunmetal
    ctx.fillStyle='#1a1c28';
    rr(_brlX,_brlY,_brlW,_brlH,2);ctx.fill();
    // Barrel side highlight
    ctx.save();ctx.globalAlpha=0.45;ctx.fillStyle='#7a7e94';
    ctx.fillRect(_brlX+1,_brlY+2,1,_brlH-4);ctx.restore();
    // Muzzle ring — bright red tip with glow
    ctx.shadowColor='#ef4444';ctx.shadowBlur=10;
    ctx.fillStyle='#ef4444';
    ctx.fillRect(_brlX,_brlY,_brlW,3);
    ctx.shadowBlur=0;
    ctx.restore();
  }

  if(dmg>0)ctx.restore();
  if(isPlayer&&tilt&&Math.abs(tilt)>0.004)ctx.restore();
  if(isPlayer&&ghostTimer>0)ctx.restore();
}

/* ══════════════════════════════════════════════
   DRAW — OBSTACLE  (richer detail)
══════════════════════════════════════════════ */
function drawObstacle(o,alpha){
  if(alpha!==undefined){ctx.save();ctx.globalAlpha=alpha;}
  const x=LANE_XS[o.lane];
  if(o.type==='stone'){
    // ── 3D CHROME SPHERE (like reference image) ──
    const r=17;
    // Ground shadow ellipse
    ctx.save();ctx.globalAlpha=0.38;
    const shG=ctx.createRadialGradient(x+3,o.y+r*0.7,1,x+3,o.y+r*0.7,r*1.1);
    shG.addColorStop(0,'rgba(0,0,0,0.7)');shG.addColorStop(1,'transparent');
    ctx.fillStyle=shG;ctx.beginPath();ctx.ellipse(x+3,o.y+r*0.65,r*0.85,r*0.28,0,0,Math.PI*2);ctx.fill();
    ctx.restore();
    // Main sphere body — radial gradient from bright top-left to dark bottom-right
    const sg=ctx.createRadialGradient(x-r*0.38,o.y-r*0.38,r*0.04,x,o.y,r);
    sg.addColorStop(0,'#ffffff');
    sg.addColorStop(0.18,'#e0e4ec');
    sg.addColorStop(0.48,'#9098a8');
    sg.addColorStop(0.78,'#4a5060');
    sg.addColorStop(1,'#1a1c22');
    ctx.fillStyle=sg;ctx.beginPath();ctx.arc(x,o.y,r,0,Math.PI*2);ctx.fill();
    // Rim stroke for definition
    ctx.strokeStyle='rgba(60,65,80,0.7)';ctx.lineWidth=0.8;
    ctx.beginPath();ctx.arc(x,o.y,r,0,Math.PI*2);ctx.stroke();
    // Primary specular highlight — bright white dot top-left
    ctx.save();ctx.globalAlpha=0.92;ctx.fillStyle='#ffffff';
    ctx.beginPath();ctx.ellipse(x-r*0.34,o.y-r*0.34,r*0.22,r*0.16,Math.PI*0.75,0,Math.PI*2);ctx.fill();ctx.restore();
    // Secondary specular — smaller, sharper
    ctx.save();ctx.globalAlpha=0.55;ctx.fillStyle='#ffffff';
    ctx.beginPath();ctx.arc(x-r*0.26,o.y-r*0.26,r*0.08,0,Math.PI*2);ctx.fill();ctx.restore();
    // Embossed chevron arrows — like reference image
    ctx.save();ctx.globalAlpha=0.28;ctx.strokeStyle='#c8ccd8';ctx.lineWidth=1.8;ctx.lineCap='round';ctx.lineJoin='round';
    const aw=6,ah=4;
    // Two stacked chevrons pointing right
    ctx.beginPath();ctx.moveTo(x-aw,o.y-ah);ctx.lineTo(x,o.y);ctx.lineTo(x-aw,o.y+ah);ctx.stroke();
    ctx.beginPath();ctx.moveTo(x+1,o.y-ah);ctx.lineTo(x+aw+1,o.y);ctx.lineTo(x+1,o.y+ah);ctx.stroke();
    ctx.restore();
  } else {
    // ── WHITE/SILVER MANHOLE with RED X ──
    // Ground shadow ellipse
    ctx.save();ctx.globalAlpha=0.35;
    const _mhShG=ctx.createRadialGradient(x+4,o.y+14,1,x+4,o.y+14,28);
    _mhShG.addColorStop(0,'rgba(0,0,0,0.7)');_mhShG.addColorStop(1,'transparent');
    ctx.fillStyle=_mhShG;ctx.beginPath();ctx.ellipse(x+4,o.y+16,28,10,0,0,Math.PI*2);ctx.fill();
    ctx.restore();
    // Outer rim — bright metallic
    const rimG=ctx.createRadialGradient(x-6,o.y-6,2,x,o.y,26);
    rimG.addColorStop(0,'#f1f5f9');rimG.addColorStop(0.5,'#cbd5e1');rimG.addColorStop(1,'#94a3b8');
    ctx.fillStyle=rimG;
    ctx.beginPath();ctx.ellipse(x,o.y,26,17,0,0,Math.PI*2);ctx.fill();
    ctx.strokeStyle='#e2e8f0';ctx.lineWidth=2;
    ctx.beginPath();ctx.ellipse(x,o.y,26,17,0,0,Math.PI*2);ctx.stroke();
    // Cover plate
    const covG=ctx.createRadialGradient(x-5,o.y-4,2,x,o.y,18);
    covG.addColorStop(0,'#e2e8f0');covG.addColorStop(0.6,'#b0bec5');covG.addColorStop(1,'#78909c');
    ctx.fillStyle=covG;
    ctx.beginPath();ctx.ellipse(x,o.y,18,12,0,0,Math.PI*2);ctx.fill();
    ctx.strokeStyle='#cfd8dc';ctx.lineWidth=1.2;
    ctx.beginPath();ctx.ellipse(x,o.y,18,12,0,0,Math.PI*2);ctx.stroke();
    // Grid lines
    ctx.strokeStyle='rgba(40,50,60,0.55)';ctx.lineWidth=1;
    for(let i=-2;i<=2;i++){
      ctx.beginPath();ctx.moveTo(x+i*4.5,o.y-10);ctx.lineTo(x+i*4.5,o.y+10);ctx.stroke();
      ctx.beginPath();ctx.moveTo(x-14,o.y+i*3.0);ctx.lineTo(x+14,o.y+i*3.0);ctx.stroke();
    }
    // Rim highlight
    ctx.save();ctx.globalAlpha=0.5;ctx.fillStyle='#ffffff';
    ctx.beginPath();ctx.ellipse(x-6,o.y-7,10,4,Math.PI*0.2,0,Math.PI*2);ctx.fill();ctx.restore();
    // Centre bolt
    const boltG=ctx.createRadialGradient(x-1,o.y-1,0,x,o.y,4);
    boltG.addColorStop(0,'#ffffff');boltG.addColorStop(0.5,'#cbd5e1');boltG.addColorStop(1,'#64748b');
    ctx.fillStyle=boltG;ctx.beginPath();ctx.arc(x,o.y,4,0,Math.PI*2);ctx.fill();
    ctx.strokeStyle='#94a3b8';ctx.lineWidth=0.8;ctx.beginPath();ctx.arc(x,o.y,4,0,Math.PI*2);ctx.stroke();
    // ── RED X — thick, no glow ──
    ctx.save();
    ctx.shadowBlur=0;
    ctx.strokeStyle='#cc0000';ctx.lineWidth=5.5;ctx.lineCap='round';
    ctx.beginPath();ctx.moveTo(x-10,o.y-7);ctx.lineTo(x+10,o.y+7);ctx.stroke();
    ctx.beginPath();ctx.moveTo(x+10,o.y-7);ctx.lineTo(x-10,o.y+7);ctx.stroke();
    ctx.strokeStyle='#ff1111';ctx.lineWidth=2.5;
    ctx.beginPath();ctx.moveTo(x-10,o.y-7);ctx.lineTo(x+10,o.y+7);ctx.stroke();
    ctx.beginPath();ctx.moveTo(x+10,o.y-7);ctx.lineTo(x-10,o.y+7);ctx.stroke();
    ctx.restore();
  }
  if(alpha!==undefined)ctx.restore();
}

/* ══════════════════════════════════════════════
   DRAW — CATTLE (alive – same logic, richer colours)
══════════════════════════════════════════════ */
function drawCattle(c){
  const lsw=fastSin(frameCount*0.28+c.id)*5;
  const bull=c.type==='bull';
  ctx.save();ctx.translate(c.x,c.y);
  if(c.dir<0)ctx.scale(-1,1);

  // Ground shadow
  ctx.save();ctx.globalAlpha=0.28;
  const sh=ctx.createRadialGradient(0,20,2,0,20,34);
  sh.addColorStop(0,'rgba(0,0,0,0.65)');sh.addColorStop(1,'transparent');
  ctx.fillStyle=sh;ctx.beginPath();ctx.ellipse(0,22,32,10,0,0,Math.PI*2);ctx.fill();ctx.restore();

  // ── LEGS — pairs with perspective offset ──
  const legCol=bull?'#7a3a1a':'#a06535';
  const legShade=bull?'#502210':'#7a4a20';
  [[-16,lsw,false],[-7,-lsw,true],[5,lsw,false],[14,-lsw,true]].forEach(([lx,sw,back])=>{
    ctx.fillStyle=back?legShade:legCol;
    rr(lx+sw,10,7,16,2);ctx.fill();
    // Hoof
    ctx.fillStyle='#2a1a0a';rr(lx+sw,24,7,4,1);ctx.fill();
  });

  // ── BODY — volumetric ellipse with top shading ──
  const bodyTop=bull?'#a0522d':'#c8855a';
  const bodyBot=bull?'#6b3318':'#8b5a2b';
  const bodyG=ctx.createLinearGradient(-24,-14,0,18);
  bodyG.addColorStop(0,bodyTop);bodyG.addColorStop(0.5,bull?'#8a4225':'#b06a3a');bodyG.addColorStop(1,bodyBot);
  ctx.fillStyle=bodyG;
  ctx.beginPath();ctx.ellipse(0,0,26,16,0,0,Math.PI*2);ctx.fill();
  // Bold dark outline — makes silhouette instantly readable at speed
  ctx.strokeStyle='rgba(0,0,0,0.82)';ctx.lineWidth=2.8;
  ctx.beginPath();ctx.ellipse(0,0,26,16,0,0,Math.PI*2);ctx.stroke();
  // Body top highlight
  ctx.save();ctx.globalAlpha=0.22;ctx.fillStyle='#fff';
  ctx.beginPath();ctx.ellipse(-4,-8,12,5,Math.PI*0.1,0,Math.PI*2);ctx.fill();ctx.restore();

  // Cow spots
  if(!bull){
    ctx.fillStyle='rgba(40,20,8,0.80)';
    ctx.beginPath();ctx.ellipse(-7,-2,9,6,0.4,0,Math.PI*2);ctx.fill();
    ctx.beginPath();ctx.ellipse(9,5,6,8,-0.3,0,Math.PI*2);ctx.fill();
    // Belly / udder
    ctx.fillStyle='#f5a0a0';ctx.beginPath();ctx.ellipse(-4,14,11,6,0,0,Math.PI*2);ctx.fill();
  }

  // ── HEAD — more dimensional ──
  const headCol=bull?'#a0522d':'#c8855a';
  // Head body
  const headG=ctx.createRadialGradient(28,-8,2,34,-6,16);
  headG.addColorStop(0,bull?'#b06030':'#d4956a');
  headG.addColorStop(1,bull?'#7a3a20':'#8b5a2b');
  ctx.fillStyle=headG;ctx.beginPath();ctx.ellipse(32,-6,15,12,0,0,Math.PI*2);ctx.fill();
  // Head outline
  ctx.strokeStyle='rgba(0,0,0,0.75)';ctx.lineWidth=2;
  ctx.beginPath();ctx.ellipse(32,-6,15,12,0,0,Math.PI*2);ctx.stroke();
  // Snout
  ctx.fillStyle=bull?'#b07a50':'#ddb880';
  ctx.beginPath();ctx.ellipse(43,-1,8,7,0,0,Math.PI*2);ctx.fill();
  // Nostrils
  ctx.fillStyle='#3a2010';ctx.beginPath();ctx.ellipse(41,1,2,1.5,0.2,0,Math.PI*2);ctx.fill();
  ctx.beginPath();ctx.ellipse(45,1,2,1.5,-0.2,0,Math.PI*2);ctx.fill();
  // Eye
  ctx.fillStyle='#111';ctx.beginPath();ctx.arc(26,-11,3,0,Math.PI*2);ctx.fill();
  ctx.fillStyle='rgba(255,255,255,0.9)';ctx.beginPath();ctx.arc(25,-12,1.3,0,Math.PI*2);ctx.fill();
  ctx.fillStyle='rgba(255,255,255,0.5)';ctx.beginPath();ctx.arc(27,-10,0.7,0,Math.PI*2);ctx.fill();
  // Ear
  ctx.fillStyle=headCol;ctx.beginPath();ctx.ellipse(22,-18,5,3,Math.PI*0.3,0,Math.PI*2);ctx.fill();
  ctx.fillStyle='#ff9999';ctx.beginPath();ctx.ellipse(22,-18,3,1.8,Math.PI*0.3,0,Math.PI*2);ctx.fill();

  // ── HORNS ──
  ctx.strokeStyle=bull?'#d4a820':'#d4c890';ctx.lineWidth=3;ctx.lineCap='round';
  if(bull){
    ctx.beginPath();ctx.moveTo(22,-17);ctx.quadraticCurveTo(10,-36,16,-40);ctx.stroke();
    ctx.beginPath();ctx.moveTo(30,-17);ctx.quadraticCurveTo(42,-36,36,-40);ctx.stroke();
  } else {
    ctx.beginPath();ctx.moveTo(22,-17);ctx.quadraticCurveTo(14,-30,19,-34);ctx.stroke();
    ctx.beginPath();ctx.moveTo(30,-17);ctx.quadraticCurveTo(38,-30,34,-34);ctx.stroke();
  }

  // ── TAIL with tuft ──
  ctx.strokeStyle=bull?'#7a4522':'#c0a070';ctx.lineWidth=2.5;ctx.lineCap='round';
  ctx.beginPath();ctx.moveTo(-24,0);ctx.quadraticCurveTo(-40,-12+lsw,-38,-24);ctx.stroke();
  // Tuft
  ctx.fillStyle='#444';ctx.beginPath();ctx.arc(-38,-24,5,0,Math.PI*2);ctx.fill();
  ctx.strokeStyle='#333';ctx.lineWidth=1.5;
  for(let t=0;t<4;t++){
    const ta=(t/4)*Math.PI-Math.PI/2;
    ctx.beginPath();ctx.moveTo(-38,-24);ctx.lineTo(-38+Math.cos(ta)*7,-24+Math.sin(ta)*7);ctx.stroke();
  }
  ctx.restore();
}

/* ══════════════════════════════════════════════
   DRAW — CATTLE (dead)
══════════════════════════════════════════════ */
function drawDeadCattle(c){
  ctx.save();ctx.translate(c.x,c.y);ctx.rotate(Math.PI/2);
  const bull=c.type==='bull';
  // Blood pool
  ctx.save();ctx.globalAlpha=0.70;
  const bpG=ctx.createRadialGradient(0,0,4,0,0,42);
  bpG.addColorStop(0,'rgba(140,0,0,0.9)');bpG.addColorStop(0.5,'rgba(100,0,0,0.6)');bpG.addColorStop(1,'rgba(60,0,0,0)');
  ctx.fillStyle=bpG;ctx.beginPath();ctx.ellipse(0,0,40,24,0,0,Math.PI*2);ctx.fill();ctx.restore();
  // Body — lying flat, foreshortened
  const dBodyG=ctx.createLinearGradient(-22,-12,22,12);
  if(bull){dBodyG.addColorStop(0,'#7a4828');dBodyG.addColorStop(1,'#4a2810');}
  else{dBodyG.addColorStop(0,'#c8b8a0');dBodyG.addColorStop(1,'#a09070');}
  ctx.fillStyle=dBodyG;rr(-24,-12,48,24,9);ctx.fill();
  // Blood stain overlay on body
  ctx.save();ctx.globalAlpha=0.50;ctx.fillStyle='#800000';rr(-24,-12,48,24,9);ctx.fill();ctx.restore();
  // Head — slumped
  ctx.fillStyle=bull?'#6a3820':'#d8c8a8';
  ctx.beginPath();ctx.ellipse(28,-5,13,10,0.2,0,Math.PI*2);ctx.fill();
  // X eyes
  ctx.strokeStyle='#111';ctx.lineWidth=2.5;ctx.lineCap='round';
  ctx.beginPath();ctx.moveTo(23,-11);ctx.lineTo(28,-5);ctx.stroke();
  ctx.beginPath();ctx.moveTo(28,-11);ctx.lineTo(23,-5);ctx.stroke();
  // Legs up in the air (stiff)
  ctx.fillStyle=bull?'#5a3018':'#a09070';
  [[-14,-16],[-6,-18],[4,-18],[12,-16]].forEach(([lx,ly])=>{
    ctx.save();ctx.translate(lx,0);ctx.rotate(-Math.PI*0.35);
    rr(-3,ly,6,14,2);ctx.fill();ctx.restore();
  });
  ctx.restore();
}

/* ══════════════════════════════════════════════
   HELPER — small HUD coin icon  (reused wherever
   a coin symbol is needed in UI overlays)
   cx/cy = centre, r = radius
══════════════════════════════════════════════ */
function _coinIco(cx,cy,r){
  ctx.save();
  ctx.shadowColor='rgba(251,191,36,0.80)';ctx.shadowBlur=r*1.4;
  const g=ctx.createRadialGradient(cx-r*0.35,cy-r*0.35,0,cx,cy,r);
  g.addColorStop(0,'#fff8d0');g.addColorStop(0.38,'#f59e0b');
  g.addColorStop(0.75,'#b45309');g.addColorStop(1,'#7c2d00');
  ctx.fillStyle=g;
  ctx.beginPath();ctx.arc(cx,cy,r,0,Math.PI*2);ctx.fill();
  // inner highlight
  ctx.shadowBlur=0;ctx.globalAlpha=0.55;ctx.fillStyle='#fff8d0';
  ctx.beginPath();ctx.ellipse(cx-r*0.22,cy-r*0.22,r*0.38,r*0.28,Math.PI*0.3,0,Math.PI*2);ctx.fill();
  ctx.restore();
}

/* ══════════════════════════════════════════════
   DRAW — COINS  (3-D feel)
══════════════════════════════════════════════ */
function drawCoin(c){
  const bob=fastSin(frameCount*0.09+c.id)*2.5;
  const cy=c.y+bob;
  ctx.save();

  // ── PEDESTAL BASE (cylindrical stand like reference image) ──
  const pW=14, pH=8, pX=c.x-pW/2, pY=cy+6;
  // Pedestal side face (front face of cylinder — darker gold)
  ctx.fillStyle='#7a4e00';
  ctx.beginPath();ctx.moveTo(pX,pY);ctx.lineTo(pX+pW,pY);ctx.lineTo(pX+pW,pY+pH);ctx.lineTo(pX,pY+pH);ctx.closePath();ctx.fill();
  // Pedestal top ellipse
  const ptG=ctx.createLinearGradient(pX,pY-2,pX+pW,pY+2);
  ptG.addColorStop(0,'#f0a820');ptG.addColorStop(0.5,'#ffd060');ptG.addColorStop(1,'#c07010');
  ctx.fillStyle=ptG;ctx.beginPath();ctx.ellipse(c.x,pY,pW/2,3,0,0,Math.PI*2);ctx.fill();
  // Pedestal bottom ellipse (darker)
  ctx.fillStyle='#5a3800';ctx.beginPath();ctx.ellipse(c.x,pY+pH,pW/2+1,3,0,0,Math.PI*2);ctx.fill();
  // Side face highlight
  ctx.save();ctx.globalAlpha=0.3;ctx.fillStyle='#ffd880';
  ctx.fillRect(pX+2,pY+1,3,pH-2);ctx.restore();

  // ── COIN DISC ──
  ctx.shadowColor='#fbbf24';ctx.shadowBlur=28;

  // Pulsing warm gold halo — demands attention from distance
  const _coinPulse=0.55+fastSin(frameCount*0.11+c.id*1.3)*0.35;
  ctx.save();
  ctx.globalAlpha=_coinPulse*0.42;
  const _haloG=ctx.createRadialGradient(c.x,cy,4,c.x,cy,18);
  _haloG.addColorStop(0,'rgba(251,191,36,0.9)');
  _haloG.addColorStop(0.5,'rgba(251,191,36,0.4)');
  _haloG.addColorStop(1,'rgba(251,191,36,0)');
  ctx.fillStyle=_haloG;
  ctx.beginPath();ctx.arc(c.x,cy,18,0,Math.PI*2);ctx.fill();
  ctx.restore();
  // Outer ring (bevelled edge)
  const og=ctx.createRadialGradient(c.x-3,cy-3,1,c.x,cy,11);
  og.addColorStop(0,'#fff8d0');og.addColorStop(0.3,'#f59e0b');og.addColorStop(0.75,'#b45309');og.addColorStop(1,'#7c2d00');
  ctx.fillStyle=og;ctx.beginPath();ctx.arc(c.x,cy,11,0,Math.PI*2);ctx.fill();
  ctx.shadowBlur=0;
  // Inner coin face
  ctx.fillStyle='#fcd34d';ctx.beginPath();ctx.arc(c.x,cy,8.5,0,Math.PI*2);ctx.fill();
  // Coin face gradient for 3D top light
  const fG=ctx.createRadialGradient(c.x-2,cy-3,1,c.x,cy,9);
  fG.addColorStop(0,'rgba(255,255,200,0.55)');fG.addColorStop(0.6,'rgba(250,200,30,0.0)');
  ctx.fillStyle=fG;ctx.beginPath();ctx.arc(c.x,cy,8.5,0,Math.PI*2);ctx.fill();
  // Specular highlight top-left
  ctx.save();ctx.globalAlpha=0.70;ctx.fillStyle='#fffce0';
  ctx.beginPath();ctx.ellipse(c.x-2.5,cy-2.5,3.5,2.5,Math.PI*0.25,0,Math.PI*2);ctx.fill();ctx.restore();
  // Dollar symbol — embossed look
  ctx.fillStyle='#92400e';ctx.font="bold 9px 'Orbitron',sans-serif";
  ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillText('$',c.x+0.5,cy+0.8);
  ctx.restore();
}

/* ══════════════════════════════════════════════
   DRAW — POWER-UP ICONS  (distinct per type)
══════════════════════════════════════════════ */
const PU_COLS={shield:'#3b82f6',magnet:'#06b6d4',nitro:'#f59e0b',ghost:'#e2e8f0',gun:'#ffe060'};
const PU_FULL={shield:'SHIELD',magnet:'MAGNET',nitro:'NITRO',ghost:'GHOST',gun:'GUN'};
const PU_EMOJI={shield:'⛨',magnet:'⊕',nitro:'⚡',ghost:'◈',gun:'🔫'}; // still used by drawPuBanner & HUD

function drawPowerUpIcon(x,y,type,radius){
  const bob=fastSin(frameCount*0.08+x)*3;
  const yy=y+bob;
  ctx.save();

  const _glowRGB={
    shield:'59,130,246', magnet:'6,182,212',
    nitro:'245,158,11',  ghost:'192,132,252', gun:'255,224,96'
  }[type]||'255,255,255';

  // ── Reduced ambient soft glow — background warmth only, no longer dominant ──
  const _gPulse=0.55+fastSin(frameCount*0.09+x*0.1)*0.35;
  ctx.save();
  ctx.globalAlpha=_gPulse*0.20;
  ctx.shadowColor=`rgb(${_glowRGB})`;ctx.shadowBlur=radius*3.5;
  ctx.fillStyle=`rgba(${_glowRGB},0.09)`;
  ctx.beginPath();ctx.arc(x,yy,radius*1.1,0,Math.PI*2);ctx.fill();
  ctx.restore();

  // ── Pulsing halo ring — crisp, colour-coded, unmissable at game speed ──
  // Pulses between 0.3 and 0.7 opacity as requested
  const _haloPulse=0.3+fastSin(frameCount*0.13+x*0.08)*0.40;
  ctx.save();
  ctx.globalAlpha=_haloPulse;
  const _haloG=ctx.createRadialGradient(x,yy,10,x,yy,24);
  _haloG.addColorStop(0,   `rgba(${_glowRGB},0.70)`);
  _haloG.addColorStop(0.55,`rgba(${_glowRGB},0.45)`);
  _haloG.addColorStop(1,   `rgba(${_glowRGB},0)`);
  ctx.fillStyle=_haloG;
  ctx.beginPath();ctx.arc(x,yy,24,0,Math.PI*2);ctx.fill();
  ctx.restore();

  if(type==='shield')   _puShield(x,yy,radius);
  else if(type==='magnet') _puMagnet(x,yy,radius);
  else if(type==='nitro')  _puNitro(x,yy,radius);
  else if(type==='ghost')  _puGhost(x,yy,radius);
  else if(type==='gun')    _puGun(x,yy,radius*1.1);
  ctx.restore();
}

// ── SHIELD ──────────────────────────────────────────────────────
function _puShield(cx,cy,r){
  ctx.save();
  const w=r*1.6,h=r*1.9,x=cx-w/2,y=cy-h/2;
  // Outer glow aura
  ctx.shadowColor='#3b82f6';ctx.shadowBlur=r*4.5;
  // Body
  ctx.beginPath();
  ctx.moveTo(x,y);ctx.lineTo(x+w,y);ctx.lineTo(x+w,y+h*0.58);
  ctx.quadraticCurveTo(x+w,y+h*0.82,cx,y+h);
  ctx.quadraticCurveTo(x,y+h*0.82,x,y+h*0.58);
  ctx.lineTo(x,y);ctx.closePath();
  const bG=ctx.createLinearGradient(x,y,x+w,y+h);
  bG.addColorStop(0,'#1e3a8a');bG.addColorStop(0.3,'#2563eb');
  bG.addColorStop(0.7,'#1d4ed8');bG.addColorStop(1,'#1e3a8a');
  ctx.fillStyle=bG;ctx.fill();
  // Border stroke
  ctx.strokeStyle='#60a5fa';ctx.lineWidth=r*0.18;
  ctx.beginPath();
  ctx.moveTo(x,y);ctx.lineTo(x+w,y);ctx.lineTo(x+w,y+h*0.58);
  ctx.quadraticCurveTo(x+w,y+h*0.82,cx,y+h);
  ctx.quadraticCurveTo(x,y+h*0.82,x,y+h*0.58);
  ctx.lineTo(x,y);ctx.closePath();ctx.stroke();
  // Inner rim
  ctx.save();ctx.globalAlpha=0.4;ctx.strokeStyle='#93c5fd';ctx.lineWidth=r*0.08;
  const ir=r*0.2;
  ctx.beginPath();ctx.moveTo(x+ir,y+ir);ctx.lineTo(x+w-ir,y+ir);ctx.lineTo(x+w-ir,y+h*0.56);
  ctx.quadraticCurveTo(x+w-ir,y+h*0.80,cx,y+h-ir*2);
  ctx.quadraticCurveTo(x+ir,y+h*0.80,x+ir,y+h*0.56);
  ctx.lineTo(x+ir,y+ir);ctx.closePath();ctx.stroke();ctx.restore();
  // Cross lines
  ctx.save();ctx.globalAlpha=0.45;ctx.strokeStyle='#93c5fd';ctx.lineWidth=r*0.1;
  ctx.beginPath();ctx.moveTo(cx,y+r*0.28);ctx.lineTo(cx,y+h-r*0.5);ctx.stroke();
  ctx.beginPath();ctx.moveTo(x+r*0.25,y+h*0.40);ctx.lineTo(x+w-r*0.25,y+h*0.40);ctx.stroke();
  ctx.restore();
  // Glare top-left
  ctx.save();ctx.globalAlpha=0.22;
  const gG=ctx.createLinearGradient(x,y,cx,cy);
  gG.addColorStop(0,'rgba(255,255,255,0.6)');gG.addColorStop(1,'rgba(255,255,255,0)');
  ctx.fillStyle=gG;
  ctx.beginPath();ctx.moveTo(x+ir,y+ir);ctx.lineTo(cx+r*0.3,y+ir);ctx.lineTo(cx+r*0.3,y+h*0.38);ctx.lineTo(x+ir,y+h*0.38);ctx.closePath();
  ctx.fill();ctx.restore();
  ctx.restore();
}

// ── MAGNET ──────────────────────────────────────────────────────
function _puMagnet(cx,cy,r){
  ctx.save();
  ctx.translate(cx,cy);ctx.rotate(-Math.PI*0.25);
  const armW=r*0.52,arcR=r*0.55,armH=r*0.70;
  // Ground shadow
  ctx.save();ctx.globalAlpha=0.25;ctx.fillStyle='rgba(0,0,0,0.45)';
  ctx.beginPath();ctx.ellipse(r*0.1,r*0.1,r*1.0,r*0.65,0,0,Math.PI*2);ctx.fill();ctx.restore();
  // Left arm (red)
  const laG=ctx.createLinearGradient(-arcR-armW/2,0,-arcR+armW/2,0);
  laG.addColorStop(0,'#c0192c');laG.addColorStop(0.4,'#ef3349');laG.addColorStop(1,'#c0192c');
  ctx.fillStyle=laG;ctx.fillRect(-arcR-armW/2,-r*0.16,armW,armH+r*0.16);
  // Right arm (red)
  const raG=ctx.createLinearGradient(arcR-armW/2,0,arcR+armW/2,0);
  raG.addColorStop(0,'#c0192c');raG.addColorStop(0.4,'#ef3349');raG.addColorStop(1,'#c0192c');
  ctx.fillStyle=raG;ctx.fillRect(arcR-armW/2,-r*0.16,armW,armH+r*0.16);
  // Arc top
  ctx.strokeStyle='#ef3349';ctx.lineWidth=armW;
  ctx.shadowColor='#06b6d4';ctx.shadowBlur=r*4.0;
  ctx.beginPath();ctx.arc(0,-r*0.14,arcR,Math.PI,0);ctx.stroke();
  // Arc highlight
  ctx.save();ctx.globalAlpha=0.35;ctx.strokeStyle='#ff8fa3';ctx.lineWidth=armW*0.28;
  ctx.beginPath();ctx.arc(0,-r*0.14,arcR-armW*0.18,Math.PI*1.05,Math.PI*1.7);ctx.stroke();ctx.restore();
  // Gray tips
  const tipH=r*0.32;
  const ltG=ctx.createLinearGradient(-arcR-armW/2,-r*0.16,-arcR+armW/2,-r*0.16);
  ltG.addColorStop(0,'#94a3b8');ltG.addColorStop(0.5,'#e2e8f0');ltG.addColorStop(1,'#94a3b8');
  ctx.fillStyle=ltG;ctx.shadowColor='#e2e8f0';ctx.shadowBlur=r*0.6;
  ctx.fillRect(-arcR-armW/2,-r*0.16,armW,tipH);
  const rtG=ctx.createLinearGradient(arcR-armW/2,-r*0.16,arcR+armW/2,-r*0.16);
  rtG.addColorStop(0,'#94a3b8');rtG.addColorStop(0.5,'#e2e8f0');rtG.addColorStop(1,'#94a3b8');
  ctx.fillStyle=rtG;ctx.shadowColor='#e2e8f0';ctx.shadowBlur=r*0.6;
  ctx.fillRect(arcR-armW/2,-r*0.16,armW,tipH);
  ctx.shadowBlur=0;
  // Spark lines
  ctx.save();ctx.strokeStyle='#94a3b8';ctx.lineWidth=r*0.15;ctx.lineCap='round';ctx.globalAlpha=0.85;
  const lx=-arcR,ly=-r*0.16+tipH*0.5;
  [Math.PI*1.1,Math.PI*1.25,Math.PI*1.4].forEach((a,i)=>{
    const len=r*(0.18+i*0.06);
    ctx.beginPath();ctx.moveTo(lx+Math.cos(a)*r*0.26,ly+Math.sin(a)*r*0.26);
    ctx.lineTo(lx+Math.cos(a)*(r*0.26+len),ly+Math.sin(a)*(r*0.26+len));ctx.stroke();
  });
  const rx=arcR,ry=-r*0.16+tipH*0.5;
  [-Math.PI*0.05,Math.PI*0.10,Math.PI*0.25].forEach((a,i)=>{
    const len=r*(0.18+i*0.06);
    ctx.beginPath();ctx.moveTo(rx+Math.cos(a)*r*0.26,ry+Math.sin(a)*r*0.26);
    ctx.lineTo(rx+Math.cos(a)*(r*0.26+len),ry+Math.sin(a)*(r*0.26+len));ctx.stroke();
  });
  ctx.restore();
  ctx.restore();
}

// ── NITRO ───────────────────────────────────────────────────────
function _puNitro(cx,cy,r){
  ctx.save();
  const sz=r*1.4;
  const sw=1.20; // 20% wider on X axis
  function _boltPts(cx,cy,sz){
    return [[cx+sz*0.25*sw,cy-sz*0.52],[cx+sz*0.02*sw,cy-sz*0.02],[cx+sz*0.20*sw,cy-sz*0.02],
            [cx-sz*0.25*sw,cy+sz*0.52],[cx-sz*0.02*sw,cy+sz*0.02],[cx-sz*0.18*sw,cy+sz*0.02]];
  }
  function _bolt(cx,cy,sz){
    const p=_boltPts(cx,cy,sz);
    ctx.beginPath();ctx.moveTo(p[0][0],p[0][1]);
    p.slice(1).forEach(q=>ctx.lineTo(q[0],q[1]));ctx.closePath();
  }
  // Multi-layer glow — boosted alphas for visible amber halo
  [3,2,1].forEach(pass=>{
    const blurs=[sz*5.0,sz*3.2,sz*1.6],alphas=[0.32,0.50,0.68];
    ctx.save();ctx.globalAlpha=alphas[3-pass];
    ctx.shadowColor='#fbbf24';ctx.shadowBlur=blurs[3-pass];
    _bolt(cx,cy,sz);ctx.fillStyle='rgba(253,224,71,0.40)';ctx.fill();ctx.restore();
  });
  // Main bolt — strong glow shadow
  ctx.shadowColor='#f59e0b';ctx.shadowBlur=sz*2.4;
  _bolt(cx,cy,sz);
  const bG=ctx.createLinearGradient(cx,cy-sz*0.52,cx,cy+sz*0.52);
  bG.addColorStop(0,'#fef08a');bG.addColorStop(0.3,'#fbbf24');
  bG.addColorStop(0.7,'#f59e0b');bG.addColorStop(1,'#d97706');
  ctx.fillStyle=bG;ctx.fill();
  // White core highlight
  ctx.save();ctx.globalAlpha=0.62;ctx.fillStyle='#ffffff';
  ctx.beginPath();ctx.moveTo(cx+sz*0.20*sw,cy-sz*0.52);ctx.lineTo(cx+sz*0.04*sw,cy-sz*0.06);ctx.lineTo(cx+sz*0.16*sw,cy-sz*0.06);ctx.closePath();ctx.fill();ctx.restore();
  // Glowing outline
  _bolt(cx,cy,sz);
  ctx.shadowColor='#fde68a';ctx.shadowBlur=sz*0.7;
  ctx.strokeStyle='#fde68a';ctx.lineWidth=sz*0.07;ctx.stroke();
  ctx.shadowBlur=0;
  // Side sparks (also widened)
  ctx.save();ctx.globalAlpha=0.68;ctx.strokeStyle='#fef08a';ctx.lineWidth=sz*0.07;ctx.lineCap='round';
  ctx.shadowColor='#fbbf24';ctx.shadowBlur=sz*1.8;
  [[cx-sz*0.28*sw,cy-sz*0.15,cx-sz*0.48*sw,cy-sz*0.30],
   [cx-sz*0.30*sw,cy-sz*0.02,cx-sz*0.50*sw,cy-sz*0.02],
   [cx+sz*0.28*sw,cy+sz*0.10,cx+sz*0.48*sw,cy+sz*0.24],
   [cx+sz*0.26*sw,cy+sz*0.28,cx+sz*0.46*sw,cy+sz*0.28]].forEach(([x1,y1,x2,y2])=>{
    ctx.beginPath();ctx.moveTo(x1,y1);ctx.lineTo(x2,y2);ctx.stroke();});
  ctx.restore();
  ctx.restore();
}

// ── GHOST ───────────────────────────────────────────────────────
function _puGhost(cx,cy,r){
  ctx.save();
  const w=r*1.55,h=r*1.8,x=cx-w/2,y=cy-h/2,bR=w/4.5;
  // Outer glow
  ctx.shadowColor='#c084fc';ctx.shadowBlur=r*4.5;
  // Body path
  function _ghostPath(){
    ctx.beginPath();
    ctx.moveTo(x,y+h*0.72);
    ctx.quadraticCurveTo(x,y+h,x+bR,y+h);ctx.quadraticCurveTo(x+bR*2,y+h,x+bR*2,y+h*0.78);
    ctx.quadraticCurveTo(x+bR*2,y+h,x+bR*3,y+h);ctx.quadraticCurveTo(x+bR*4,y+h,x+bR*4,y+h*0.78);
    ctx.quadraticCurveTo(x+bR*4,y+h,x+w,y+h);ctx.quadraticCurveTo(x+w,y+h*0.72,x+w,y+h*0.72);
    ctx.lineTo(x+w,y+h*0.38);
    ctx.quadraticCurveTo(x+w,y,cx,y);ctx.quadraticCurveTo(x,y,x,y+h*0.38);
    ctx.lineTo(x,y+h*0.72);ctx.closePath();
  }
  _ghostPath();
  const gG=ctx.createLinearGradient(cx-w*0.3,y,cx+w*0.3,y+h);
  gG.addColorStop(0,'#f5f0ff');gG.addColorStop(0.4,'#ede9fe');gG.addColorStop(1,'#c4b5fd');
  ctx.fillStyle=gG;ctx.fill();
  // Outline
  ctx.strokeStyle='#a78bfa';ctx.lineWidth=r*0.12;ctx.shadowBlur=0;
  _ghostPath();ctx.stroke();
  // Eyes
  const eY=y+h*0.38,eRx=w*0.11,eRy=h*0.11;
  ctx.save();ctx.shadowColor='#7c3aed';ctx.shadowBlur=r*0.5;ctx.fillStyle='#3a2d6e';
  ctx.beginPath();ctx.ellipse(cx-w*0.22,eY,eRx,eRy,0,0,Math.PI*2);ctx.fill();
  ctx.beginPath();ctx.ellipse(cx+w*0.22,eY,eRx,eRy,0,0,Math.PI*2);ctx.fill();
  ctx.globalAlpha=0.75;ctx.fillStyle='#ffffff';
  ctx.beginPath();ctx.ellipse(cx-w*0.24,eY-eRy*0.3,eRx*0.35,eRy*0.3,0,0,Math.PI*2);ctx.fill();
  ctx.beginPath();ctx.ellipse(cx+w*0.20,eY-eRy*0.3,eRx*0.35,eRy*0.3,0,0,Math.PI*2);ctx.fill();
  ctx.restore();
  // Glare
  ctx.save();ctx.globalAlpha=0.20;
  const glG=ctx.createRadialGradient(cx-w*0.15,y+h*0.2,0,cx,y+h*0.3,w*0.4);
  glG.addColorStop(0,'#ffffff');glG.addColorStop(1,'transparent');
  ctx.fillStyle=glG;ctx.beginPath();ctx.ellipse(cx-w*0.1,y+h*0.22,w*0.3,h*0.18,0,0,Math.PI*2);ctx.fill();ctx.restore();
  ctx.restore();
}

// ── GUN ─────────────────────────────────────────────────────────
function _puGun(cx,cy,r){
  ctx.save();
  const sz=r*1.55; // scale factor
  // Wide yellow-white bloom — 3 passes
  const _a1=ctx.createRadialGradient(cx,cy,sz*0.01,cx,cy,sz*3.2);
  _a1.addColorStop(0,'rgba(255,255,200,0.42)');_a1.addColorStop(0.35,'rgba(255,240,100,0.25)');
  _a1.addColorStop(0.7,'rgba(220,180,0,0.12)');_a1.addColorStop(1,'rgba(0,0,0,0)');
  ctx.fillStyle=_a1;ctx.beginPath();ctx.ellipse(cx,cy,sz*3.2,sz*2.2,0,0,Math.PI*2);ctx.fill();
  const _a2=ctx.createRadialGradient(cx,cy,sz*0.01,cx,cy,sz*2.0);
  _a2.addColorStop(0,'rgba(255,255,220,0.75)');_a2.addColorStop(0.4,'rgba(255,230,60,0.48)');
  _a2.addColorStop(1,'rgba(0,0,0,0)');
  ctx.fillStyle=_a2;ctx.beginPath();ctx.ellipse(cx,cy,sz*2.0,sz*1.36,0,0,Math.PI*2);ctx.fill();
  const _a3=ctx.createRadialGradient(cx,cy,sz*0.01,cx,cy,sz*1.0);
  _a3.addColorStop(0,'rgba(255,255,255,0.95)');_a3.addColorStop(0.4,'rgba(255,250,160,0.70)');
  _a3.addColorStop(1,'rgba(0,0,0,0)');
  ctx.fillStyle=_a3;ctx.beginPath();ctx.ellipse(cx,cy,sz*1.0,sz*0.68,0,0,Math.PI*2);ctx.fill();
  // SLIDE — bright chrome
  const sX=cx-sz*0.52,sY=cy-sz*0.30,sW=sz*1.00,sH=sz*0.32;
  const slG=ctx.createLinearGradient(sX,sY,sX,sY+sH);
  slG.addColorStop(0,'#c8ccd8');slG.addColorStop(0.25,'#9098a8');
  slG.addColorStop(0.6,'#606878');slG.addColorStop(1,'#383848');
  ctx.fillStyle=slG;ctx.shadowColor='rgba(255,240,120,0.55)';ctx.shadowBlur=sz*0.4;
  rr(sX,sY,sW,sH,4);ctx.fill();
  // Serrations
  ctx.save();ctx.globalAlpha=0.55;ctx.strokeStyle='#303040';ctx.lineWidth=sz*0.028;
  for(let i=0;i<5;i++){const sx=sX+sz*0.58+i*sz*0.12;ctx.beginPath();ctx.moveTo(sx,sY+sz*0.04);ctx.lineTo(sx,sY+sH-sz*0.04);ctx.stroke();}
  ctx.restore();
  // Top edge highlight
  ctx.save();ctx.globalAlpha=0.75;ctx.fillStyle='#ffffff';ctx.fillRect(sX+2,sY+1,sW-4,2);ctx.restore();
  // BARREL — gold
  const brlY=cy-sz*0.18,brlH=sz*0.12,brlX=cx-sz*0.52-sz*0.22,brlW=sz*0.24;
  const brlG=ctx.createLinearGradient(brlX,brlY,brlX,brlY+brlH);
  brlG.addColorStop(0,'#d4a830');brlG.addColorStop(0.5,'#f0c040');brlG.addColorStop(1,'#a07820');
  ctx.fillStyle=brlG;ctx.shadowColor='rgba(255,200,40,0.7)';ctx.shadowBlur=sz*0.36;
  rr(brlX,brlY,brlW,brlH,3);ctx.fill();
  // Muzzle tip
  ctx.fillStyle='#fff8c0';ctx.shadowColor='#ffe060';ctx.shadowBlur=sz*0.5;
  ctx.fillRect(brlX,brlY+1,6,brlH-2);ctx.shadowBlur=0;
  // FRAME
  const frX=cx-sz*0.15,frY=cy-sz*0.02,frW=sz*0.63,frH=sz*0.16;
  const frG=ctx.createLinearGradient(frX,frY,frX,frY+frH);
  frG.addColorStop(0,'#7a7a8a');frG.addColorStop(1,'#484858');
  ctx.fillStyle=frG;ctx.shadowColor='rgba(255,220,60,0.35)';ctx.shadowBlur=sz*0.26;
  rr(frX,frY,frW,frH,3);ctx.fill();ctx.shadowBlur=0;
  // TRIGGER GUARD
  ctx.strokeStyle='#6a6a7a';ctx.lineWidth=sz*0.10;ctx.lineCap='round';ctx.lineJoin='round';
  const tgX=cx+sz*0.08,tgY=cy;
  ctx.beginPath();ctx.moveTo(tgX,tgY);ctx.quadraticCurveTo(tgX+sz*0.14,tgY+sz*0.26,tgX+sz*0.28,tgY+sz*0.08);ctx.stroke();
  ctx.save();ctx.globalAlpha=0.4;ctx.strokeStyle='#b0b0c0';ctx.lineWidth=sz*0.04;
  ctx.beginPath();ctx.moveTo(tgX,tgY);ctx.quadraticCurveTo(tgX+sz*0.14,tgY+sz*0.26,tgX+sz*0.28,tgY+sz*0.08);ctx.stroke();ctx.restore();
  // TRIGGER — gold
  ctx.strokeStyle='#d4a830';ctx.lineWidth=sz*0.045;
  ctx.beginPath();ctx.moveTo(tgX+sz*0.10,tgY+sz*0.04);ctx.lineTo(tgX+sz*0.18,tgY+sz*0.18);ctx.stroke();
  // GRIP
  const grX=cx+sz*0.28,grY=cy-sz*0.02,grW=sz*0.20,grH=sz*0.50;
  const grG=ctx.createLinearGradient(grX,grY,grX+grW,grY);
  grG.addColorStop(0,'#484858');grG.addColorStop(0.5,'#585868');grG.addColorStop(1,'#383848');
  ctx.fillStyle=grG;
  ctx.save();ctx.translate(grX+grW/2,grY);ctx.rotate(0.10);
  ctx.fillRect(-grW/2,0,grW,grH);
  ctx.save();ctx.globalAlpha=0.45;ctx.strokeStyle='#a0a0b8';ctx.lineWidth=0.9;
  for(let i=1;i<8;i++){ctx.beginPath();ctx.moveTo(-grW/2+2,i*grH/8);ctx.lineTo(grW/2-2,i*grH/8);ctx.stroke();}
  ctx.restore();ctx.restore();
  // SIGHTS — bright white
  ctx.fillStyle='#ffffff';ctx.shadowColor='#fffce0';ctx.shadowBlur=sz*0.18;
  ctx.fillRect(cx+sz*0.35,sY-4,5,6);ctx.fillRect(brlX+brlW-3,sY-3,4,5);ctx.shadowBlur=0;
  // Slide outline
  ctx.strokeStyle='#d0d4e0';ctx.lineWidth=1.2;rr(sX,sY,sW,sH,4);ctx.stroke();
  // GUN label
  ctx.save();
  ctx.font=`bold ${Math.max(7,(sz*0.28)|0)}px 'Orbitron',sans-serif`;
  ctx.textAlign='center';ctx.textBaseline='top';
  ctx.shadowColor='#ffe060';ctx.shadowBlur=sz*0.5;ctx.fillStyle='#fff8c0';
  ctx.fillText('GUN',cx,sY+sH+sz*0.06);
  ctx.restore();
  ctx.restore();
}

/* ══════════════════════════════════════════════
   DRAW — SHIELD BUBBLE
══════════════════════════════════════════════ */
function drawShieldBubble(){
  if(!activeShield)return;
  const px=player.visualX,py=player.y-player.jumpOff;
  const pulse=0.88+fastSin(frameCount*0.13)*0.12;
  const rx=28*pulse, ry=44*pulse;
  ctx.save();

  // Outer glow halo
  ctx.shadowColor='#3b82f6';ctx.shadowBlur=32;
  ctx.strokeStyle=`rgba(59,130,246,${0.50+fastSin(frameCount*0.16)*0.18})`;
  ctx.lineWidth=2.8;ctx.beginPath();ctx.ellipse(px,py,rx,ry,0,0,Math.PI*2);ctx.stroke();
  ctx.shadowBlur=0;

  // Inner translucent dome fill — gradient top-bright to bottom-dark
  const domeG=ctx.createLinearGradient(px,py-ry,px,py+ry);
  domeG.addColorStop(0,'rgba(147,197,253,0.18)');
  domeG.addColorStop(0.4,'rgba(59,130,246,0.08)');
  domeG.addColorStop(1,'rgba(30,64,175,0.03)');
  ctx.fillStyle=domeG;ctx.beginPath();ctx.ellipse(px,py,rx,ry,0,0,Math.PI*2);ctx.fill();

  // Top glare reflection — makes it look like a glass dome
  ctx.save();ctx.globalAlpha=0.30;
  const glareG=ctx.createLinearGradient(px-rx*0.4,py-ry*0.7,px+rx*0.2,py-ry*0.1);
  glareG.addColorStop(0,'rgba(255,255,255,0.7)');glareG.addColorStop(1,'rgba(147,197,253,0)');
  ctx.fillStyle=glareG;
  ctx.beginPath();ctx.ellipse(px-rx*0.1,py-ry*0.35,rx*0.42,ry*0.28,Math.PI*0.1,0,Math.PI*2);ctx.fill();
  ctx.restore();

  // Secondary ring inside — hexagonal energy pattern
  ctx.save();ctx.globalAlpha=0.18;ctx.strokeStyle='#93c5fd';ctx.lineWidth=1;
  ctx.beginPath();ctx.ellipse(px,py,rx*0.72,ry*0.72,0,0,Math.PI*2);ctx.stroke();ctx.restore();

  // Rotating sparkle nodes
  ctx.globalAlpha=0.65;
  for(let i=0;i<8;i++){
    const a=(i/8)*Math.PI*2+frameCount*0.025;
    const sx=px+Math.cos(a)*rx, sy=py+Math.sin(a)*ry;
    ctx.shadowColor='#93c5fd';ctx.shadowBlur=8;
    ctx.fillStyle='#bfdbfe';ctx.beginPath();ctx.arc(sx,sy,2,0,Math.PI*2);ctx.fill();
  }
  ctx.restore();
}

