/* ══════════════════════════════════════════════
   DRAW — GUN FIRE BUTTON HINT
   Pulsing arrow pointing to the fire button,
   shown for 5 seconds after picking up the gun.
   Fades in over 20f, fades out over 40f.
══════════════════════════════════════════════ */
function drawGunFireHint(){
  if(!gunActive||gunPickupHintTimer<=0)return;
  if(gst!==ST.PLAYING&&gst!==ST.RESPAWNING)return;

  // Fade in first 20 frames, hold, fade out last 40 frames
  const elapsed=300-gunPickupHintTimer;
  let alpha=1;
  if(elapsed<20)        alpha=elapsed/20;
  else if(gunPickupHintTimer<40) alpha=gunPickupHintTimer/40;
  alpha=clamp(alpha,0,1);
  if(alpha<=0.01)return;

  const pulse=0.72+fastSin(frameCount*0.20)*0.28;
  // Arrow bounces toward the right edge where the fire button lives
  const bounce=fastSin(frameCount*0.18)*5;
  // Position: right-side of canvas, vertically centred on player
  const py=player.y-player.jumpOff;
  const arrowX=W-62+bounce; // points right toward the button
  const arrowY=py;

  ctx.save();
  ctx.globalAlpha=alpha*pulse;

  // Animated arrow →
  ctx.fillStyle='#ef4444';
  ctx.shadowColor='#ef4444';ctx.shadowBlur=18;
  ctx.font="bold 36px 'Orbitron',sans-serif";
  ctx.textAlign='center';ctx.textBaseline='middle';
  ctx.fillText('→',arrowX,arrowY);
  ctx.shadowBlur=0;

  // Hint pill above arrow
  ctx.globalAlpha=alpha*0.92;
  const pillTxt='TAP TO FIRE';
  ctx.font="bold 9px 'Orbitron',sans-serif";
  const tw=ctx.measureText(pillTxt).width+18;
  const pillX=W-tw-6, pillY=arrowY-30;
  ctx.fillStyle='rgba(4,6,18,0.92)';
  rr(pillX,pillY,tw,20,5);ctx.fill();
  ctx.strokeStyle='rgba(239,68,68,0.70)';ctx.lineWidth=1.2;
  rr(pillX,pillY,tw,20,5);ctx.stroke();
  ctx.fillStyle='#fca5a5';ctx.textAlign='center';ctx.textBaseline='middle';
  ctx.fillText(pillTxt,pillX+tw/2,pillY+10);

  ctx.restore();
}

/* ══════════════════════════════════════════════
   DRAW — PLAYER PROXIMITY POWER BADGES
   Small icon + draining arc ring drawn just
   below the player car. One badge per active
   power (shield / magnet / nitro / ghost).
   Also draws a faint road glow under the car
   in the power's colour.
══════════════════════════════════════════════ */
function drawPlayerPowerStatus(){
  if(gst!==ST.PLAYING&&gst!==ST.RESPAWNING)return;

  // Build active list (gun excluded — stays top HUD)
  const active=[];
  if(activeShield)  active.push({type:'shield',t:1,     max:1});
  if(magnetTimer>0) active.push({type:'magnet',t:magnetTimer,max:360});
  if(nitroTimer>0)  active.push({type:'nitro', t:nitroTimer, max:200});
  if(ghostTimer>0)  active.push({type:'ghost', t:ghostTimer, max:180});
  if(!active.length)return;

  const px=player.visualX;
  const py=player.y-player.jumpOff;

  // ── Road glow under car (blended colour of all active powers) ──
  ctx.save();
  const primaryCol=PU_COLS[active[0].type];
  const rgb0=hexToRgb(primaryCol);
  const pulse=0.28+fastSin(frameCount*0.12)*0.10;
  const glowG=ctx.createRadialGradient(px,py+28,2,px,py+28,52);
  glowG.addColorStop(0,`rgba(${rgb0.r},${rgb0.g},${rgb0.b},${pulse})`);
  glowG.addColorStop(1,'rgba(0,0,0,0)');
  ctx.fillStyle=glowG;
  ctx.beginPath();ctx.ellipse(px,py+28,52,18,0,0,Math.PI*2);ctx.fill();
  ctx.restore();

  // ── Badges below car ──
  const BADGE_R=17;          // icon circle radius — larger for clear visibility
  const BADGE_GAP=40;        // horizontal spacing between badge centres
  const BADGE_Y=py+68;       // vertical position: below car, clear of car body
  const totalW=(active.length-1)*BADGE_GAP;
  const startX=px-totalW/2;

  active.forEach(({type,t,max},i)=>{
    const col=PU_COLS[type];
    const rgb=hexToRgb(col);
    const fill=type==='shield'?1:clamp(t/max,0,1);
    const bx=startX+i*BADGE_GAP;
    const by=BADGE_Y;

    // Urgency: pulse faster when <30% remaining
    const urgent=fill<0.30&&type!=='shield';
    const urgentPulse=urgent?(0.45+fastSin(frameCount*0.55)*0.55):1;

    ctx.save();
    ctx.globalAlpha=clamp(urgentPulse,0.25,1);

    // ── Outer glow aura — bigger when urgent ──
    const auraR=BADGE_R+8+fastSin(frameCount*0.10)*3;
    const auraG=ctx.createRadialGradient(bx,by,BADGE_R*0.3,bx,by,auraR*1.8);
    auraG.addColorStop(0,`rgba(${rgb.r},${rgb.g},${rgb.b},${urgent?0.70:0.50})`);
    auraG.addColorStop(1,'rgba(0,0,0,0)');
    ctx.fillStyle=auraG;
    ctx.beginPath();ctx.arc(bx,by,auraR*1.8,0,Math.PI*2);ctx.fill();

    // ── Dark circle background ──
    ctx.fillStyle='rgba(6,8,20,0.92)';
    ctx.shadowColor=col;ctx.shadowBlur=urgent?22:13;
    ctx.beginPath();ctx.arc(bx,by,BADGE_R,0,Math.PI*2);ctx.fill();
    ctx.shadowBlur=0;

    // ── Draining arc ring — thick and bold ──
    // Background track (dim)
    ctx.strokeStyle=`rgba(${rgb.r},${rgb.g},${rgb.b},0.18)`;
    ctx.lineWidth=4;ctx.lineCap='round';
    ctx.beginPath();ctx.arc(bx,by,BADGE_R,-Math.PI/2,-Math.PI/2+Math.PI*2);ctx.stroke();
    // Active portion
    ctx.shadowColor=col;ctx.shadowBlur=urgent?18:10;
    ctx.strokeStyle=col;ctx.lineWidth=4;
    const endAngle=-Math.PI/2+Math.PI*2*fill;
    ctx.beginPath();ctx.arc(bx,by,BADGE_R,-Math.PI/2,endAngle);ctx.stroke();
    ctx.shadowBlur=0;

    // ── Icon inside badge — bigger font ──
    ctx.shadowColor=col;ctx.shadowBlur=urgent?10:6;
    ctx.fillStyle=urgent?'#ffffff':col;
    ctx.font=`${(BADGE_R*1.25)|0}px -apple-system,sans-serif`;
    ctx.textAlign='center';ctx.textBaseline='middle';
    ctx.fillText(PU_EMOJI[type],bx,by+1);
    ctx.shadowBlur=0;

    // ── Label under badge — bigger font ──
    ctx.font="bold 7.5px 'Orbitron',sans-serif";
    ctx.fillStyle=urgent?'#ffffff':col;
    ctx.shadowColor=col;ctx.shadowBlur=urgent?6:3;
    ctx.textAlign='center';ctx.textBaseline='top';
    ctx.fillText(PU_FULL[type],bx,by+BADGE_R+4);
    ctx.shadowBlur=0;

    ctx.restore();
  });
}

/* ══════════════════════════════════════════════
   DRAW — COMBO METER
══════════════════════════════════════════════ */
function drawComboMeter(){
  if(nearMissStreak===0&&comboMult===1)return;
  const fill=comboDecay>0?clamp(1-(comboDecay/300),0,1):1;
  const col=comboMult>=4?'#ef4444':comboMult>=3?'#f97316':comboMult>=2?'#facc15':'#4ade80';
  const rgb=hexToRgb(col);

  // ── Vertical bar on right side ──
  const barW=7, barH=180;
  const bx=W-12, by=(H-barH)/2 + 50;  // shifted up toward player car level

  ctx.save();
  // Track background
  ctx.fillStyle='rgba(0,0,0,0.55)';rr(bx,by,barW,barH,4);ctx.fill();

  // Fill grows upward from bottom
  if(fill>0){
    const fH=barH*fill;
    const fy=by+barH-fH;
    ctx.save();ctx.beginPath();rr(bx,by,barW,barH,4);ctx.clip();
    const fg=ctx.createLinearGradient(bx,fy+fH,bx,fy);
    fg.addColorStop(0,`rgba(${rgb.r},${rgb.g},${rgb.b},0.9)`);
    fg.addColorStop(1,`rgba(${rgb.r},${rgb.g},${rgb.b},0.5)`);
    ctx.fillStyle=fg;ctx.fillRect(bx,fy,barW,fH);ctx.restore();
    // Sheen on top half of fill
    ctx.save();ctx.globalAlpha=0.2;ctx.fillStyle='#fff';
    ctx.save();ctx.beginPath();rr(bx,fy,barW/2,fH,3);ctx.clip();ctx.fillRect(bx,fy,barW,fH);ctx.restore();ctx.restore();
    // Animated pulse dot at fill top
    const pulseA=0.5+fastSin(frameCount*0.18)*0.4;
    ctx.save();ctx.globalAlpha=pulseA;ctx.fillStyle=col;ctx.shadowColor=col;ctx.shadowBlur=8;
    ctx.beginPath();ctx.arc(bx+barW/2,fy,4,0,Math.PI*2);ctx.fill();ctx.restore();
  }

  // Border glow
  ctx.shadowColor=col;ctx.shadowBlur=6;
  ctx.strokeStyle=col+'88';ctx.lineWidth=1;rr(bx,by,barW,barH,4);ctx.stroke();
  ctx.shadowBlur=0;

  // STREAK label — below the bar at 270°
  if(nearMissStreak>0){
    ctx.save();
    ctx.globalAlpha=0.85;
    ctx.fillStyle='#94a3b8';
    ctx.font="700 8px 'Orbitron',sans-serif";
    ctx.textAlign='right';ctx.textBaseline='middle';
    ctx.translate(bx+barW/2, by+barH+5);
    ctx.rotate(-Math.PI/2);
    ctx.fillText('STREAK '+nearMissStreak,0,0);
    ctx.restore();
  }

  // Multiplier badge — above the bar
  if(comboMult>1){
    const flash=comboFlashTimer>0?(0.7+fastSin(frameCount*0.6)*0.3):1;
    ctx.globalAlpha=flash;ctx.shadowColor=col;ctx.shadowBlur=14;
    ctx.fillStyle=col;
    ctx.font="900 14px 'Orbitron',impact,sans-serif";
    ctx.textAlign='center';ctx.textBaseline='bottom';
    ctx.fillText(comboMult+'×',bx+barW/2,by-4);
  }
  ctx.restore();
}

/* ══════════════════════════════════════════════
   DRAW — NEAR-MISS POPUPS
   Supports two rendering modes:
   • Normal: simple alpha fade (existing near-miss text)
   • Special (streak / legendary): scale-in pop → hold → fade + glow
══════════════════════════════════════════════ */
function drawNMPopups(){
  for(let i=0;i<_NMPOP_POOL._n;i++){
    const p=_NMPOP_POOL[i];if(!p._active||p.timer<=0)continue;
    const popType=p.popType||'';
    ctx.save();
    ctx.textAlign='center';ctx.textBaseline='middle';

    if(popType==='streak'||popType==='legendary'){
      const maxT=p.maxTimer||60;
      const life=clamp(p.timer/maxT,0,1); // 1.0 at birth → 0 at death

      // Scale: pops from 1.6 → 1.0 in first 28% of lifetime, stays 1.0 after
      const POP_END=0.72;
      const scaleT=clamp((life-POP_END)/(1.0-POP_END),0,1);
      const sc=1.0+scaleT*0.60; // 1.6 at birth → 1.0 at POP_END

      // Alpha: full from birth, fades in last 38% of lifetime
      const FADE_START=0.38;
      const alpha=life<FADE_START?life/FADE_START:1;

      const isLegend=popType==='legendary';
      const fontSize=isLegend?22:18;
      const glowBlur=isLegend?26:18;

      ctx.globalAlpha=alpha;
      ctx.save();
      ctx.translate(p.x,p.y);
      ctx.scale(sc,sc);
      ctx.translate(-p.x,-p.y);

      // ── Two-pass rendering: emoji with emoji font, text with Orbitron ──
      // Fixes emoji rendering as boxes on canvas (Orbitron/impact have no emoji glyphs)
      const spaceIdx=p.text.indexOf(' ');
      const emojiPart=spaceIdx>0?p.text.slice(0,spaceIdx+1):'';
      const textPart =spaceIdx>0?p.text.slice(spaceIdx+1):p.text;

      const emojiFont=`900 ${fontSize}px 'Apple Color Emoji','Segoe UI Emoji','Noto Color Emoji',sans-serif`;
      const textFont =`900 ${fontSize}px 'Orbitron',impact,sans-serif`;

      // Measure both parts to compute centred start position
      ctx.font=emojiFont;
      const ew=emojiPart?ctx.measureText(emojiPart).width:0;
      ctx.font=textFont;
      const tw=ctx.measureText(textPart).width;
      const startX=p.x-(ew+tw)/2;

      ctx.textAlign='left';ctx.textBaseline='middle';
      ctx.shadowColor=p.col;ctx.shadowBlur=glowBlur;
      ctx.fillStyle=p.col;

      // Draw emoji
      if(emojiPart){
        ctx.font=emojiFont;
        ctx.fillText(emojiPart,startX,p.y);
      }
      // Draw text
      ctx.font=textFont;
      ctx.fillText(textPart,startX+ew,p.y);

      // Inner bright core pass for legendary only
      if(isLegend){
        ctx.shadowBlur=8;ctx.fillStyle='#ffffff';ctx.globalAlpha=alpha*0.50;
        if(emojiPart){ctx.font=emojiFont;ctx.fillText(emojiPart,startX,p.y);}
        ctx.font=textFont;ctx.fillText(textPart,startX+ew,p.y);
      }

      ctx.restore();

    } else {
      // Normal popup — alpha fade over last 40 frames
      const a=clamp(p.timer/40,0,1);
      ctx.globalAlpha=a;ctx.shadowColor=p.col;ctx.shadowBlur=10;
      ctx.fillStyle=p.col;
      ctx.font=`900 ${p.big?15:11}px 'Orbitron',impact,sans-serif`;
      ctx.fillText(p.text,p.x,p.y);
    }

    ctx.restore();
  }
}



/* ══════════════════════════════════════════════
   CANVAS VIGNETTE
══════════════════════════════════════════════ */
function drawVignette(){
  // Pull back to ~0.28 effective opacity (gradient bakes 0.55, globalAlpha 0.51 → 0.55×0.51≈0.28)
  ctx.save();
  ctx.globalAlpha=0.51;
  ctx.fillStyle=GC.vignette;ctx.fillRect(0,0,W,H);
  ctx.restore();
}
