/* ══════════════════════════════════════════════
   NITRO SPEED LINES
══════════════════════════════════════════════ */
function updateSpeedLines(dt){
  const _dt=dt||1;
  if(nitroTimer>0||spd>6.5){
    const intensity=nitroTimer>0?1:(spd-6.5)/3;
    const count=nitroTimer>0?4:2;
    const spawns=Math.round(count*_dt);
    for(let i=0;i<spawns;i++){
      const ang=Math.random()*Math.PI*2,dist=30+Math.random()*120;
      const p=_SPEEDLINE_POOL._get();
      p.x=player.visualX+Math.cos(ang)*dist;
      p.y=(player.y-player.jumpOff)+Math.sin(ang)*dist*0.35;
      p.vx=Math.cos(ang)*-(4+Math.random()*6);
      p.vy=Math.sin(ang)*-(1.5+Math.random()*2);
      p.len=18+Math.random()*32;p.life=1;
      p.col=nitroTimer>0?'#f59e0b':'rgba(255,255,255,0.7)';
      p.alpha=0.55*intensity;
    }
  }
  for(let i=0;i<_SPEEDLINE_POOL._n;i++){
    const p=_SPEEDLINE_POOL[i];if(!p._active)continue;
    p.x+=p.vx*_dt;p.y+=p.vy*_dt;p.life-=0.09*_dt;
    if(p.life<=0)p._active=false;
  }
}
function drawSpeedLines(){
  ctx.save();
  for(let i=0;i<_SPEEDLINE_POOL._n;i++){
    const p=_SPEEDLINE_POOL[i];if(!p._active||p.life<=0)continue;
    ctx.globalAlpha=p.life*p.alpha;
    ctx.strokeStyle=p.col;ctx.lineWidth=1.2+p.life;
    ctx.shadowColor=p.col;ctx.shadowBlur=5;
    const ex=p.x-p.vx*p.len*0.12,ey=p.y-p.vy*p.len*0.12;
    ctx.beginPath();ctx.moveTo(p.x,p.y);ctx.lineTo(ex,ey);ctx.stroke();
  }
  ctx.restore();
}
/* ══════════════════════════════════════════════
   LANDING IMPACT RING
══════════════════════════════════════════════ */
function spawnLandingRing(x,y){
  const r=_RING_POOL._get();
  r.x=x;r.y=y;r.r=8;r.life=1;r.maxR=52;
}
function tickLandingRings(dt){
  const _dt=dt||1;
  for(let i=0;i<_RING_POOL._n;i++){
    const r=_RING_POOL[i];if(!r._active)continue;
    r.r+=(r.maxR-r.r)*0.18*_dt;r.life-=0.055*_dt;
    if(r.life<=0)r._active=false;
  }
}
function drawLandingRings(){
  const skin=getSkin();
  for(let i=0;i<_RING_POOL._n;i++){
    const ring=_RING_POOL[i];if(!ring._active||ring.life<=0)continue;
    ctx.save();
    ctx.globalAlpha=ring.life*0.70;
    ctx.strokeStyle=skin.color;ctx.shadowColor=skin.color;ctx.shadowBlur=14;
    ctx.lineWidth=2.5*(ring.life);
    ctx.beginPath();ctx.ellipse(ring.x,ring.y,ring.r,ring.r*0.32,0,0,Math.PI*2);ctx.stroke();
    ctx.restore();
  }
}
/* ══════════════════════════════════════════════
   PARTICLES
══════════════════════════════════════════════ */
function spawnCrashParticles(x,y,isCattle){
  const cols=isCattle?['#dc2626','#f97316','#6b7280','#1f2937','#ff6b00']:['#f97316','#fbbf24','#94a3b8','#475569','#fff'];
  for(let i=0;i<PERF.maxCrash;i++){
    const ang=Math.random()*Math.PI*2,sp=1.5+Math.random()*5;
    const p=_CRASH_POOL._get();
    p.x=x;p.y=y;p.vx=Math.cos(ang)*sp;p.vy=Math.sin(ang)*sp-0.5;
    p.life=1;p.size=3+Math.random()*7;p.color=cols[Math.floor(Math.random()*cols.length)];p.gravity=0;
  }
}
function spawnBloodParticles(x,y){
  const burstCount=Math.ceil(PERF.maxBlood*(60/74));
  for(let i=0;i<burstCount;i++){
    const ang=Math.random()*Math.PI*2,sp=0.8+Math.random()*8,isBig=Math.random()<0.18;
    const p=_BLOOD_POOL._get();
    p.x=x;p.y=y;p.vx=Math.cos(ang)*sp*(isBig?0.7:1);p.vy=Math.sin(ang)*sp*(isBig?0.7:1)-1.5;
    p.life=0.7+Math.random()*0.5;p.size=isBig?(6+Math.random()*10):(1.5+Math.random()*4);
    p.color=Math.random()<0.65?'#cc0000':Math.random()<0.5?'#8b0000':'#aa1111';
    p.gravity=isBig?0.06:0.12;
  }
  const dripCount=PERF.maxBlood-burstCount;
  for(let i=0;i<dripCount;i++){
    const sp=3+Math.random()*9,p=_BLOOD_POOL._get();
    p.x=x+(Math.random()-0.5)*20;p.y=y;p.vx=(Math.random()-0.5)*1.5;p.vy=-sp;
    p.life=0.5+Math.random()*0.4;p.size=1.5+Math.random()*3;p.color='#aa0000';p.gravity=0.15;
  }
  for(let k=0;k<4;k++){
    bloodPools.push({x:x+(Math.random()-0.5)*50,y:y+(Math.random()-0.5)*24,
      rx:12+Math.random()*22,ry:5+Math.random()*9,rot:(Math.random()-0.5)*0.6,
      alpha:0.55+Math.random()*0.35,life:1,decay:0.0008+Math.random()*0.0005});
  }
  bloodPools.push({x,y:y+8,rx:32,ry:13,rot:(Math.random()-0.5)*0.3,alpha:0.75,life:1,decay:0.0005});
}
function spawnShieldBurst(x,y){
  for(let i=0;i<24;i++){
    const ang=Math.random()*Math.PI*2,sp=2+Math.random()*6,p=_SHIELD_POOL._get();
    p.x=x;p.y=y;p.vx=Math.cos(ang)*sp;p.vy=Math.sin(ang)*sp;
    p.life=1;p.size=2+Math.random()*4;p.color=Math.random()<0.5?'#3b82f6':'#bfdbfe';p.gravity=0;
  }
}
function spawnCoinCollect(x,y){
  for(let i=0;i<5;i++){
    const ang=-Math.PI/2+(Math.random()-0.5)*2.0,sp=1.5+Math.random()*3,p=_SHIELD_POOL._get();
    p.x=x;p.y=y;p.vx=Math.cos(ang)*sp;p.vy=Math.sin(ang)*sp-0.8;
    p.life=1.4;p.size=1+Math.random()*2;p.color=Math.random()<0.6?'#fbbf24':'#fde68a';p.gravity=0;
  }
}
// ── Bomb blast render-only state ─────────────────────────────────────
// _bombTrail: [{x,y,life,r}] — brief smoky trail behind each bullet
// _bombBlasts: [{x,y,life,maxLife}] — expanding smoke cloud after impact
let _bombTrail  = [];
let _bombBlasts = [];

function spawnBulletHit(x,y,hitColor){
  // ── Fiery debris particles — base fire + tinted shards matching hit target color ──
  for(let i=0;i<20;i++){
    const ang=Math.random()*Math.PI*2, sp=3+Math.random()*9;
    const p=_CRASH_POOL._get();
    p.x=x; p.y=y;
    p.vx=Math.cos(ang)*sp; p.vy=Math.sin(ang)*sp;
    p.life=1; p.size=3+Math.random()*7;
    p.gravity=0.06;
    const roll=Math.random();
    if(hitColor && roll<0.55){
      // Use the hit target's body color for more than half the particles
      p.color=hitColor;
    } else {
      // Rest: fire/smoke
      p.color=roll<0.35?'#ff6b00':roll<0.65?'#fbbf24':roll<0.82?'#7a7a7a':'#333333';
    }
  }
  // ── Expanding smoke cloud ──
  _bombBlasts.push({x, y, life:1.0, maxLife:1.0});
}
function tickBombBlasts(dt){
  const _dt=dt||1;
  for(let i=_bombBlasts.length-1;i>=0;i--){
    _bombBlasts[i].life-=0.060*_dt;  // full fade in ~0.5s at 60fps
    if(_bombBlasts[i].life<=0)_bombBlasts.splice(i,1);
  }
  // Tick bomb trail
  for(let i=_bombTrail.length-1;i>=0;i--){
    _bombTrail[i].life-=0.18*_dt;   // fades in ~6 frames
    if(_bombTrail[i].life<=0)_bombTrail.splice(i,1);
  }
}
function drawBombBlasts(){
  if(!_bombBlasts.length)return;
  ctx.save();
  for(const b of _bombBlasts){
    const t=1-b.life;               // 0 at birth, 1 at death
    const r=8+t*70;                 // radius expands 8→78px
    const alpha=b.life*0.75;        // fades out
    // Smoke cloud: light silver/white — visible against dark road
    const g=ctx.createRadialGradient(b.x,b.y,r*0.05,b.x,b.y,r);
    g.addColorStop(0,   `rgba(210,205,200,${alpha*0.88})`);
    g.addColorStop(0.25,`rgba(190,185,178,${alpha*0.72})`);
    g.addColorStop(0.55,`rgba(160,155,148,${alpha*0.45})`);
    g.addColorStop(0.80,`rgba(120,115,110,${alpha*0.20})`);
    g.addColorStop(1,   'rgba(80,75,70,0)');
    ctx.fillStyle=g;
    ctx.beginPath();ctx.arc(b.x,b.y,r,0,Math.PI*2);ctx.fill();
    // Bright highlight on smoke puff top — gives the puffy 3D cloud look
    const hg=ctx.createRadialGradient(b.x-r*0.18,b.y-r*0.22,0,b.x,b.y,r*0.55);
    hg.addColorStop(0,   `rgba(240,238,235,${alpha*0.45})`);
    hg.addColorStop(0.5, `rgba(220,215,210,${alpha*0.20})`);
    hg.addColorStop(1,   'rgba(0,0,0,0)');
    ctx.fillStyle=hg;
    ctx.beginPath();ctx.arc(b.x,b.y,r*0.55,0,Math.PI*2);ctx.fill();
    // Inner fireball at birth (first 25% of life)
    if(b.life>0.75){
      const fT=(b.life-0.75)/0.25;  // 1→0 during first quarter
      const fr=4+fT*30;
      const fg=ctx.createRadialGradient(b.x,b.y,0,b.x,b.y,fr);
      fg.addColorStop(0,   `rgba(255,255,200,${fT*0.95})`);
      fg.addColorStop(0.35,`rgba(255,160,0,${fT*0.80})`);
      fg.addColorStop(0.70,`rgba(220,60,0,${fT*0.50})`);
      fg.addColorStop(1,   'rgba(0,0,0,0)');
      ctx.fillStyle=fg;
      ctx.beginPath();ctx.arc(b.x,b.y,fr,0,Math.PI*2);ctx.fill();
    }
  }
  ctx.restore();
}
function drawBombTrail(){
  if(!_bombTrail.length)return;
  ctx.save();
  for(const t of _bombTrail){
    const g=ctx.createRadialGradient(t.x,t.y,0,t.x,t.y,t.r);
    g.addColorStop(0,   `rgba(255,140,20,${t.life*0.60})`);
    g.addColorStop(0.5, `rgba(150,80,10,${t.life*0.35})`);
    g.addColorStop(1,   'rgba(60,30,0,0)');
    ctx.fillStyle=g;
    ctx.beginPath();ctx.arc(t.x,t.y,t.r,0,Math.PI*2);ctx.fill();
  }
  ctx.restore();
}

function tickParticles(arr,grav,dt){
  const _dt=dt||1;
  for(let i=0;i<arr._n;i++){
    const p=arr[i];
    if(!p._active)continue;
    p.x+=p.vx*_dt;p.y+=p.vy*_dt;
    const g=p.gravity!==undefined?p.gravity:(grav||0);
    p.vy+=g*_dt;
    p.vx*=Math.pow(0.91,_dt);p.vy*=Math.pow(0.91,_dt);
    p.life-=0.025*_dt;p.size+=0.1*_dt;
    if(p.life<=0)p._active=false; // return to pool — no splice
  }
}
function drawParticles(arr){
  ctx.save();
  const byCol={};
  for(let i=0;i<arr._n;i++){
    const p=arr[i];
    if(!p._active||p.life<=0)continue;
    (byCol[p.color]||(byCol[p.color]=[])).push(p);
  }
  for(const col in byCol){
    ctx.fillStyle=col;
    byCol[col].forEach(p=>{
      ctx.globalAlpha=p.life*0.90;
      ctx.beginPath();ctx.arc(p.x,p.y,p.size,0,Math.PI*2);ctx.fill();
    });
  }
  ctx.restore();
}
function tickBloodPools(dt){
  const _dt=dt||1;
  bloodPools.forEach(p=>{ p.life-=p.decay*_dt; });
  bloodPools=bloodPools.filter(p=>p.life>0);
  // also scroll with road
  bloodPools.forEach(p=>{ p.y+=spd*_dt; });
  bloodPools=bloodPools.filter(p=>p.y<H+80);
}
function drawBloodPools(){
  if(!bloodPools||!bloodPools.length)return;
  ctx.save();
  bloodPools.forEach(p=>{
    ctx.save();
    ctx.globalAlpha=p.alpha*p.life*0.85;
    ctx.translate(p.x,p.y);ctx.rotate(p.rot);
    // Main irregular splat
    const bg=ctx.createRadialGradient(0,0,0,0,0,p.rx);
    bg.addColorStop(0,'#990000');bg.addColorStop(0.55,'#770000');bg.addColorStop(1,'rgba(80,0,0,0)');
    ctx.fillStyle=bg;
    ctx.beginPath();
    // Jagged ellipse
    const steps=12;
    for(let i=0;i<=steps;i++){
      const a=(i/steps)*Math.PI*2;
      const jitter=0.75+Math.sin(a*3.7+p.rot*8)*0.25;
      const rx=p.rx*jitter, ry=p.ry*jitter;
      const px2=Math.cos(a)*rx, py2=Math.sin(a)*ry;
      i===0?ctx.moveTo(px2,py2):ctx.lineTo(px2,py2);
    }
    ctx.closePath();ctx.fill();
    // Darker center
    ctx.globalAlpha*=0.5;
    ctx.fillStyle='#550000';
    ctx.beginPath();ctx.ellipse(0,0,p.rx*0.4,p.ry*0.4,0,0,Math.PI*2);ctx.fill();
    ctx.restore();
  });
  ctx.restore();
}
function drawExhaust(){
  const trail=getTrail();
  for(let i=0;i<_EXHAUST_POOL._n;i++){
    const p=_EXHAUST_POOL[i];
    if(!p._active||p.life<=0)continue;
    ctx.save();
    if(p.nitro){
      // ── Nitro fire: yellow → orange → violet, no smoke ──
      const t=1-p.life; // 0=fresh, 1=dying
      let r,g,b;
      if(t<0.45){
        // Yellow → orange
        const u=t/0.45;
        r=255;g=Math.floor(230-u*110);b=Math.floor(u*40);
      } else {
        // Orange → violet
        const u=(t-0.45)/0.55;
        r=Math.floor(255-u*115);g=Math.floor(120-u*90);b=Math.floor(40+u*200);
      }
      ctx.globalAlpha=p.life*0.90;
      ctx.fillStyle=`rgb(${r},${g},${b})`;
      ctx.shadowColor=ctx.fillStyle;ctx.shadowBlur=10;
      ctx.beginPath();ctx.arc(p.x,p.y,p.size,0,Math.PI*2);ctx.fill();
    } else {
      // ── Normal smoke / trail exhaust ──
      ctx.globalAlpha=p.life*0.55;
      if(trail.cols){
        const idx=Math.floor((1-p.life)*trail.cols.length);
        ctx.fillStyle=trail.cols[clamp(idx,0,trail.cols.length-1)];
        ctx.shadowColor=ctx.fillStyle;ctx.shadowBlur=4;
      } else {
        const v=Math.floor(p.life*55);ctx.fillStyle=`rgb(${175+v},${175+v},${200+v})`;
      }
      ctx.beginPath();ctx.arc(p.x,p.y,p.size,0,Math.PI*2);ctx.fill();
    }
    ctx.restore();
  }
}



/* ══════════════════════════════════════════════
   DRAW — SPEED BUMP
══════════════════════════════════════════════ */
function drawSpeedBump(o){
  const x=LANE_XS[o.lane];
  const bw=32, bh=12;
  const bx=x-bw/2, by=o.y-bh/2;
  ctx.save();
  // Ground shadow
  ctx.globalAlpha=0.28;ctx.fillStyle='rgba(0,0,0,0.5)';
  ctx.beginPath();ctx.ellipse(x+2,o.y+bh/2+4,bw*0.65,5,0,0,Math.PI*2);ctx.fill();
  ctx.globalAlpha=1;
  // ── 3D RAISED BUMP — front face (visible sloped face) ──
  const frontH=7;
  ctx.fillStyle='#1a1a1a';
  ctx.beginPath();ctx.moveTo(bx,by+bh);ctx.lineTo(bx+bw,by+bh);ctx.lineTo(bx+bw,by+bh-frontH+2);ctx.lineTo(bx,by+bh-frontH+2);ctx.closePath();ctx.fill();
  // Top face — alternating yellow/black stripes with 3D tilt
  for(let i=0;i<4;i++){
    const sx=bx+i*(bw/4), sw=bw/4;
    ctx.fillStyle=i%2===0?'#e8b800':'#1a1a1a';
    ctx.beginPath();ctx.moveTo(sx,by);ctx.lineTo(sx+sw,by);ctx.lineTo(sx+sw,by+bh-frontH+2);ctx.lineTo(sx,by+bh-frontH+2);ctx.closePath();ctx.fill();
  }
  // Front face stripes (darker, bottom-angled for 3D depth)
  for(let i=0;i<4;i++){
    const sx=bx+i*(bw/4), sw=bw/4;
    ctx.fillStyle=i%2===0?'rgba(200,140,0,0.8)':'rgba(0,0,0,0.85)';
    ctx.beginPath();ctx.moveTo(sx,by+bh-frontH+2);ctx.lineTo(sx+sw,by+bh-frontH+2);ctx.lineTo(sx+sw,by+bh);ctx.lineTo(sx,by+bh);ctx.closePath();ctx.fill();
  }
  // Top highlight edge
  ctx.save();ctx.globalAlpha=0.35;ctx.fillStyle='#ffdd44';ctx.fillRect(bx,by,bw,3);ctx.restore();
  // Outer border
  ctx.strokeStyle='rgba(255,210,40,0.80)';ctx.lineWidth=1.2;ctx.strokeRect(bx,by,bw,bh);
  ctx.restore();
}
/* ══════════════════════════════════════════════
   DRAW — BROKEN CAR (2-lane wide)
══════════════════════════════════════════════ */
function drawBrokenCar(o){
  const x1=LANE_XS[Math.min(o.lane,2)];
  const x2=LANE_XS[Math.min(o.lane+1,3)];
  const cx=(x1+x2)/2, cy=o.y;
  ctx.save();

  // Ground shadow — large since car is sideways
  ctx.globalAlpha=0.32;
  const shG=ctx.createRadialGradient(cx+4,cy+28,2,cx+4,cy+28,60);
  shG.addColorStop(0,'rgba(0,0,0,0.65)');shG.addColorStop(1,'transparent');
  ctx.fillStyle=shG;ctx.beginPath();ctx.ellipse(cx+4,cy+28,62,14,0,0,Math.PI*2);ctx.fill();
  ctx.globalAlpha=1;

  // ── BODY — crashed car lying sideways ──
  // Underbody / bottom face (visible because car is angled)
  ctx.fillStyle='#2a1010';
  ctx.beginPath();ctx.moveTo(cx-52,cy-10);ctx.lineTo(cx+52,cy-10);ctx.lineTo(cx+52,cy-6);ctx.lineTo(cx-52,cy-6);ctx.closePath();ctx.fill();

  // Main body face — gradient with damage coloring
  const bodyG=ctx.createLinearGradient(cx-50,cy-16,cx+50,cy+16);
  bodyG.addColorStop(0,'#4a1010');bodyG.addColorStop(0.3,'#722020');bodyG.addColorStop(0.6,'#6a1c1c');bodyG.addColorStop(1,'#3a0c0c');
  ctx.fillStyle=bodyG;rr(cx-52,cy-16,104,30,7);ctx.fill();
  // Body top highlight
  ctx.save();ctx.globalAlpha=0.15;ctx.fillStyle='#fff';ctx.fillRect(cx-48,cy-15,100,5);ctx.restore();
  // Crumple / damage lines
  ctx.strokeStyle='rgba(255,80,0,0.6)';ctx.lineWidth=1.2;
  ctx.beginPath();ctx.moveTo(cx-30,cy-15);ctx.lineTo(cx-18,cy-2);ctx.lineTo(cx-22,cy+12);ctx.stroke();
  ctx.beginPath();ctx.moveTo(cx+20,cy-14);ctx.lineTo(cx+32,cy+2);ctx.stroke();

  // Broken windows — dark angled panes
  ctx.fillStyle='rgba(60,90,120,0.50)';rr(cx-38,cy-13,24,16,3);ctx.fill();
  rr(cx+14,cy-13,24,16,3);ctx.fill();
  // Window frame
  ctx.strokeStyle='rgba(40,60,80,0.7)';ctx.lineWidth=1;
  rr(cx-38,cy-13,24,16,3);ctx.stroke();rr(cx+14,cy-13,24,16,3);ctx.stroke();
  // Crack on windshield
  ctx.strokeStyle='rgba(255,255,255,0.65)';ctx.lineWidth=0.9;
  ctx.beginPath();ctx.moveTo(cx-30,cy-12);ctx.lineTo(cx-25,cy-4);ctx.lineTo(cx-29,cy+2);ctx.stroke();

  // Exposed wheel (bottom-facing, since car is on side)
  [[cx-44,cy+14],[cx-44,cy-14],[cx+44,cy+14],[cx+44,cy-14]].forEach(([wx,wy])=>{
    ctx.fillStyle='#101018';rr(wx-6,wy-5,12,10,3);ctx.fill();
    ctx.fillStyle='#5a5a70';rr(wx-4,wy-3,8,6,2);ctx.fill();
    ctx.strokeStyle='#3a3a50';ctx.lineWidth=0.6;rr(wx-4,wy-3,8,6,2);ctx.stroke();
  });

  // Warning triangle on road ahead
  ctx.save();
  ctx.shadowColor='rgba(255,70,0,0.8)';ctx.shadowBlur=10;
  ctx.fillStyle='rgba(255,65,0,0.92)';
  ctx.beginPath();ctx.moveTo(cx,cy-34);ctx.lineTo(cx+12,cy-14);ctx.lineTo(cx-12,cy-14);ctx.closePath();ctx.fill();
  ctx.strokeStyle='#ff6600';ctx.lineWidth=1.5;
  ctx.beginPath();ctx.moveTo(cx,cy-34);ctx.lineTo(cx+12,cy-14);ctx.lineTo(cx-12,cy-14);ctx.closePath();ctx.stroke();
  ctx.fillStyle='#fff';ctx.font="bold 10px 'Orbitron',sans-serif";ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillText('!',cx,cy-23);
  ctx.restore();

  ctx.restore();
}
/* ══════════════════════════════════════════════
   DRAW — TRUCK  (2-hit obstacle, same direction as player)
   t.y = top of cab. hits=0 -> full container (72px); hits=1 -> short (36px).
══════════════════════════════════════════════ */
function drawTruck(t){
  const cx=LANE_XS[t.lane];
  const ty=t.y;
  const CAB_W=44, CAB_H=35;
  const CONT_W=40;
  const contH=t.hits>=1?36:72;
  const gapY=ty+CAB_H+4;

  // Fade to 50% while player is crossing through (nitro smash or shield pass)
  const _truckAlpha = t._nitroOverlap ? 0.50 : 1.0;

  ctx.save();
  if(_truckAlpha < 1.0) ctx.globalAlpha = _truckAlpha;

  // Ground shadow
  ctx.save();ctx.globalAlpha=0.28;
  const shG=ctx.createRadialGradient(cx+4,ty+CAB_H*0.5,2,cx,ty+CAB_H*0.5,CONT_W*0.95);
  shG.addColorStop(0,'rgba(0,0,0,0.65)');shG.addColorStop(1,'transparent');
  ctx.fillStyle=shG;
  ctx.beginPath();ctx.ellipse(cx,ty+CAB_H+contH*0.5,CONT_W*0.88,11,0,0,Math.PI*2);ctx.fill();
  ctx.restore();

  // Cab body
  ctx.fillStyle='#2e3140';
  rr(cx-CAB_W/2,ty,CAB_W,CAB_H,5);ctx.fill();
  const cabG=ctx.createLinearGradient(cx-CAB_W/2,0,cx+CAB_W/2,0);
  cabG.addColorStop(0,'rgba(255,255,255,0.04)');
  cabG.addColorStop(0.25,'rgba(255,255,255,0.10)');
  cabG.addColorStop(0.5,'rgba(255,255,255,0.14)');
  cabG.addColorStop(0.75,'rgba(255,255,255,0.08)');
  cabG.addColorStop(1,'rgba(255,255,255,0.02)');
  ctx.fillStyle=cabG;
  rr(cx-CAB_W/2,ty,CAB_W,CAB_H,5);ctx.fill();
  ctx.strokeStyle='#1a1c24';ctx.lineWidth=1.5;
  rr(cx-CAB_W/2,ty,CAB_W,CAB_H,5);ctx.stroke();

  // Windshield
  ctx.save();
  const wsG=ctx.createLinearGradient(0,ty+3,0,ty+17);
  wsG.addColorStop(0,'rgba(155,215,245,0.88)');
  wsG.addColorStop(1,'rgba(70,145,205,0.55)');
  ctx.fillStyle=wsG;
  ctx.beginPath();
  ctx.moveTo(cx-CAB_W/2+8,ty+3);ctx.lineTo(cx+CAB_W/2-8,ty+3);
  ctx.lineTo(cx+CAB_W/2-5,ty+17);ctx.lineTo(cx-CAB_W/2+5,ty+17);
  ctx.closePath();ctx.fill();
  ctx.globalAlpha=0.32;ctx.fillStyle='#fff';
  ctx.beginPath();
  ctx.moveTo(cx-CAB_W/2+9,ty+4);ctx.lineTo(cx-CAB_W/2+16,ty+4);
  ctx.lineTo(cx-CAB_W/2+13,ty+16);ctx.lineTo(cx-CAB_W/2+7,ty+16);
  ctx.closePath();ctx.fill();
  ctx.restore();

  // Headlights
  ctx.save();
  ctx.shadowColor='#c8e8ff';ctx.shadowBlur=8;ctx.fillStyle='#c8e8ff';
  ctx.fillRect(cx-CAB_W/2+3,ty,11,3);ctx.fillRect(cx+CAB_W/2-14,ty,11,3);
  ctx.shadowBlur=0;ctx.restore();

  // Side mirrors
  ctx.fillStyle='#252830';
  ctx.fillRect(cx-CAB_W/2-5,ty+9,5,4);ctx.fillRect(cx+CAB_W/2,ty+9,5,4);

  // Grille
  ctx.fillStyle='#111318';
  rr(cx-CAB_W/2+8,ty+CAB_H-7,CAB_W-16,6,2);ctx.fill();
  ctx.save();ctx.strokeStyle='rgba(90,95,110,0.8)';ctx.lineWidth=0.9;
  for(let gi=0;gi<5;gi++){
    const gx=cx-CAB_W/2+10+gi*5;
    ctx.beginPath();ctx.moveTo(gx,ty+CAB_H-6);ctx.lineTo(gx,ty+CAB_H-2);ctx.stroke();
  }
  ctx.restore();

  // Coupling
  ctx.fillStyle='#1c1e28';ctx.fillRect(cx-8,ty+CAB_H,16,4);
  ctx.fillStyle='#3a3d50';ctx.fillRect(cx-5,ty+CAB_H+1,10,2);

  // Container
  const contX=cx-CONT_W/2;
  const ctG=ctx.createLinearGradient(contX,0,contX+CONT_W,0);
  ctG.addColorStop(0,'#9a9a9a');ctG.addColorStop(0.10,'#d8d8d8');
  ctG.addColorStop(0.50,'#f5f5f5');ctG.addColorStop(0.90,'#d8d8d8');ctG.addColorStop(1,'#9a9a9a');
  ctx.fillStyle=ctG;
  rr(contX,gapY,CONT_W,contH,3);ctx.fill();
  ctx.strokeStyle='#7a7a7a';ctx.lineWidth=1;
  rr(contX,gapY,CONT_W,contH,3);ctx.stroke();

  // Horizontal ribs
  ctx.save();ctx.strokeStyle='rgba(90,90,90,0.30)';ctx.lineWidth=0.9;
  const ribCount=t.hits>=1?2:5;
  for(let r=0;r<ribCount;r++){
    const ry=gapY+(contH/(ribCount+1))*(r+1);
    ctx.beginPath();ctx.moveTo(contX+4,ry);ctx.lineTo(contX+CONT_W-4,ry);ctx.stroke();
  }
  ctx.restore();

  // Edge rails
  ctx.save();ctx.globalAlpha=0.45;ctx.fillStyle='#aaa';
  ctx.fillRect(contX+2,gapY+3,3,contH-6);ctx.fillRect(contX+CONT_W-5,gapY+3,3,contH-6);
  ctx.globalAlpha=0.55;ctx.fillStyle='#fff';
  ctx.fillRect(contX+3,gapY+4,1,contH-8);ctx.fillRect(contX+CONT_W-4,gapY+4,1,contH-8);
  ctx.restore();

  // Damage effects after 1st hit
  if(t.hits>=1){
    const tearY=gapY+contH-2;
    const zigPts=[0,4,2,6,3,5,1,4,2,5,0];
    const step=CONT_W/10;
    ctx.save();ctx.fillStyle='#1a1a2e';
    ctx.beginPath();ctx.moveTo(contX,tearY);
    for(let zi=0;zi<=10;zi++) ctx.lineTo(contX+zi*step,tearY-(zigPts[zi%zigPts.length]));
    ctx.lineTo(contX+CONT_W,gapY+contH+3);ctx.lineTo(contX,gapY+contH+3);
    ctx.closePath();ctx.fill();ctx.restore();
    ctx.save();ctx.globalAlpha=0.65;
    ctx.fillStyle='#e85500';ctx.beginPath();ctx.ellipse(contX+7,tearY-5,6,3,0,0,Math.PI*2);ctx.fill();
    ctx.fillStyle='#ffaa00';ctx.beginPath();ctx.ellipse(contX+CONT_W-9,tearY-4,5,2.5,0,0,Math.PI*2);ctx.fill();
    ctx.globalAlpha=0.12;ctx.fillStyle='#ff4400';
    rr(contX,gapY,CONT_W,contH,3);ctx.fill();
    ctx.restore();
  }

  // Wheels
  const wW=10,wH=14;
  [[cx-CAB_W/2-7,ty+7],[cx+CAB_W/2-3,ty+7],[contX-7,gapY+contH-21],[contX+CONT_W-3,gapY+contH-21]].forEach(([wx,wy])=>{
    const wcx=wx+wW/2,wcy=wy+wH/2;
    ctx.fillStyle='#181820';rr(wx,wy,wW,wH,3);ctx.fill();
    ctx.strokeStyle='#2a2a35';ctx.lineWidth=0.8;rr(wx,wy,wW,wH,3);ctx.stroke();
    ctx.save();ctx.beginPath();rr(wx+1,wy+1,wW-2,wH-2,2);ctx.clip();
    ctx.fillStyle='#6a6a80';ctx.fillRect(wx+1,wy+1,wW-2,wH-2);
    ctx.translate(wcx,wcy);
    ctx.strokeStyle='#4a4a60';ctx.lineWidth=1;
    for(let s=0;s<4;s++){const a=(s/4)*Math.PI*2;ctx.beginPath();ctx.moveTo(0,0);ctx.lineTo(Math.cos(a)*4,Math.sin(a)*5);ctx.stroke();}
    ctx.restore();
  });

  ctx.restore();
}
/* ══════════════════════════════════════════════
   DRAW — BOSS PURSUIT CAR
══════════════════════════════════════════════ */
function drawBossCar(bc){
  const cx=bc.x,cy=bc.y;
  const bw=44, bh=72;
  const bx=cx-bw/2, by=cy-bh/2;
  ctx.save();
  // Boss comes from top, front faces DOWN toward player
  // We draw it in natural orientation (front at bottom) then flip
  ctx.translate(cx,cy);ctx.scale(1,-1);ctx.translate(-cx,-cy);

  // Ground shadow
  ctx.save();ctx.globalAlpha=0.35;
  const shG=ctx.createRadialGradient(cx,cy+bh*0.46,2,cx,cy+bh*0.46,bw);
  shG.addColorStop(0,'rgba(0,0,0,0.7)');shG.addColorStop(1,'transparent');
  ctx.fillStyle=shG;ctx.beginPath();ctx.ellipse(cx,cy+bh*0.45,bw*0.9,11,0,0,Math.PI*2);ctx.fill();
  ctx.restore();

  // Wheel arches
  ctx.fillStyle='#1a2030';
  ctx.beginPath();ctx.ellipse(bx+2,by+22,10,6,0,0,Math.PI*2);ctx.fill();
  ctx.beginPath();ctx.ellipse(bx+bw-2,by+22,10,6,0,0,Math.PI*2);ctx.fill();
  ctx.beginPath();ctx.ellipse(bx+2,by+bh-22,10,6,0,0,Math.PI*2);ctx.fill();
  ctx.beginPath();ctx.ellipse(bx+bw-2,by+bh-22,10,6,0,0,Math.PI*2);ctx.fill();

  // Body — police white/silver with lateral gradient
  const bodyG=ctx.createLinearGradient(bx,0,bx+bw,0);
  bodyG.addColorStop(0,'#b0c0d0');bodyG.addColorStop(0.2,'#d8e4ee');bodyG.addColorStop(0.5,'#eaf0f8');bodyG.addColorStop(0.8,'#c8d8e8');bodyG.addColorStop(1,'#a0b4c4');
  ctx.fillStyle=bodyG;
  ctx.beginPath();
  ctx.moveTo(bx+4,by+14);ctx.lineTo(bx+bw-4,by+14);
  ctx.lineTo(bx+bw,by+bh-4);ctx.lineTo(bx,by+bh-4);
  ctx.closePath();ctx.fill();

  // Police side stripe — bold black band across middle
  ctx.fillStyle='#111822';ctx.fillRect(bx,cy-7,bw,16);
  // "POLICE" text on stripe
  ctx.fillStyle='#fbbf24';ctx.font="bold 7px 'Orbitron',sans-serif";
  ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillText('POLICE',cx,cy+1);

  // Body highlight crease
  ctx.save();ctx.globalAlpha=0.20;ctx.fillStyle='#fff';
  ctx.fillRect(bx+4,by+18,3,bh-36);ctx.fillRect(bx+bw-7,by+18,3,bh-36);ctx.restore();

  // Roof / cabin
  const roofG=ctx.createLinearGradient(bx+8,0,bx+bw-8,0);
  roofG.addColorStop(0,'#6070a0');roofG.addColorStop(0.5,'#8090b8');roofG.addColorStop(1,'#6070a0');
  ctx.fillStyle=roofG;
  ctx.beginPath();ctx.moveTo(bx+10,by+13);ctx.lineTo(bx+bw-10,by+13);ctx.lineTo(bx+bw-6,by+34);ctx.lineTo(bx+6,by+34);ctx.closePath();ctx.fill();

  // Windshield
  const wsG=ctx.createLinearGradient(bx+14,by+8,bx+14,by+30);
  wsG.addColorStop(0,'rgba(140,200,255,0.88)');wsG.addColorStop(0.4,'rgba(100,170,230,0.75)');wsG.addColorStop(1,'rgba(60,120,200,0.55)');
  ctx.fillStyle=wsG;
  ctx.beginPath();ctx.moveTo(bx+12,by+14);ctx.lineTo(bx+bw-12,by+14);ctx.lineTo(bx+bw-8,by+31);ctx.lineTo(bx+8,by+31);ctx.closePath();ctx.fill();
  ctx.save();ctx.globalAlpha=0.25;ctx.fillStyle='#fff';
  ctx.beginPath();ctx.moveTo(bx+14,by+15);ctx.lineTo(bx+20,by+15);ctx.lineTo(bx+16,by+29);ctx.lineTo(bx+11,by+29);ctx.closePath();ctx.fill();ctx.restore();

  // Side mirrors
  ctx.fillStyle='#8090a0';
  ctx.fillRect(bx-5,by+18,5,4);ctx.fillRect(bx+bw,by+18,5,4);

  // Bumper
  ctx.fillStyle='#8090a8';
  ctx.beginPath();ctx.moveTo(bx+4,by+14);ctx.lineTo(bx+bw-4,by+14);ctx.lineTo(bx+bw-2,by+18);ctx.lineTo(bx+2,by+18);ctx.closePath();ctx.fill();

  // ── POLICE LIGHT BAR — 3D raised bar on roof ──
  const flashOn=Math.floor(frameCount/6)%2===0;
  // Bar body (physical bar shape)
  ctx.fillStyle='#222835';rr(cx-16,cy-42,32,7,3);ctx.fill();
  ctx.strokeStyle='#3a4050';ctx.lineWidth=0.8;rr(cx-16,cy-42,32,7,3);ctx.stroke();
  // Red and blue light pods
  ctx.save();ctx.shadowColor=flashOn?'#ef4444':'#3b82f6';ctx.shadowBlur=22;
  ctx.fillStyle=flashOn?'#ff4444':'#1a1a2a';
  rr(cx-15,cy-41,13,5,2);ctx.fill();
  ctx.fillStyle=flashOn?'#1a1a2a':'#3b82f6';
  rr(cx+2,cy-41,13,5,2);ctx.fill();
  ctx.restore();
  // Light flare glow above bar
  ctx.save();ctx.globalAlpha=0.18;
  ctx.fillStyle=flashOn?'#ff4444':'#3366ff';
  ctx.beginPath();ctx.ellipse(cx,cy-46,18,6,0,0,Math.PI*2);ctx.fill();ctx.restore();

  // Headlights at front (bottom = player-facing after flip)
  const hlY=by+2;
  ctx.fillStyle='#222230';ctx.fillRect(bx+2,hlY,14,7);ctx.fillRect(bx+bw-16,hlY,14,7);
  ctx.save();ctx.shadowColor='#fff0a0';ctx.shadowBlur=18;ctx.fillStyle='#fffce0';
  ctx.fillRect(bx+3,hlY+1,12,5);ctx.fillRect(bx+bw-15,hlY+1,12,5);ctx.restore();

  // Taillights at rear (top after flip)
  const tlY=by+bh-7;
  ctx.fillStyle='#1a0a0a';ctx.fillRect(bx+2,tlY-1,14,8);ctx.fillRect(bx+bw-16,tlY-1,14,8);
  ctx.save();ctx.shadowColor='#ff2222';ctx.shadowBlur=14;ctx.fillStyle='#ff3333';
  ctx.fillRect(bx+3,tlY,12,6);ctx.fillRect(bx+bw-15,tlY,12,6);ctx.restore();

  // Wheels — wide police cruiser style
  const _wSpin=4*frameCount*0.05;
  [[bx-7,by+16,10,14],[bx+bw-3,by+16,10,14],[bx-7,by+bh-30,10,14],[bx+bw-3,by+bh-30,10,14]].forEach(([wx,wy,ww,wh])=>{
    const wcx=wx+ww/2,wcy=wy+wh/2;
    ctx.fillStyle='#181820';rr(wx,wy,ww,wh,3);ctx.fill();
    ctx.save();ctx.beginPath();rr(wx+1,wy+1,ww-2,wh-2,2);ctx.clip();
    ctx.fillStyle='#6a6a80';ctx.fillRect(wx+1,wy+1,ww-2,wh-2);
    ctx.translate(wcx,wcy);ctx.rotate(_wSpin);
    ctx.strokeStyle='#3a3a50';ctx.lineWidth=1;
    for(let s=0;s<5;s++){const a=(s/5)*Math.PI*2;ctx.beginPath();ctx.moveTo(0,0);ctx.lineTo(Math.cos(a)*4,Math.sin(a)*5);ctx.stroke();}
    ctx.restore();
  });

  ctx.restore();
}

/* ══════════════════════════════════════════════
   DRAW (main)
══════════════════════════════════════════════ */
/* ══════════════════════════════════════════════
   DRAW — CONTEXTUAL TUTORIAL HINT
   Ring tracks live object position each frame.
   Tooltip avoids top HUD and jump bar zones.
   Alpha driven by elapsed/fadeOut, not a timer.
══════════════════════════════════════════════ */
function drawTutorial(){
  if(!tut) return;
  if(gst!==ST.PLAYING&&gst!==ST.RESPAWNING) return;

  // ── Resolve live ring position ──
  const obj = tut.objRef;
  let ringX = LANE_XS[1]; // safe fallback
  let ringY = 200;
  if(obj && obj._active){
    ringY = obj.y + (TUT_RING_OFFSET[tut.key]||0);
    if(tut.key==='cattle'){
      ringX = obj.x;
    } else if(tut.key==='brokencar'){
      ringX = (LANE_XS[Math.min(obj.lane,2)]+LANE_XS[Math.min(obj.lane+1,3)])/2;
    } else if(obj.lane!==undefined){
      ringX = LANE_XS[obj.lane];
    } else {
      ringX = obj.x||LANE_XS[1];
    }
  }

  // Don't render while object is still off the top of screen
  if(ringY < TUT_TRIGGER_Y - 10) return;

  // ── Alpha: fade in over 10f, hold, fade out over 14f when dismissing ──
  const fadeIn  = clamp(tut.elapsed/10, 0, 1);
  const fadeOut = tut.dismissing ? clamp(tut.fadeOut/14, 0, 1) : 1.0;
  const alpha   = fadeIn * fadeOut;
  if(alpha <= 0.01) return;

  const TW=160, TH=50;
  // Safe zone: below top HUD (scorebox+combo badge ~72px), above player area
  const HUD_TOP = 72, HUD_BOT = 485;

  // Flip decision is locked at hint creation time — read from tut, never recalculate
  const flippedBelow = tut.flippedBelow;
  let tipY = flippedBelow ? ringY + 42 : ringY - TH - 38;
  tipY = clamp(tipY, HUD_TOP, HUD_BOT);

  // Left margin 52px clears the jump bar (x=8, width ~36px)
  let tipX = ringX - TW/2;
  tipX = clamp(tipX, 52, W-TW-8);

  // Arrow connects tooltip edge to ring, flips with tooltip
  const arrowX     = clamp(ringX, tipX+16, tipX+TW-16);
  const arrowBaseY = flippedBelow ? tipY     : tipY+TH;
  const arrowTipY  = flippedBelow ? tipY-10  : tipY+TH+10;

  ctx.save();
  ctx.globalAlpha = alpha;

  // ── Pulsing glow ring — follows live object every frame ──
  const ringR = TUT_RING_RADIUS[tut.key] || 32;
  const pulse = 0.72 + fastSin(frameCount*0.18)*0.28;
  ctx.save();
  ctx.globalAlpha = alpha * pulse * 0.55;
  ctx.strokeStyle = '#00e676'; ctx.lineWidth = 2.5;
  ctx.shadowColor = '#00e676'; ctx.shadowBlur = 14;
  ctx.beginPath(); ctx.arc(ringX, ringY, ringR, 0, Math.PI*2); ctx.stroke();
  ctx.globalAlpha = alpha * pulse * 0.20;
  ctx.lineWidth = 7;
  ctx.beginPath(); ctx.arc(ringX, ringY, ringR, 0, Math.PI*2); ctx.stroke();
  ctx.restore();

  // ── Arrow ──
  ctx.save();
  ctx.globalAlpha = alpha * 0.90;
  ctx.fillStyle = '#00e676'; ctx.shadowColor = '#00e676'; ctx.shadowBlur = 8;
  ctx.beginPath();
  ctx.moveTo(arrowX-8, arrowBaseY); ctx.lineTo(arrowX+8, arrowBaseY);
  ctx.lineTo(arrowX, arrowTipY); ctx.closePath(); ctx.fill();
  ctx.restore();

  // ── Tooltip panel ──
  ctx.save();
  ctx.globalAlpha = alpha;
  ctx.fillStyle = 'rgba(4,10,22,0.92)';
  ctx.shadowColor = '#00e676'; ctx.shadowBlur = 16;
  rr(tipX, tipY, TW, TH, 10); ctx.fill();
  ctx.shadowBlur = 0; ctx.strokeStyle = '#00e676'; ctx.lineWidth = 1.5;
  rr(tipX, tipY, TW, TH, 10); ctx.stroke();
  ctx.restore();

  // ── Slam-in text: 1.30→1.00 scale, white→mint, cubic ease over 6 frames ──
  const slamEase  = 1 - Math.pow(1-tut.slamT, 3);
  const slamScale = 1.30 - 0.30*slamEase;
  const centX = tipX + TW/2;
  const centY = tipY + TH/2 - 4;
  ctx.save();
  ctx.globalAlpha  = alpha;
  ctx.translate(centX, centY); ctx.scale(slamScale, slamScale);
  ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
  ctx.font = "900 15px 'Orbitron',impact,sans-serif";
  const cr = Math.round(lerp(255,  0,   slamEase));
  const cg = Math.round(lerp(255, 230,  slamEase));
  const cb = Math.round(lerp(255, 118,  slamEase));
  ctx.fillStyle = `rgb(${cr},${cg},${cb})`;
  ctx.shadowColor = `rgb(${cr},${cg},${cb})`; ctx.shadowBlur = lerp(0,12,slamEase);
  ctx.fillText(tut.msg, 0, 0);
  ctx.restore();

  // ── "TAP TO SKIP" — appears once slam settles ──
  if(tut.slamT > 0.7){
    const sa = clamp((tut.slamT-0.7)/0.3, 0, 1) * alpha * 0.55;
    ctx.save();
    ctx.globalAlpha = sa;
    ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
    ctx.font = "600 7px 'Rajdhani',sans-serif"; ctx.fillStyle = '#94a3b8';
    ctx.fillText('TAP TO SKIP', centX, tipY+TH-9);
    ctx.restore();
  }

  ctx.restore();
}

function draw(){
  ctx.clearRect(0,0,W,H);

  // ── HUD visibility: throttled — only touch DOM when state actually changes ──
  const _hudVisible = gst===ST.PLAYING||gst===ST.RESPAWNING||gst===ST.CRASHING;
  const _inGame = _hudVisible||gst===ST.REVIVE||gamePaused||exitConfirmActive;
  const _hudOp = _hudVisible ? '1' : '0';
  const _inGameDisp = _inGame ? 'flex' : 'none';
  if(_hudEl  && _hudEl._lastOp  !== _hudOp) { _hudEl.style.opacity  = _hudOp;       _hudEl._lastOp  = _hudOp; }
  if(_jbarEl) { _jbarEl.style.display = 'none'; } // jump bar removed — no longer needed
  if(_scBtn  && _scBtn._lastDisp !== _inGameDisp) { _scBtn.style.display   = _inGameDisp; _scBtn._lastDisp  = _inGameDisp; }
  if(_pauseBtn && _pauseBtn._lastDisp !== _inGameDisp) { _pauseBtn.style.display = _inGameDisp; _pauseBtn._lastDisp = _inGameDisp; }
  if(_exitBtn  && _exitBtn._lastDisp  !== _inGameDisp) { _exitBtn.style.display  = _inGameDisp; _exitBtn._lastDisp  = _inGameDisp; }
  // Fire button: visible only during active gameplay, hidden on splash/menu screens
  if(_fireBtn){ const _fd=_hudVisible?'flex':'none'; if(_fireBtn._lastDisp!==_fd){_fireBtn.style.display=_fd;_fireBtn._lastDisp=_fd;} }
  // Nitro button: mirrors fire button visibility; CSS handles active/dim state
  if(_nitroBtn){ const _nd=_hudVisible?'flex':'none'; if(_nitroBtn._lastDisp!==_nd){_nitroBtn.style.display=_nd;_nitroBtn._lastDisp=_nd;} }

  // ENGINE START screen and Splash render their own full scene — skip all game world drawing
  if(gst===ST.ENGINE){drawEngineStart();return;}
  // Splash renders its own full scene — skip all game world drawing
  if(gst===ST.SPLASH){drawSplash();return;}

  ctx.save();
  if(shakeAmt>0)ctx.translate((Math.random()-0.5)*shakeAmt*0.65,(Math.random()-0.5)*shakeAmt*0.4);
  // Almost dead zoom — slight push-in centred on player
  const _adActive=almostDeadTimer>0&&(gst===ST.PLAYING||gst===ST.RESPAWNING||gst===ST.CRASHING);
  if(_adActive){
    const _zoomT=almostDeadTimer/500;
    const _zoom=1+0.065*_zoomT;
    const _zx=player.visualX, _zy=player.y-player.jumpOff;
    ctx.translate(_zx,_zy);ctx.scale(_zoom,_zoom);ctx.translate(-_zx,-_zy);
  }

  // Environment (top-down mode)
  drawBackground(); drawRoad();

  // Collectibles — skip if off-screen
  if(gst!==ST.GAMEOVER&&gst!==ST.INTRO&&gst!==ST.SHOP&&gst!==ST.HOWTO){
    for(let i=0;i<_COIN_POOL._n;i++){
      const c=_COIN_POOL[i]; if(!c._active||c.y<-20||c.y>H+20) continue;
      drawCoin(c);
    }
    for(let i=0;i<_PU_POOL._n;i++){
      const p=_PU_POOL[i]; if(!p._active||p.y<-30||p.y>H+30) continue;
      drawPowerUpIcon(p.x, p.y, p.type, 14);
    }
  }

  // Obstacles — always draw at full alpha (never vanish on jump)
  for(let i=0;i<_OBST_POOL._n;i++){
    const o=_OBST_POOL[i]; if(!o._active||o.y<-80||o.y>H+80) continue;
    if(o.type==='speedbump') drawSpeedBump(o);
    else if(o.type==='brokencar') drawBrokenCar(o);
    else drawObstacle(o, 1);
  }

  // Trucks
  for(let i=0;i<_TRUCK_POOL._n;i++){
    const t=_TRUCK_POOL[i];if(!t._active)continue;
    const truckBottom=t.y+35+4+(t.hits>=1?36:72);
    if(truckBottom<-10||t.y>H+10)continue;
    drawTruck(t);
  }

  // Cattle — always draw; reduce opacity to 50% when player is jumping directly over
  drawBloodPools();
  for(let i=0;i<_CATTLE_POOL._n;i++){
    const c=_CATTLE_POOL[i]; if(!c._active) continue;
    const under=player.jumping&&Math.abs(c.x-player.visualX)<40&&Math.abs(c.y-player.y)<65;
    if(under){ ctx.save(); ctx.globalAlpha=0.50; }
    if(c.dead) drawDeadCattle(c); else drawCattle(c);
    if(under){ ctx.restore(); }
  }

  // Particles (behind player)
  drawParticles(bloodP); drawParticles(crashP); drawParticles(shieldBurstP);
  drawExhaust();
  tickBombBlasts(1);
  drawLandingRings();

  // Jump shadow
  if(player.jumping){
    const sc=1-player.jumpOff/(JUMP_H*1.6);
    ctx.save(); ctx.globalAlpha=0.22*sc;
    const jsh=ctx.createRadialGradient(player.visualX,player.y+4,0,player.visualX,player.y+4,20*sc);
    jsh.addColorStop(0,'rgba(0,0,0,0.5)'); jsh.addColorStop(1,'transparent');
    ctx.fillStyle=jsh; ctx.fillRect(player.visualX-20,player.y-5,40,20);
    ctx.restore();
  }

  // ── PLAYER CAR ───────────────────────────────
  const skin=getSkin();
  const dmgProg=gst===ST.CRASHING?clamp(crashTimer/28,0,1):0;
  const flashVis=gst!==ST.RESPAWNING||Math.floor(player.invTimer/5)%2===0;
  // Respawn fade-in: car materialises from invisible to full over 30 frames
  const _respawnAlpha=(respawnFadeTimer>0)?clamp(1-respawnFadeTimer/30,0,1):1;
  if(flashVis){
    const _pDrawX = player.visualX;
    const _recoilOff = (gunRecoilTimer>0)?3:0;
    const _pDrawY = player.y - player.jumpOff + _recoilOff;
    if(_respawnAlpha<1){ctx.save();ctx.globalAlpha=_respawnAlpha;}
    if(player.jumping && player.jumpOff > 2){
      const jumpPhase = Math.sin(player.jumpProg * Math.PI);
      const jumpScale = 1 + jumpPhase * 0.22;
      ctx.save();
      ctx.translate(_pDrawX, _pDrawY); ctx.scale(jumpScale, jumpScale); ctx.translate(-_pDrawX, -_pDrawY);
      ctx.translate(_pDrawX, _pDrawY); ctx.rotate(jumpPhase * 0.04); ctx.translate(-_pDrawX, -_pDrawY);
      drawCar(_pDrawX, _pDrawY, skin.color, skin.hl, true, dmgProg, playerTilt);
      ctx.restore();
    } else {
      drawCar(_pDrawX, _pDrawY, skin.color, skin.hl, true, dmgProg, playerTilt);
    }
    if(_respawnAlpha<1){ctx.restore();}
  }
  drawShieldBubble();
  drawSpeedLines();

  // ── BOMBS (projectiles) ──────────────────────
  if(gst===ST.PLAYING||gst===ST.RESPAWNING){

    // Collect current positions for trail
    for(let _bi=0;_bi<_BULLET_POOL._n;_bi++){
      const _blt=_BULLET_POOL[_bi]; if(!_blt._active) continue;
      _bombTrail.push({x:_blt.x, y:_blt.y+6, life:1.0, r:9});
    }

    // Draw smoky trail first (behind bomb)
    drawBombTrail();

    // Draw each bomb
    ctx.save();
    for(let _bi=0;_bi<_BULLET_POOL._n;_bi++){
      const _blt=_BULLET_POOL[_bi]; if(!_blt._active) continue;
      const _bx=_blt.x, _by=_blt.y;

      // Outer orange flare (elongated in travel direction)
      ctx.save();
      ctx.shadowColor='#ff6b00'; ctx.shadowBlur=22;
      const _flG=ctx.createRadialGradient(_bx,_by+4,0,_bx,_by+4,18);
      _flG.addColorStop(0,  'rgba(255,200,60,0.90)');
      _flG.addColorStop(0.4,'rgba(255,100,0,0.60)');
      _flG.addColorStop(1,  'rgba(255,50,0,0)');
      ctx.fillStyle=_flG;
      ctx.beginPath(); ctx.ellipse(_bx,_by+8,9,20,0,0,Math.PI*2); ctx.fill();
      ctx.restore();

      // Cannonball body — dark iron sphere with hot glowing ring + shine
      ctx.save();
      // Outer glow aura
      ctx.shadowColor='#ff4400'; ctx.shadowBlur=22;
      // Iron body: dark grey with subtle warm sheen (top-left lit)
      const _bG=ctx.createRadialGradient(_bx-4,_by-4,0.5,_bx,_by,12);
      _bG.addColorStop(0,  '#6a5a4a');   // lit face — warm grey
      _bG.addColorStop(0.35,'#3a2e22');  // mid tone
      _bG.addColorStop(0.70,'#1c1408');  // dark side
      _bG.addColorStop(1,  '#0a0805');   // edge rim
      ctx.fillStyle=_bG;
      ctx.beginPath(); ctx.arc(_bx,_by,12,0,Math.PI*2); ctx.fill();
      // Hot orange glowing equator ring
      ctx.strokeStyle='#ff5500'; ctx.lineWidth=2.8;
      ctx.shadowColor='#ff3300'; ctx.shadowBlur=16;
      ctx.beginPath(); ctx.arc(_bx,_by,12,0,Math.PI*2); ctx.stroke();
      ctx.shadowBlur=0;
      // Primary specular highlight — bright white catch-light top-left
      ctx.globalAlpha=0.80;
      ctx.fillStyle='#ffffff';
      ctx.beginPath(); ctx.ellipse(_bx-4,_by-5,3.5,2.2,Math.PI*0.35,0,Math.PI*2); ctx.fill();
      // Secondary softer sheen — warm off-white
      ctx.globalAlpha=0.35;
      ctx.fillStyle='#ffe8c0';
      ctx.beginPath(); ctx.ellipse(_bx-2,_by-3,5,3,Math.PI*0.25,0,Math.PI*2); ctx.fill();
      // Rim light on bottom-right edge (light bounce)
      ctx.globalAlpha=0.25;
      ctx.fillStyle='#ff8844';
      ctx.beginPath(); ctx.ellipse(_bx+5,_by+5,2.5,1.5,Math.PI*0.8,0,Math.PI*2); ctx.fill();
      ctx.restore();
    }
    ctx.restore();

    // Muzzle flash — enlarged to match bomb scale
    if(gunMuzzleFlash>0){
      const _mAlpha=clamp(gunMuzzleFlash/3,0,1);
      const _mRecoil=(gunRecoilTimer>0)?3:0;
      const _mpx=player.visualX,_mpy=player.y-player.jumpOff+_mRecoil-42;
      ctx.save();ctx.globalAlpha=_mAlpha;
      // Outer bloom
      ctx.fillStyle='rgba(255,140,0,0.55)';ctx.shadowColor='#ff8800';ctx.shadowBlur=24;
      ctx.beginPath();ctx.ellipse(_mpx,_mpy,28,16,0,0,Math.PI*2);ctx.fill();
      // Inner white core
      ctx.fillStyle='#ffffff';ctx.shadowColor='#ffffa0';ctx.shadowBlur=20;
      ctx.beginPath();ctx.ellipse(_mpx,_mpy,16,10,0,0,Math.PI*2);ctx.fill();
      ctx.restore();
    }

    // Draw bomb blast smoke clouds (in front of particles)
    drawBombBlasts();
  }

  // ── ENEMY CARS ───────────────────────────────
  const _ENEMY_COLS=['#e84118','#1e40af','#cbd5e1'];
  const _ENEMY_HLS =['#ff8c6a','#93c5fd','#ffffff'];
  for(let i=0;i<_ENEMY_POOL._n;i++){
    const e=_ENEMY_POOL[i]; if(!e._active||e.y<-80||e.y>H+80) continue;
    // Assign color variety at first draw — persists on object for its lifetime
    if(!e._drawColor){
      const ci=Math.floor(Math.random()*3);
      e._drawColor=_ENEMY_COLS[ci];
      e._drawHL=_ENEMY_HLS[ci];
    }
    const eLaneX = LANE_XS[e.lane];
    ctx.save(); ctx.translate(eLaneX,e.y); ctx.scale(1,-1); ctx.translate(-eLaneX,-e.y);
    drawCar(eLaneX, e.y, e._drawColor, e._drawHL, false, 0);
    ctx.restore();
    if(e.y>-60&&e.y<H+60){
      ctx.save(); ctx.globalAlpha=0.06;
      ctx.translate(0, e.y+60);
      ctx.fillStyle=GC.enemyHL[eLaneX];
      ctx.beginPath();
      ctx.moveTo(eLaneX-18,-28); ctx.lineTo(eLaneX+18,-28);
      ctx.lineTo(eLaneX+50,60); ctx.lineTo(eLaneX-50,60);
      ctx.closePath(); ctx.fill(); ctx.restore();
    }
  }

  // Boss pursuit car
  if(bossActive&&bossCar)drawBossCar(bossCar);

  // Crash flash — simple radial fill replaced with fast flat fill (imperceptible difference at crash speed)
  if(gst===ST.CRASHING&&crashTimer<14){
    ctx.save();ctx.globalAlpha=(1-crashTimer/14)*0.55;
    ctx.fillStyle='rgba(255,80,0,0.9)';ctx.fillRect(0,0,W,H);ctx.restore();
  }

  ctx.restore(); // end shake

  // Post-processing effects
  drawSpeedOverlay();
  drawWeatherOverlay();
  drawVignette();
  drawVerticalPowerBars();

  // ── Danger vignette — last life ──
  if(player.lives<=1&&(gst===ST.PLAYING||gst===ST.RESPAWNING)){
    const dAlpha=0.18+fastSin(dangerPulse)*0.12;
    ctx.save();
    // Use cached gradient, modulate via globalAlpha instead of rebuilding every frame
    if(!GC.dangerVig){
      const dvg=ctx.createRadialGradient(W/2,H/2,H*0.22,W/2,H/2,H*0.78);
      dvg.addColorStop(0,'transparent');dvg.addColorStop(1,'rgba(220,20,20,1)');
      GC.dangerVig=dvg;
    }
    ctx.globalAlpha=dAlpha;
    ctx.fillStyle=GC.dangerVig;ctx.fillRect(0,0,W,H);
    ctx.globalAlpha=dAlpha*0.6;
    ctx.strokeStyle='rgba(255,40,40,0.7)';ctx.lineWidth=4;
    ctx.strokeRect(2,2,W-4,H-4);
    ctx.restore();
  }

  // ── ALMOST DEAD overlay — cinematic crash moment ──
  if(_adActive){
    const _at=almostDeadTimer/750; // 1.0→0.0 over 750ms
    ctx.save();
    if(!GC.adVig){
      const _vg=ctx.createRadialGradient(W/2,H/2,H*0.08,W/2,H/2,H*0.70);
      _vg.addColorStop(0,'transparent');_vg.addColorStop(0.6,'rgba(200,0,0,0.6)');_vg.addColorStop(1,'rgba(255,0,0,1)');
      GC.adVig=_vg;
    }
    // Vignette — peaks at start, fades as crash continues
    ctx.globalAlpha=0.25+_at*0.50;
    ctx.fillStyle=GC.adVig;ctx.fillRect(0,0,W,H);
    // Pulsing border ring
    ctx.globalAlpha=0.50+_at*0.40;
    ctx.strokeStyle='rgba(255,20,20,1)';ctx.lineWidth=4+_at*5;
    ctx.strokeRect(3,3,W-6,H-6);
    ctx.restore();

    // ── Explosion starburst + CRASH! — 120px above crash point ──
    // Shown ONLY when no lives remain (final death crash)
    // Pop in: first 20% = 150ms | Hold: 150ms–637ms (~490ms) | Fade: last 15% = 112ms
    const _popT=clamp((1-_at)/0.20,0,1);
    const _fadeT=clamp(_at/0.15,0,1);
    const _bAlpha=_popT*(0.3+_fadeT*0.7);
    if(_bAlpha>0.02&&player.lives<=1){
      const _bx=clamp(crashX,-10+W*0.18,W-W*0.18);
      const _by=crashY-120; // 120px above impact
      const _scale=0.5+_popT*0.65;
      const _outerR=46*_scale, _innerR=22*_scale;
      const _pts=12;
      ctx.save();
      ctx.globalAlpha=_bAlpha;
      ctx.translate(_bx,_by);
      ctx.rotate(fastSin(crashTimer*0.4)*0.08);

      // Fill gradient — soft yellow core → yellow → orange → transparent tips (no pure white)
      const _eg=ctx.createRadialGradient(0,0,_innerR*0.3,0,0,_outerR);
      _eg.addColorStop(0,'#fff5a0');
      _eg.addColorStop(0.25,'#ffec40');
      _eg.addColorStop(0.65,'#ff7a00');
      _eg.addColorStop(1,'rgba(220,30,0,0)');

      // Starburst polygon
      ctx.beginPath();
      for(let _i=0;_i<_pts*2;_i++){
        const _a=(_i*Math.PI/_pts)-Math.PI/2;
        const _r=_i%2===0?_outerR:_innerR;
        if(_i===0) ctx.moveTo(Math.cos(_a)*_r,Math.sin(_a)*_r);
        else ctx.lineTo(Math.cos(_a)*_r,Math.sin(_a)*_r);
      }
      ctx.closePath();
      ctx.fillStyle=_eg;ctx.fill();

      // Outer glow
      ctx.globalAlpha=_bAlpha*0.45;
      ctx.shadowColor='#ff8800';ctx.shadowBlur=18;
      ctx.strokeStyle='rgba(255,180,0,0.85)';ctx.lineWidth=2;ctx.stroke();

      // CRASH! text inside starburst — yellow tint, not pure white
      ctx.globalAlpha=Math.min(1,_bAlpha*1.1);
      ctx.shadowColor='#ff4400';ctx.shadowBlur=10;
      ctx.fillStyle='#ffe566';
      ctx.font="900 "+Math.round(14*_scale)+"px 'Orbitron',sans-serif";
      ctx.textAlign='center';ctx.textBaseline='middle';
      ctx.fillText('CRASH!',0,1);
      ctx.restore();
    }
  }

  // ── Lives-remaining banner — independent timer, 1.5× duration, no starburst ──
  // Shown whenever player survives a crash (lives > 0 remaining)
  if(livesTextTimer>0){
    const _lt=livesTextTimer/1125; // 1.0→0.0 over 1125ms
    const _msgIn=clamp((1-_lt)/0.10,0,1);   // fade in over first 10% (~112ms)
    const _msgOut=clamp(_lt/0.06,0,1);        // fade out over last 6% (~67ms)
    const _msgAlpha=_msgIn*_msgOut;
    if(_msgAlpha>0.02){
      const _msgTxt=livesTextCount>=2?(livesTextCount+' LIVES LEFT'):'LAST LIFE';
      const _pillCol=livesTextCount>=2?'#f97316':'#ef4444'; // orange for multi-life, red for last
      const _msgX=W/2;
      const _msgY=H*0.45; // clear of HUD, above player action zone
      const _pw=190,_ph=38;
      ctx.save();
      ctx.globalAlpha=_msgAlpha;
      ctx.textAlign='center';ctx.textBaseline='middle';
      // Dark pill
      ctx.fillStyle='rgba(4,6,18,0.90)';
      rr(_msgX-_pw/2,_msgY-_ph/2,_pw,_ph,10);ctx.fill();
      ctx.save();ctx.shadowColor=_pillCol;ctx.shadowBlur=14;
      ctx.strokeStyle=_pillCol;ctx.lineWidth=1.8;
      rr(_msgX-_pw/2,_msgY-_ph/2,_pw,_ph,10);ctx.stroke();ctx.restore();
      // Text
      ctx.shadowColor=_pillCol;ctx.shadowBlur=8;
      ctx.fillStyle='#fff8d0';
      ctx.font="900 14px 'Orbitron',sans-serif";
      ctx.fillText(_msgTxt,_msgX,_msgY);
      ctx.shadowBlur=0;
      ctx.restore();
    }
  }

  // Oil slick removed

  // ── Breathing room indicator (stage 10+, brief clear stretches) ──
  if(clearStretchTimer>0&&stageNum>=10){
    const br_a=Math.min(1,clearStretchTimer/40)*Math.min(1,(clearStretchTimer)/40)*0.55;
    ctx.save();ctx.globalAlpha=br_a;
    ctx.fillStyle='rgba(0,230,118,0.06)';ctx.fillRect(0,0,W,H);
    ctx.font="bold 10px 'Orbitron',sans-serif";ctx.textAlign='center';ctx.fillStyle='rgba(0,230,118,0.65)';
    ctx.fillText('CLEAR ROAD',W/2,H-56);
    ctx.restore();
  }

  // ── Stage flash — cinematic version ──
  if(stageFlash){
    const t=stageFlash.timer;
    const maxT=220;
    // Flash phase 0-20f: white screen slam
    if(t>200){
      const sl=1-(t-200)/20;
      ctx.save();ctx.globalAlpha=sl*0.82;ctx.fillStyle='#fff';ctx.fillRect(0,0,W,H);ctx.restore();
    }
    // Main display phase 180-30f
    const a=clamp(Math.min(t/30,(maxT-t)/18),0,1);
    if(a>0.01){
      ctx.save();ctx.globalAlpha=a;
      // Background pulse — very subtle so road stays fully visible
      ctx.fillStyle=stageFlash.boss?'rgba(220,30,30,0.08)':'rgba(250,200,0,0.05)';
      ctx.fillRect(0,0,W,H);
      // Pill backdrop — 75% size, anchored near top of screen (clear of player action zone)
      const col=stageFlash.boss?'#ef4444':'#fbbf24';
      const pillW=165,pillH=51;
      // Fixed Y near top — below HUD (~60px), well above mid-screen obstacles
      const pillCY=118;
      ctx.fillStyle='rgba(4,6,18,0.42)';
      rr(W/2-pillW/2,pillCY-pillH/2,pillW,pillH,11);ctx.fill();
      ctx.save();ctx.shadowColor=col;ctx.shadowBlur=18;
      ctx.strokeStyle=col;ctx.lineWidth=1.5;
      rr(W/2-pillW/2,pillCY-pillH/2,pillW,pillH,11);ctx.stroke();
      ctx.restore();
      // STAGE text
      ctx.textAlign='center';ctx.textBaseline='middle';
      ctx.font="900 21px 'Orbitron',impact,sans-serif";
      ctx.fillStyle=col;ctx.shadowColor=col;ctx.shadowBlur=12;
      const scale=1+Math.sin((1-a)*Math.PI*0.5)*0.12;
      ctx.save();ctx.translate(W/2,pillCY-9);ctx.scale(scale,scale);
      ctx.fillText('STAGE '+stageFlash.stage,0,0);ctx.restore();
      // Sub text — stage-specific mechanic hints
      const stageHints={
        2:'ROCKS & MANHOLES AHEAD',3:'WATCH YOUR SPEED',
        4:'CATTLE! JUMP OR DODGE',5:'JUMP TIMING IS KEY',
        6:'WRECKS INCOMING',7:'PLAN YOUR ROUTE',
        8:'ROADWORKS + BOSS CHASE',9:'THREE THREATS AT ONCE',
        10:'FULL CHAOS — STAY SHARP'
      };
      const subTxt = stageFlash.boss ? '⚠ BOSS INCOMING!' : (stageHints[stageFlash.stage]||'SPEED UP!');
      ctx.font="bold 10px 'Orbitron',sans-serif";
      ctx.fillStyle=stageFlash.boss?'#fca5a5':'#fed7aa';ctx.shadowBlur=6;
      ctx.fillText(subTxt,W/2,pillCY+13);
      ctx.textBaseline='alphabetic';ctx.restore();
    }
  }

  // ── NEW RECORD flash ──
  if(newRecordFlash>0){
    const a=clamp(Math.min(newRecordFlash/20,(180-newRecordFlash)/18+1)*1,0,1)*clamp(newRecordFlash/180*3,0,1);
    if(a>0.01){
      ctx.save();ctx.globalAlpha=a;
      ctx.fillStyle='rgba(250,204,21,0.12)';ctx.fillRect(0,0,W,H);
      const pillW=220,pillH=42;
      ctx.fillStyle='rgba(4,6,18,0.90)';rr(W/2-pillW/2,72,pillW,pillH,12);ctx.fill();
      ctx.save();ctx.shadowColor='#fbbf24';ctx.shadowBlur=22;
      ctx.strokeStyle='#fbbf24';ctx.lineWidth=2;rr(W/2-pillW/2,72,pillW,pillH,12);ctx.stroke();ctx.restore();
      ctx.textAlign='center';ctx.textBaseline='middle';
      ctx.font="900 18px 'Orbitron',impact,sans-serif";ctx.fillStyle='#fef9c3';ctx.shadowColor='#fbbf24';ctx.shadowBlur=12;
      const pulse=1+fastSin(frameCount*0.25)*0.06;
      ctx.save();ctx.translate(W/2,93);ctx.scale(pulse,pulse);
      ctx.fillText('🏆 NEW RECORD!',0,0);ctx.restore();
      ctx.textBaseline='alphabetic';ctx.restore();
    }
  }

  // ── NEW BEST celebration — confetti + large pulsing text ──
  if(newBestCelebTimer>0){
    const celebA=newBestCelebTimer>20?1:newBestCelebTimer/20;
    // Draw confetti particles
    ctx.save();
    confettiParticles.forEach(p=>{
      ctx.save();
      ctx.globalAlpha=celebA*clamp(p.life,0,1);
      ctx.fillStyle=p.color;
      ctx.shadowColor=p.color;ctx.shadowBlur=4;
      ctx.translate(p.x,p.y);ctx.rotate(p.rot);
      ctx.fillRect(-p.size/2,-p.size*0.35,p.size,p.size*0.7);
      ctx.restore();
    });
    ctx.restore();
    // Golden border glow around score box area (top-left HUD)
    const _gbPulse=0.6+fastSin(frameCount*0.22)*0.4;
    ctx.save();
    ctx.globalAlpha=celebA*_gbPulse*0.85;
    ctx.strokeStyle='#fbbf24';ctx.lineWidth=3;
    ctx.shadowColor='#fbbf24';ctx.shadowBlur=18;
    ctx.strokeRect(2,2,W-4,H-4);
    ctx.shadowBlur=0;
    ctx.restore();
    // Large "NEW BEST!" pulsing text in centre
    const _nbPulse=1+fastSin(frameCount*0.20)*0.08;
    ctx.save();
    ctx.globalAlpha=celebA;
    ctx.textAlign='center';ctx.textBaseline='middle';
    ctx.save();ctx.translate(W/2,H/2-20);ctx.scale(_nbPulse,_nbPulse);
    ctx.font="900 36px 'Orbitron',impact,sans-serif";
    ctx.fillStyle='#fbbf24';ctx.shadowColor='#f59e0b';ctx.shadowBlur=32;
    ctx.fillText('NEW BEST!',0,0);
    ctx.shadowBlur=0;ctx.restore();
    ctx.restore();
  }

  // ── SAVED! shield flash ──
  if(savedFlash>0){
    const a=clamp(savedFlash/55,0,1);
    ctx.save();ctx.globalAlpha=a;
    // Slow-mo blue tint
    ctx.fillStyle='rgba(59,130,246,0.15)';ctx.fillRect(0,0,W,H);
    // Text
    ctx.textAlign='center';ctx.textBaseline='middle';
    ctx.font="900 36px 'Orbitron',impact,sans-serif";
    ctx.fillStyle='#93c5fd';ctx.shadowColor='#3b82f6';ctx.shadowBlur=28;
    const sc=0.8+a*0.35;ctx.save();ctx.translate(W/2,H/2-40);ctx.scale(sc,sc);
    ctx.fillText('SAVED!',0,0);ctx.restore();
    ctx.textBaseline='alphabetic';ctx.restore();
  }

  // ── Mission complete toast — top of screen, below HUD ──
  if(missionCompleteFlash>0){
    const a=clamp(Math.min(missionCompleteFlash/20,(240-missionCompleteFlash)/20),0,1);
    if(a>0.01){
      ctx.save();ctx.globalAlpha=a;
      // Compact pill just below the HUD boxes (~y=52), centered, narrow enough to miss mute button on right
      const pillW=220,pillH=28,pillX=(W-pillW)/2,pillY=54;
      ctx.fillStyle='rgba(4,6,18,0.92)';rr(pillX,pillY,pillW,pillH,8);ctx.fill();
      ctx.save();ctx.shadowColor='#4ade80';ctx.shadowBlur=14;
      ctx.strokeStyle='#4ade80';ctx.lineWidth=1.4;rr(pillX,pillY,pillW,pillH,8);ctx.stroke();ctx.restore();
      ctx.textAlign='center';ctx.textBaseline='middle';
      ctx.font="bold 10px 'Orbitron',sans-serif";ctx.fillStyle='#bbf7d0';
      ctx.fillText('✓ '+missionCompleteText,W/2,pillY+pillH/2);
      ctx.textBaseline='alphabetic';ctx.restore();
    }
  }

  // ── Extra life — heart particle animation ──
  if(lifeMsg){
    const t=lifeMsg.timer; // 240→0
    const prog=1-t/240;   // 0→1
    const cx=lifeMsg.cx||W/2, cy=lifeMsg.cy||(H*0.40);
    const htx=lifeMsg.htx||70, hty=lifeMsg.hty||14;

    if(prog<0.28){
      // Phase 1 (0→0.28): particles converge to heart outline
      const p=prog/0.28;
      ctx.save();
      lifeMsg.pts.forEach(pt=>{
        const px=pt.sx+(pt.tx-pt.sx)*p;
        const py=pt.sy+(pt.ty-pt.sy)*p;
        ctx.globalAlpha=0.30+p*0.70;
        ctx.fillStyle='#f9a8d4';
        ctx.shadowColor='#ec4899';ctx.shadowBlur=8;
        ctx.beginPath();ctx.arc(px,py,2+p*1.5,0,Math.PI*2);ctx.fill();
      });
      ctx.restore();
    } else if(prog<0.55){
      // Phase 2 (0.28→0.55): full heart + "EXTRA LIFE!" text fully visible
      const pulse=1.0+Math.sin(frameCount*0.25)*0.07;
      _drawAnimHeart(ctx,cx,cy,28*pulse,1.0);
      ctx.save();
      ctx.globalAlpha=1.0;
      ctx.textAlign='center';ctx.textBaseline='middle';
      ctx.font="900 13px 'Orbitron',impact,sans-serif";
      ctx.fillStyle='#fce7f3';
      ctx.shadowColor='#ec4899';ctx.shadowBlur=14;
      ctx.fillText('EXTRA LIFE!',cx,cy+46);
      ctx.shadowBlur=0;ctx.restore();
    } else if(prog<0.72){
      // Phase 3 (0.55→0.72): heart stays, text fades OUT
      const p=(prog-0.55)/0.17; // 0→1
      const textAlpha=1.0-p;
      _drawAnimHeart(ctx,cx,cy,28,1.0);
      ctx.save();
      ctx.globalAlpha=textAlpha;
      ctx.textAlign='center';ctx.textBaseline='middle';
      ctx.font="900 13px 'Orbitron',impact,sans-serif";
      ctx.fillStyle='#fce7f3';
      ctx.shadowColor='#ec4899';ctx.shadowBlur=10;
      ctx.fillText('EXTRA LIFE!',cx,cy+46);
      ctx.shadowBlur=0;ctx.restore();
    } else {
      // Phase 4 (0.72→1.0): text gone, heart flies to HUD slot with ease-in-out
      const p=(prog-0.72)/0.28; // 0→1 linear
      // Ease-in-out cubic — starts slow, fast in middle, decelerates to HUD
      const ease=p<0.5?4*p*p*p:1-Math.pow(-2*p+2,3)/2;
      const hx=cx+(htx-cx)*ease;
      const hy=cy+(hty-cy)*ease;
      // Shrink from r=28 to r=5 as it approaches HUD
      const r=28-(28-5)*ease;
      // Fade out the flying heart as it lands — HUD heart appears simultaneously
      const alpha=p>0.85?1-(p-0.85)/0.15:1.0;
      _drawAnimHeart(ctx,hx,hy,r,alpha);
      // When heart is ~90% of the way to HUD, reveal the new heart in the indicator
      if(!lifeMsg.hudUpdated&&ease>0.90){
        lifeMsg.hudUpdated=true;
        _redrawHeartsCanvas(lifeMsg.newLives);
      }
    }
  }

  // ── Active mission bar with progress (bottom strip) ──
  if(activeMission&&(gst===ST.PLAYING||gst===ST.RESPAWNING)){
    // Calculate mission progress 0-1
    let _mProg=0;
    if(activeMission.id==='coins15')   _mProg=Math.min(sessionCoins,15)/15;
    else if(activeMission.id==='nearMiss3') _mProg=Math.min(nearMissStreak,3)/3;
    else if(activeMission.id==='nitroRain') _mProg=runNitroRainDone?1:0;
    else if(activeMission.id==='stages3')   _mProg=Math.min(runStagesSurvived,3)/3;
    // Bar geometry
    const _mY=H-22, _mH=18, _mX=4, _mW=W-8, _mR=5;
    ctx.save();ctx.globalAlpha=0.88;
    // Background pill
    ctx.fillStyle='rgba(4,6,20,0.85)';rr(_mX,_mY,_mW,_mH,_mR);ctx.fill();
    ctx.strokeStyle='rgba(99,179,237,0.25)';ctx.lineWidth=1;rr(_mX,_mY,_mW,_mH,_mR);ctx.stroke();
    // Icon + mission text
    ctx.textAlign='left';ctx.textBaseline='middle';
    ctx.font="600 8.5px 'Rajdhani',sans-serif";
    ctx.fillStyle='#fbbf24';ctx.fillText('🎯',_mX+6,_mY+_mH/2);
    ctx.fillStyle='#94a3b8';
    // Truncate text to fit
    const _maxTxtW=_mW-70;
    let _mTxt=activeMission.text;
    ctx.font="600 8px 'Rajdhani',sans-serif";
    while(ctx.measureText(_mTxt).width>_maxTxtW&&_mTxt.length>8)_mTxt=_mTxt.slice(0,-1);
    if(_mTxt!==activeMission.text)_mTxt=_mTxt.slice(0,-1)+'…';
    ctx.fillText(_mTxt,_mX+20,_mY+_mH/2);
    // Progress bar on right
    const _bX=_mW-58,_bW=52,_bY=_mY+5,_bH=8;
    ctx.fillStyle='rgba(30,40,70,0.9)';rr(_bX,_bY,_bW,_bH,4);ctx.fill();
    if(_mProg>0){
      const _fillCol=_mProg>=1?'#4ade80':'#60a5fa';
      ctx.fillStyle=_fillCol;
      if(_mProg>=1){ctx.shadowColor='#4ade80';ctx.shadowBlur=6;}
      rr(_bX,_bY,Math.max(8,_bW*_mProg),_bH,4);ctx.fill();
      ctx.shadowBlur=0;
    }
    ctx.strokeStyle='rgba(99,179,237,0.30)';ctx.lineWidth=0.8;rr(_bX,_bY,_bW,_bH,4);ctx.stroke();
    ctx.restore();
  }

  drawNMPopups();
  drawTutorial();
  drawTutorialPhase();
  // Tutorial rewind overlay — blue tint + REWIND text
  if(tutRewindActive && (gst===ST.PLAYING||gst===ST.RESPAWNING)) _drawRewindOverlay();
  drawComboMeter();
  drawActivePowerUps();
  drawGunFireHint();
  drawPlayerPowerStatus();
  drawPuBanner();
  drawPerfBadge();

  if(gst===ST.SPLASH)    {drawSplash(); return;}
  if(gst===ST.REVIVE)    drawRevive();
  if(gst===ST.GAMEOVER)  drawGameOver();
  if(gst===ST.LEADERBOARD) drawLeaderboard();
  if(gst===ST.INTRO)     drawIntro();
  if(gst===ST.HOWTO)     drawHowTo();
  if(gst===ST.STATS)     drawStatsScreen();
  if(gst===ST.SHOP)      drawShop();

  // ── Pause / Exit overlays (always on top) ──
  if(gamePaused)       drawPauseOverlay();
  if(exitConfirmActive) drawExitConfirmOverlay();
}

/* ══════════════════════════════════════════════
   DRAW — GUIDED FIRST-RUN TUTORIAL PHASE OVERLAY
   Phases 1-5 replace old 0-16 tutorial system.
   Big green sweeping arrows, lane glows, rewind.
══════════════════════════════════════════════ */

/* ── Big sweeping green screen arrow (like attached image) ──────────────
   dir: 'right' | 'left'
   Sweeps continuously across the screen at 50% max opacity.
   Shape: chunky arrow with notched tail, solid green fill. */
/* ── Double-chevron directional arrows ─────────────────────────────────
   Two tall green ">>" or "<<" shapes. Small, upper-half of screen.
   Fade in → drift slightly → fade out. Never start from screen edges.  */
function _drawBigScreenArrow(dir){
  const cycle = 80;
  const t = (frameCount % cycle) / cycle;

  // Fade envelope: in 0→35%, hold, out 65→100%
  let fEnv;
  if(t < 0.35)      fEnv = t / 0.35;
  else if(t < 0.65) fEnv = 1.0;
  else              fEnv = (1 - t) / 0.35;
  if(fEnv <= 0.02) return;

  // Inherit caller's globalAlpha — allows caller to cap opacity further
  const _callerAlpha = ctx.globalAlpha;
  const baseAlpha = _callerAlpha * 0.40 * fEnv; // 40% max opacity

  // Drift: ±18px in indicated direction over the cycle
  const drift = (t - 0.5) * 36;
  const baseCX = W * 0.50;
  const cx = baseCX + (dir === 'right' ? drift : -drift);
  const AY = H * 0.30;

  const CH = H * 0.22, halfH = CH / 2;
  const CW = 44, SEP = 30;
  const c1x = dir === 'right' ? cx - SEP/2 : cx + SEP/2;
  const c2x = dir === 'right' ? cx + SEP/2 : cx - SEP/2;

  function _ch(cxc){
    ctx.beginPath();
    if(dir === 'right'){
      ctx.moveTo(cxc - CW, AY - halfH);
      ctx.lineTo(cxc + CW, AY);
      ctx.lineTo(cxc - CW, AY + halfH);
    } else {
      ctx.moveTo(cxc + CW, AY - halfH);
      ctx.lineTo(cxc - CW, AY);
      ctx.lineTo(cxc + CW, AY + halfH);
    }
    ctx.closePath();
  }

  ctx.save();
  ctx.shadowBlur = 0; // no blur — sharp crisp edges

  // Trailing chevron — slightly dimmer
  ctx.globalAlpha = baseAlpha * 0.60;
  ctx.fillStyle = '#00c83a';
  _ch(c1x); ctx.fill();
  ctx.strokeStyle = '#ffffff'; ctx.lineWidth = 2.5;
  _ch(c1x); ctx.stroke();

  // Leading chevron — full opacity
  ctx.globalAlpha = baseAlpha;
  ctx.fillStyle = '#00cc44';
  _ch(c2x); ctx.fill();
  ctx.strokeStyle = '#ffffff'; ctx.lineWidth = 2.5;
  _ch(c2x); ctx.stroke();

  ctx.restore();
}

/* ── Up arrow flowing over an obstacle, prompting the player to jump ── */
function _drawUpArrowOnObst(obsRef){
  if(!obsRef||!obsRef._active) return;
  const ox = LANE_XS[obsRef.lane];
  // Bob the arrow above the obstacle
  const bobOffset = 6 + 6*Math.abs(Math.sin(frameCount*0.09));
  const arTipY  = obsRef.y - 34 - bobOffset;
  const arBaseY = arTipY + 38;
  const hdW = 24, shW = 8, hdH = 16;

  ctx.save();
  ctx.globalAlpha = 0.60 + 0.35*Math.abs(Math.sin(frameCount*0.11));
  ctx.fillStyle   = '#4ade80';
  ctx.shadowColor = '#22c55e';
  ctx.shadowBlur  = 14;
  ctx.beginPath();
  ctx.moveTo(ox,           arTipY          );  // tip
  ctx.lineTo(ox + hdW/2,   arTipY + hdH   );  // right head
  ctx.lineTo(ox + shW/2,   arTipY + hdH   );  // right shaft top
  ctx.lineTo(ox + shW/2,   arBaseY        );  // right shaft bottom
  ctx.lineTo(ox - shW/2,   arBaseY        );  // left shaft bottom
  ctx.lineTo(ox - shW/2,   arTipY + hdH   );  // left shaft top
  ctx.lineTo(ox - hdW/2,   arTipY + hdH   );  // left head
  ctx.closePath();
  ctx.fill();
  ctx.shadowBlur = 0;
  ctx.restore();
}

/* ── Angled arrow from game field toward fire button ────────────────── */
function _drawFireButtonArrow(){
  const fbX = W - 33, fbY = H - 66;
  const arStartX = W * 0.62, arStartY = H * 0.68;
  const angle = Math.atan2(fbY - arStartY, fbX - arStartX);
  const len   = 60;
  const midX  = (arStartX + fbX) * 0.5;
  const midY  = (arStartY + fbY) * 0.5;
  const blink = 0.45 + 0.55*Math.abs(Math.sin(frameCount * 0.04));
  ctx.save();
  ctx.globalAlpha = blink;
  ctx.translate(midX, midY);
  ctx.rotate(angle);
  const aw = len, ah = 32, hw = aw/2, hh = ah/2;
  const headW = hh * 1.1, bodyH = hh * 0.40, notchD = hw * 0.25;
  ctx.fillStyle='#00cc44'; ctx.shadowColor='#00e676'; ctx.shadowBlur=16;
  ctx.beginPath();
  ctx.moveTo( hw,             0       );
  ctx.lineTo( hw - headW,    -hh      );
  ctx.lineTo( hw - headW,    -bodyH   );
  ctx.lineTo(-hw + notchD,   -bodyH   );
  ctx.lineTo(-hw,             0       );
  ctx.lineTo(-hw + notchD,    bodyH   );
  ctx.lineTo( hw - headW,     bodyH   );
  ctx.lineTo( hw - headW,     hh      );
  ctx.closePath();
  ctx.fill();
  ctx.shadowBlur=0; ctx.strokeStyle='#00ff55'; ctx.lineWidth=1.5; ctx.stroke();
  ctx.restore();
}

/* Mirror of _drawFireButtonArrow — points from centre-left toward the nitro button */
function _drawNitroButtonArrow(){
  // Nitro button centre in canvas space: left:8px + w:50px/2 = 33, bottom:10px + h:112px/2 = H-66
  const nbX = 33, nbY = H - 66;
  const arStartX = W * 0.38, arStartY = H * 0.68;
  const angle = Math.atan2(nbY - arStartY, nbX - arStartX);
  const midX  = (arStartX + nbX) * 0.5;
  const midY  = (arStartY + nbY) * 0.5;
  const blink = 0.45 + 0.55*Math.abs(Math.sin(frameCount * 0.04));
  ctx.save();
  ctx.globalAlpha = blink;
  ctx.translate(midX, midY);
  ctx.rotate(angle);
  const len = 60, ah = 32, hw = len/2, hh = ah/2;
  const headW = hh * 1.1, bodyH = hh * 0.40, notchD = hw * 0.25;
  ctx.fillStyle='#00cc44'; ctx.shadowColor='#00e676'; ctx.shadowBlur=16;
  ctx.beginPath();
  ctx.moveTo( hw,             0       );
  ctx.lineTo( hw - headW,    -hh      );
  ctx.lineTo( hw - headW,    -bodyH   );
  ctx.lineTo(-hw + notchD,   -bodyH   );
  ctx.lineTo(-hw,             0       );
  ctx.lineTo(-hw + notchD,    bodyH   );
  ctx.lineTo( hw - headW,     bodyH   );
  ctx.lineTo( hw - headW,     hh      );
  ctx.closePath();
  ctx.fill();
  ctx.shadowBlur=0; ctx.strokeStyle='#00ff55'; ctx.lineWidth=1.5; ctx.stroke();
  ctx.restore();
}

/* ── Tutorial rewind overlay — blue tint + REWIND text ─────────────── */
function _drawRewindOverlay(){
  if(!tutRewindActive) return;
  const a = clamp(tutRewindTimer / 20, 0, 1);
  // Blue tint over whole screen
  ctx.save();
  ctx.globalAlpha = a * 0.28;
  ctx.fillStyle   = 'rgba(30,60,200,1)';
  ctx.fillRect(0, 0, W, H);
  ctx.restore();

  // REWIND text bar
  const blink = 0.55 + 0.45*Math.abs(Math.sin(frameCount * 0.20));
  ctx.save();
  ctx.globalAlpha = a * blink;
  const txt = '◀◀  REWIND';
  ctx.font = "900 22px 'Orbitron',impact,sans-serif";
  const tw = ctx.measureText(txt).width + 36;
  const tx = (W - tw) / 2, ty = H * 0.18;
  ctx.fillStyle = 'rgba(10,20,50,0.88)';
  rr(tx, ty, tw, 34, 10); ctx.fill();
  ctx.strokeStyle = '#60a5fa'; ctx.lineWidth = 2;
  ctx.shadowColor = '#3b82f6'; ctx.shadowBlur = 16;
  rr(tx, ty, tw, 34, 10); ctx.stroke(); ctx.shadowBlur = 0;
  ctx.fillStyle = '#93c5fd';
  ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
  ctx.fillText(txt, W/2, ty + 17);
  ctx.restore();
}

/* Draw 4 flowing chevron arrows in a given direction */
function _drawChevrons(cx, cy, dir, col){
  const COUNT=4, SP=36, SZ=26, LW=5.5;
  ctx.save();
  ctx.lineCap='round'; ctx.lineJoin='round';
  for(let i=0;i<COUNT;i++){
    const phase=((frameCount*0.055)+i*(1/COUNT))%1.0;
    const alpha=0.25+phase*0.75;
    const scale=0.60+phase*0.40;
    const armH=SZ*scale, armW=SZ*0.62*scale;
    let ax,ay;
    if(dir==='right'){ ax=(cx-(COUNT-1)*SP*0.5)+i*SP; ay=cy; }
    else if(dir==='left'){ ax=(cx+(COUNT-1)*SP*0.5)-i*SP; ay=cy; }
    else { ax=cx; ay=(cy+(COUNT-1)*SP*0.5)-i*SP; }
    ctx.save();
    ctx.globalAlpha=alpha;
    ctx.strokeStyle=col; ctx.lineWidth=LW*(0.65+scale*0.35);
    ctx.shadowColor=col; ctx.shadowBlur=18+14*phase;
    ctx.beginPath();
    if(dir==='right'){ ctx.moveTo(ax-armW,ay-armH); ctx.lineTo(ax+armW,ay); ctx.lineTo(ax-armW,ay+armH); }
    else if(dir==='left'){ ctx.moveTo(ax+armW,ay-armH); ctx.lineTo(ax-armW,ay); ctx.lineTo(ax+armW,ay+armH); }
    else { ctx.moveTo(ax-armH,ay+armW); ctx.lineTo(ax,ay-armW); ctx.lineTo(ax+armH,ay+armW); }
    ctx.stroke();
    ctx.restore();
  }
  ctx.restore();
}

function drawTutorialPhase(){
  if(tutPhase<1||tutPhase>5) return;
  if(gst!==ST.PLAYING&&gst!==ST.RESPAWNING&&gst!==ST.CRASHING) return;

  const px = player.visualX, py = player.y - player.jumpOff;
  const pulse = 0.70 + Math.sin(frameCount * 0.12) * 0.30;
  const SHOW_Y = H * 0.22;   // hint threshold — object must be on screen

  ctx.save();

  /* ── Shared helpers ── */
  function _laneGlow(lanes, col){
    lanes.forEach(l=>{
      ctx.save();
      ctx.globalAlpha = 0.07 + Math.sin(frameCount*0.09)*0.03;
      ctx.fillStyle   = col;
      ctx.fillRect(LANE_XS[l]-35, 0, 70, H);
      ctx.restore();
    });
  }
  function _dangerRing(lane, y){
    const rx = LANE_XS[lane];
    ctx.save(); ctx.globalAlpha = Math.min(1, pulse*0.85);
    ctx.strokeStyle='#ef4444'; ctx.lineWidth=4;
    ctx.shadowColor='#ef4444'; ctx.shadowBlur=16;
    ctx.beginPath(); ctx.arc(rx, y, 38, 0, Math.PI*2); ctx.stroke();
    ctx.restore();
  }
  function _topBanner(txt, col, borderCol){
    const BANNER_CY = H * 0.25, BANNER_H = 38;
    const BANNER_Y  = BANNER_CY - BANNER_H/2;
    ctx.font = "900 17px 'Orbitron',impact,sans-serif";
    const tw = ctx.measureText(txt).width + 40;
    const bx = clamp(W/2 - tw/2, 6, W - tw - 6);
    ctx.save();
    ctx.globalAlpha = 0.96;
    ctx.fillStyle = 'rgba(4,6,18,0.94)';
    rr(bx, BANNER_Y, tw, BANNER_H, 8); ctx.fill();
    ctx.strokeStyle = borderCol; ctx.lineWidth = 2;
    ctx.shadowColor = borderCol; ctx.shadowBlur = 14;
    rr(bx, BANNER_Y, tw, BANNER_H, 8); ctx.stroke(); ctx.shadowBlur=0;
    ctx.fillStyle = col; ctx.shadowColor = col; ctx.shadowBlur = 10;
    ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
    ctx.fillText(txt, W/2, BANNER_CY);
    ctx.shadowBlur = 0;
    ctx.restore();
  }

  // Shared crash popup — shown during crash animation (ST.CRASHING) and briefly after
  function _crashPopup(){
    if(tutCrashPopTimer <= 0 || !tutCrashPopText) return;
    const _ca = clamp(tutCrashPopTimer / 15, 0, 1);
    ctx.save(); ctx.globalAlpha = _ca;
    ctx.font = "900 15px 'Orbitron',sans-serif";
    const _tw = ctx.measureText(tutCrashPopText).width + 28;
    const _tx = (W - _tw) / 2;
    // Position popup near crash site — float above car
    const _ty = py - 80;
    ctx.fillStyle = 'rgba(30,0,0,0.92)';
    rr(_tx, _ty, _tw, 30, 8); ctx.fill();
    ctx.strokeStyle = '#ef4444'; ctx.lineWidth = 2;
    ctx.shadowColor = '#ef4444'; ctx.shadowBlur = 14;
    rr(_tx, _ty, _tw, 30, 8); ctx.stroke(); ctx.shadowBlur = 0;
    ctx.fillStyle = '#fca5a5';
    ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
    ctx.fillText(tutCrashPopText, W/2, _ty + 15);
    ctx.restore();
  }

  const _isCrashing = gst === ST.CRASHING;

  // ════════════════════════════════════════════════════════════
  //  PHASE 1 — Enemy cars in lanes 0+1 + 2 coins in lane 2
  //  Double-chevron RIGHT arrow, upper screen, fades in/out with drift.
  //  Crashes trigger real crash anim, then rewind.
  // ════════════════════════════════════════════════════════════
  if(tutPhase === 1){
    const _e1Vis = tutEnemyRef        && tutEnemyRef._active        && tutEnemyRef.y        >= SHOW_Y;
    const _e0Vis = tutPhase1EnemyRef2 && tutPhase1EnemyRef2._active && tutPhase1EnemyRef2.y >= SHOW_Y;
    if(!_isCrashing){
      if(_e1Vis || _e0Vis){
        // Highlight safe lanes 0+1 only once enemies are visible
        _laneGlow([2,3], '#00e676');
        if(_e1Vis) _dangerRing(tutEnemyRef.lane, tutEnemyRef.y);
        if(_e0Vis) _dangerRing(tutPhase1EnemyRef2.lane, tutPhase1EnemyRef2.y);
        _drawBigScreenArrow('right');
      }
    }
    _crashPopup();
  }

  // ════════════════════════════════════════════════════════════
  //  PHASE 2 — enemy l3 (y=-400), enemy l2 (y=-430),
  //             manhole l0 + stone l1 (y=-460) + 2 lane-1 guide coins.
  //  Double-chevron LEFT when in wrong lane, no text.
  //  Up arrow + "Swipe ↑ to jump" when in correct lane.
  //  Crash (incl. jumping over cars) → real crash anim → rewind.
  // ════════════════════════════════════════════════════════════
  else if(tutPhase === 2){
    const _e2Vis = tutJumpEnemyRef1 && tutJumpEnemyRef1._active && tutJumpEnemyRef1.y >= SHOW_Y;
    const _e3Vis = tutJumpEnemyRef2 && tutJumpEnemyRef2._active && tutJumpEnemyRef2.y >= SHOW_Y;
    const _oVis  = (tutObstRef      && tutObstRef._active      && tutObstRef.y      >= SHOW_Y) ||
                   (tutJumpObstRef2  && tutJumpObstRef2._active  && tutJumpObstRef2.y  >= SHOW_Y);

    if(!_isCrashing){
      if(player.lane >= 2){
        // Show glow + chevrons only once enemies appear at top
        if(_e2Vis || _e3Vis){
          _laneGlow([0,1], '#00e676');
          if(_e2Vis) _dangerRing(tutJumpEnemyRef1.lane, tutJumpEnemyRef1.y);
          if(_e3Vis) _dangerRing(tutJumpEnemyRef2.lane, tutJumpEnemyRef2.y);
          _drawBigScreenArrow('left');
        }
      } else {
        if(_oVis){
          const _oRef = player.lane===1 ? tutObstRef : tutJumpObstRef2;
          if(_oRef && _oRef._active && _oRef.y >= SHOW_Y){
            _drawUpArrowOnObst(_oRef);
            _topBanner('Swipe ↑ to jump', '#bbf7d0', '#4ade80');
          }
        }
      }
    }
    _crashPopup();
  }

  // ════════════════════════════════════════════════════════════
  //  PHASE 3 — Coins A + Gun pickup + Shoot pre-spawned enemy
  //  Pre-gun: big arrows at 40% opacity when player in wrong lane.
  //  Post-gun: angled fire-button arrow + white glowing button border.
  // ════════════════════════════════════════════════════════════
  else if(tutPhase === 3){
    if(!tutP3GunUsed){
      // Guide player to gun pickup lane
      if(tutGunPickupRef && tutGunPickupRef._active && tutGunPickupRef.y >= H*0.10){
        const gx = LANE_XS[tutGunLane], gy = tutGunPickupRef.y;
        ctx.save(); ctx.globalAlpha = 0.10 + Math.sin(frameCount*0.10)*0.04;
        ctx.fillStyle = '#ffe060'; ctx.fillRect(gx-35, 0, 70, H); ctx.restore();
        ctx.save(); ctx.globalAlpha = pulse*0.90;
        ctx.strokeStyle='#ffe060'; ctx.lineWidth=5;
        ctx.shadowColor='#ffe060'; ctx.shadowBlur=22;
        ctx.beginPath(); ctx.arc(gx, gy, 32, 0, Math.PI*2); ctx.stroke();
        ctx.shadowBlur=0; ctx.restore();
        if(player.lane !== tutGunLane){
          ctx.save(); ctx.globalAlpha = 0.40;
          _drawBigScreenArrow(tutGunLane > player.lane ? 'right' : 'left');
          ctx.restore();
        }
      }
    } else {
      // Gun collected — danger rings on remaining cars A, B, C
      const _cAy = tutShootEnemyRef && tutShootEnemyRef._active && tutShootEnemyRef.y >= SHOW_Y;
      const _cBy = tutP3CarBRef    && tutP3CarBRef._active    && tutP3CarBRef.y    >= SHOW_Y;
      const _cCy = tutP3CarCRef    && tutP3CarCRef._active    && tutP3CarCRef.y    >= SHOW_Y;
      if(_cAy) _dangerRing(tutShootEnemyRef.lane, tutShootEnemyRef.y);
      if(_cBy) _dangerRing(tutP3CarBRef.lane,    tutP3CarBRef.y);
      if(_cCy) _dangerRing(tutP3CarCRef.lane,    tutP3CarCRef.y);

      // Banner when car A is in firing range
      if(_cAy && tutShootEnemyRef && Math.abs(tutShootEnemyRef.y - py) < 320){
        const BANNER_CY2 = H*0.25, BANNER_H2 = 38, BANNER_Y2 = BANNER_CY2 - BANNER_H2/2;
        ctx.save(); ctx.globalAlpha = 0.96;
        ctx.fillStyle='rgba(4,6,18,0.94)';
        const _stxt='Tap launch button!';
        ctx.font="900 16px 'Orbitron',impact,sans-serif";
        const _stw2=ctx.measureText(_stxt).width+40,_sbx2=W/2-_stw2/2;
        rr(_sbx2,BANNER_Y2,_stw2,BANNER_H2,8); ctx.fill();
        ctx.strokeStyle='#ef4444'; ctx.lineWidth=2;
        ctx.shadowColor='#ef4444'; ctx.shadowBlur=14;
        rr(_sbx2,BANNER_Y2,_stw2,BANNER_H2,8); ctx.stroke(); ctx.shadowBlur=0;
        ctx.fillStyle='#fca5a5'; ctx.textAlign='center'; ctx.textBaseline='middle';
        ctx.fillText(_stxt,W/2,BANNER_CY2);
        ctx.restore();
      }
      // Angled arrow + white fire button glow (active while tutGunArrowTimer > 0 and after 0.6s delay)
      if(tutGunArrowTimer > 0 && tutGunArrowTimer < (720-36)){
        _drawFireButtonArrow();
        const _blink3 = 0.55 + 0.45*Math.abs(Math.sin(frameCount*0.06));
        ctx.save(); ctx.globalAlpha = _blink3;
        ctx.strokeStyle='#ffffff'; ctx.lineWidth=4;
        ctx.shadowColor='#ffffff'; ctx.shadowBlur=28;
        rr(W-62,H-122,54,112,14); ctx.stroke();
        ctx.shadowBlur=0; ctx.restore();
      }
    }
  }

  // ════════════════════════════════════════════════════════════
  //  PHASE 4 — Coins B + Nitro pickup + TAP BUTTON + Smash
  //  Pre-nitro: guide player toward nitro lane.
  //  Arrow mode: nitro stored, show blinking button arrow.
  //  Smash mode: show progress banner, no L/R movement allowed.
  // ════════════════════════════════════════════════════════════
  else if(tutPhase === 4){
    // ── State A: Waiting for player to tap the nitro button ──
    if(tutNitroArrowActive){
      _topBanner('TAP THE NITRO BUTTON!', '#fef3c7', '#f59e0b');
      // Green angled arrow pointing toward the nitro button — exact mirror of gun tutorial
      _drawNitroButtonArrow();
      // Blinking amber glow border around the nitro button — mirrors white gun button glow
      const _blink4 = 0.55 + 0.45*Math.abs(Math.sin(frameCount*0.06));
      ctx.save(); ctx.globalAlpha = _blink4;
      ctx.strokeStyle='#f59e0b'; ctx.lineWidth=4;
      ctx.shadowColor='#fbbf24'; ctx.shadowBlur=28;
      rr(4,H-122,54,112,14); ctx.stroke();
      ctx.shadowBlur=0; ctx.restore();

    } else if(!tutNitroMoveLocked){
      // ── State B: Guide to nitro pickup ──
      if(tutNitroPickupRef && tutNitroPickupRef._active && tutNitroPickupRef.y >= H*0.10){
        const nx = LANE_XS[tutNitroObstLane1], ny = tutNitroPickupRef.y;
        ctx.save(); ctx.globalAlpha = 0.55 + fastSin(frameCount*0.18)*0.30;
        ctx.strokeStyle='#f59e0b'; ctx.lineWidth=3.5;
        ctx.shadowColor='#f59e0b'; ctx.shadowBlur=18;
        ctx.beginPath(); ctx.arc(nx, ny, 28, 0, Math.PI*2); ctx.stroke();
        ctx.shadowBlur=0; ctx.restore();
        if(player.lane !== tutNitroObstLane1){
          const _goR4 = tutNitroObstLane1 > player.lane;
          _drawChevrons(clamp(_goR4?px+110:px-110,80,W-80), py-70, _goR4?'right':'left', '#f59e0b');
          _topBanner(_goR4?'MOVE RIGHT — GET NITRO ▶':'◀ MOVE LEFT — GET NITRO', '#fef3c7', '#f59e0b');
        } else {
          _topBanner('STAY — NITRO INCOMING ⚡', '#fef3c7', '#f59e0b');
        }
      }
    } else {
      // ── State C: Nitro smash mode — show progress banners ──
      const _o1Smashed = !tutNitroObst1Ref || tutNitroObst1Ref._tutSmashed;
      const _o2Smashed = !tutNitroObst2Ref || tutNitroObst2Ref._tutSmashed;
      const _o3Smashed = !tutNitroObst3Ref || tutNitroObst3Ref._tutSmashed;

      if(!_o3Smashed){
        ctx.save();
        ctx.font = "700 11px 'Orbitron',sans-serif";
        const _smTxt = '⚡ Smash mode on!';
        const _smW = ctx.measureText(_smTxt).width + 20;
        const _smH = 24;
        const _smX = clamp(px + 20, ROAD_L + 4, ROAD_R - _smW - 4);
        const _smY = clamp(py - 60 - _smH, 72, py - 38 - _smH);
        ctx.globalAlpha = 0.94;
        ctx.fillStyle = 'rgba(4,6,18,0.88)';
        rr(_smX, _smY, _smW, _smH, 6); ctx.fill();
        ctx.strokeStyle = '#f59e0b'; ctx.lineWidth = 1.5;
        ctx.shadowColor = '#fbbf24'; ctx.shadowBlur = 10;
        rr(_smX, _smY, _smW, _smH, 6); ctx.stroke(); ctx.shadowBlur = 0;
        ctx.fillStyle = '#fef3c7';
        ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
        ctx.fillText(_smTxt, _smX + _smW/2, _smY + _smH/2);
        ctx.restore();
      }

      if(!_o1Smashed){
        _topBanner('💥 SMASH IT!', '#fef3c7', '#f59e0b');
      } else if(!_o2Smashed){
        if(tutNitroObst2Ref&&tutNitroObst2Ref._active&&tutNitroObst2Ref.y>SHOW_Y){
          ctx.save(); ctx.globalAlpha=0.70+fastSin(frameCount*0.25)*0.30;
          ctx.strokeStyle='#ef4444'; ctx.lineWidth=4.5;
          ctx.shadowColor='#ef4444'; ctx.shadowBlur=22;
          ctx.beginPath(); ctx.arc(LANE_XS[tutNitroObstLane2],tutNitroObst2Ref.y,36,0,Math.PI*2); ctx.stroke();
          ctx.shadowBlur=0; ctx.restore();
        }
        _topBanner('💥 DOUBLE DOWN!', '#fed7aa', '#fb923c');
      } else if(!_o3Smashed){
        _topBanner('🏆 LEGENDARY — LAST ONE!', '#fca5a5', '#ef4444');
        const _urgP = 0.5 + fastSin(frameCount*0.30)*0.5;
        ctx.save(); ctx.globalAlpha=_urgP*0.75;
        ctx.fillStyle='#ef4444'; ctx.shadowColor='#ef4444'; ctx.shadowBlur=12;
        ctx.font="bold 18px 'Orbitron',sans-serif";
        ctx.textAlign='center'; ctx.textBaseline='middle';
        ctx.fillText('◀ FUEL!', W/2-65, H*0.72);
        ctx.shadowBlur=0; ctx.restore();
      }
    }
  }

  // ════════════════════════════════════════════════════════════
  //  PHASE 5 — Certified Driver! banner
  //  Fades in over 15f, holds, fades out. Green themed.
  // ════════════════════════════════════════════════════════════
  else if(tutPhase === 5){
    // 0–60 frames: coast at normal speed (no banner)
    // 60–180 frames: Certified Driver banner fades in, holds, fades out
    if(tutPhaseTimer >= 60){
      const _a5 = clamp((tutPhaseTimer-60)/15, 0, 1) * clamp((180-tutPhaseTimer)/12, 0, 1);
      if(_a5 > 0.01){
        ctx.save(); ctx.globalAlpha = _a5;
        const BW=300, BH=84, BX=(W-BW)/2, BY=(H-BH)/2-28;
        ctx.shadowColor='#00e676'; ctx.shadowBlur=44;
        ctx.fillStyle='rgba(0,230,118,0.12)';
        rr(BX-12, BY-12, BW+24, BH+24, 22); ctx.fill(); ctx.shadowBlur=0;
        ctx.fillStyle='rgba(2,8,20,0.96)';
        rr(BX, BY, BW, BH, 18); ctx.fill();
        ctx.strokeStyle='#00e676'; ctx.lineWidth=3;
        ctx.shadowColor='#00e676'; ctx.shadowBlur=30;
        rr(BX, BY, BW, BH, 18); ctx.stroke(); ctx.shadowBlur=0;
        ctx.textAlign='center'; ctx.textBaseline='middle';
        ctx.font = "900 21px 'Orbitron',impact,sans-serif";
        ctx.fillStyle='#00e676'; ctx.shadowColor='#00e676'; ctx.shadowBlur=20;
        ctx.fillText('CERTIFIED DRIVER 🏅', W/2, BY + BH*0.38); ctx.shadowBlur=0;
        ctx.font = "600 12px 'Rajdhani',sans-serif";
        ctx.fillStyle = '#86efac';
        ctx.fillText('Stage 1 begins!', W/2, BY + BH*0.70);
        ctx.restore();
      }
    }
  }

  ctx.restore();
}



/* ── Canvas heart shape helper for the extra-life animation ── */
function _drawAnimHeart(ctx,cx,cy,r,alpha){
  ctx.save();
  ctx.globalAlpha=alpha;
  ctx.beginPath();
  // Heart parametric curve — same shape as in lbox-canvas
  ctx.moveTo(cx,cy+r*0.90);
  ctx.bezierCurveTo(cx-r*0.05,cy+r*0.60,cx-r,cy+r*0.10,cx-r,cy-r*0.15);
  ctx.bezierCurveTo(cx-r,cy-r*0.70,cx-r*0.50,cy-r*0.95,cx,cy-r*0.42);
  ctx.bezierCurveTo(cx+r*0.50,cy-r*0.95,cx+r,cy-r*0.70,cx+r,cy-r*0.15);
  ctx.bezierCurveTo(cx+r,cy+r*0.10,cx+r*0.05,cy+r*0.60,cx,cy+r*0.90);
  ctx.closePath();

  // Outer glow pass
  ctx.save();
  ctx.shadowColor='#ec4899';ctx.shadowBlur=22;
  ctx.fillStyle='#cc0033';ctx.fill();
  ctx.restore();

  // Radial gradient fill — glossy red
  const gr=ctx.createRadialGradient(cx-r*0.22,cy-r*0.18,0,cx,cy,r*1.1);
  gr.addColorStop(0,'#ff6688');
  gr.addColorStop(0.38,'#e00030');
  gr.addColorStop(0.80,'#9a0020');
  gr.addColorStop(1,'#5a0012');
  ctx.fillStyle=gr;ctx.fill();

  // Gloss highlight — top-left oval
  ctx.save();ctx.globalAlpha=alpha*0.55;
  const gl=ctx.createRadialGradient(cx-r*0.25,cy-r*0.28,0,cx-r*0.10,cy-r*0.10,r*0.55);
  gl.addColorStop(0,'rgba(255,255,255,0.90)');gl.addColorStop(1,'rgba(255,255,255,0)');
  ctx.fillStyle=gl;
  ctx.beginPath();
  ctx.ellipse(cx-r*0.22,cy-r*0.20,r*0.38,r*0.22,-0.35,0,Math.PI*2);
  ctx.fill();ctx.restore();

  ctx.restore();
}

