const EXIT_CONFIRM_YES={x:(W-300)/2+20,  y:(H-210)/2-20+110, w:110, h:34};
const EXIT_CONFIRM_NO ={x:(W-300)/2+170, y:(H-210)/2-20+110, w:110, h:34};
function drawGlassPanel(x,y,w,h,r,borderCol){
  // Frosted glass backdrop
  ctx.save();
  ctx.fillStyle='rgba(7,9,20,0.88)';rr(x,y,w,h,r);ctx.fill();
  // Subtle inner gradient
  const iGrad=ctx.createLinearGradient(x,y,x,y+h);
  iGrad.addColorStop(0,'rgba(255,255,255,0.04)');iGrad.addColorStop(0.5,'rgba(255,255,255,0.01)');iGrad.addColorStop(1,'rgba(0,0,0,0.06)');
  ctx.fillStyle=iGrad;rr(x,y,w,h,r);ctx.fill();
  // Glowing border
  ctx.shadowColor=borderCol;ctx.shadowBlur=16;
  ctx.strokeStyle=borderCol;ctx.lineWidth=1.5;rr(x,y,w,h,r);ctx.stroke();
  // Top edge highlight
  ctx.shadowBlur=0;ctx.globalAlpha=0.15;ctx.strokeStyle='#fff';ctx.lineWidth=0.8;
  rr(x+1,y+1,w-2,h-2,r-1);ctx.stroke();
  ctx.restore();
}

function drawPanel(title,titleCol,rows,footer1,footer2){
  const PW=308,PH=46+rows.length*23+(footer2?108:88);
  const PX=(W-PW)/2,PY=(H-PH)/2-20;
  ctx.fillStyle='rgba(0,0,0,0.70)';ctx.fillRect(0,0,W,H);
  drawGlassPanel(PX,PY,PW,PH,16,titleCol);
  ctx.textAlign='center';
  ctx.font="900 24px 'Orbitron',impact,sans-serif";ctx.fillStyle=titleCol;
  ctx.shadowColor=titleCol;ctx.shadowBlur=12;
  ctx.fillText(title,W/2,PY+46);ctx.shadowBlur=0;
  rows.forEach(([k,v,kc,vc],i)=>{
    const ry=PY+82+i*23;if(!k)return;
    ctx.font="600 10px 'Rajdhani',sans-serif";
    ctx.fillStyle=kc||'#fbbf24';ctx.textAlign='right';ctx.fillText(k,W/2-5,ry);
    ctx.fillStyle=vc||'#cbd5e1';ctx.textAlign='left';ctx.fillText(v,W/2+5,ry);
  });
  const fy=PY+PH-(footer2?58:36);
  if(footer2){
    ctx.font="600 9px 'Rajdhani',sans-serif";ctx.fillStyle='#64748b';ctx.textAlign='center';
    ctx.fillText(footer1,W/2,fy);ctx.fillText(footer2,W/2,fy+16);
    ctx.font="bold 11px 'Orbitron',sans-serif";ctx.fillStyle='#fbbf24';
    ctx.fillText('SPACE  or  TAP  to continue',W/2,fy+40);
  } else {
    ctx.font="bold 11px 'Orbitron',sans-serif";ctx.fillStyle='#fbbf24';ctx.textAlign='center';ctx.fillText(footer1,W/2,fy);
  }
  ctx.textAlign='left';
}

