/* ══════════════════════════════════════════════
   DRAW — ENGINE START SCREEN
   Shown on first load — user must tap the
   physical-style push button to unlock the
   AudioContext, then the splash animation plays
   in full with perfect audio sync.
══════════════════════════════════════════════ */
function drawEngineStart(){
  // ── Dark starfield sky — cached gradient ──
  if(!GC.engSky){
    const sky=ctx.createLinearGradient(0,0,0,H*0.52);
    sky.addColorStop(0,'#040609');sky.addColorStop(1,'#0a0d1e');
    GC.engSky=sky;
  }
  ctx.fillStyle=GC.engSky;ctx.fillRect(0,0,W,H);

  // Twinkling stars
  for(let i=0;i<32;i++){
    const sx=(i*137.5)%W,sy=(i*83.3)%(H*0.36);
    const sr=0.5+((i*31)%3)*0.5;
    const tw=fastSin(frameCount*0.07+(i*0.9))*0.3+0.7;
    ctx.save();ctx.globalAlpha=tw*0.6;
    ctx.fillStyle='#e8eeff';ctx.beginPath();ctx.arc(sx,sy,sr,0,Math.PI*2);ctx.fill();ctx.restore();
  }

  // City skyline silhouette
  const HY=H*0.40;
  ctx.save();ctx.globalAlpha=0.5;
  [[0,52,24],[26,38,18],[46,62,20],[68,44,16],[86,56,22],
   [260,48,26],[288,64,18],[308,50,20],[330,42,16],[348,60,24],[374,46,18]]
  .forEach(([x,h,w])=>{
    ctx.fillStyle='#0d1122';ctx.fillRect(x,HY-h,w,h);
    ctx.fillStyle='rgba(255,240,140,0.20)';
    for(let r2=0;r2<Math.floor(h/10);r2++)for(let c2=0;c2<Math.floor(w/7);c2++)
      if((r2*13+c2*7)%5>1)ctx.fillRect(x+c2*7+2,HY-h+r2*10+3,3,5);
  });
  ctx.restore();

  // Ground fill
  ctx.fillStyle='#10131c';ctx.fillRect(0,HY,W,H-HY);

  // Road perspective trapezoid — cached gradient
  const RL2=70,RR2=330,horizHW2=22;
  const horizL2=W/2-horizHW2,horizR2=W/2+horizHW2;
  if(!GC.engRoad){
    const roadG2=ctx.createLinearGradient(RL2,0,RR2,0);
    roadG2.addColorStop(0,'#1a1e2e');roadG2.addColorStop(0.5,'#242a3a');roadG2.addColorStop(1,'#1a1e2e');
    GC.engRoad=roadG2;
  }
  ctx.fillStyle=GC.engRoad;
  ctx.beginPath();
  ctx.moveTo(horizL2,HY);ctx.lineTo(horizR2,HY);
  ctx.lineTo(RR2,H);ctx.lineTo(RL2,H);ctx.closePath();ctx.fill();
  // Road edge lines
  ctx.save();ctx.shadowColor='rgba(245,158,11,0.45)';ctx.shadowBlur=8;
  ctx.strokeStyle='#f59e0b';ctx.lineWidth=2.5;
  ctx.beginPath();ctx.moveTo(horizL2,HY);ctx.lineTo(RL2,H);ctx.stroke();
  ctx.beginPath();ctx.moveTo(horizR2,HY);ctx.lineTo(RR2,H);ctx.stroke();
  ctx.restore();

  // ── TITLE — Lane Havoc logo ──
  ctx.save();
  if(window._LANE_HAVOC_LOGO&&window._LANE_HAVOC_LOGO.complete&&window._LANE_HAVOC_LOGO.naturalWidth>0){
    ctx.drawImage(window._LANE_HAVOC_LOGO,W/2-160,H*0.08,320,160);
  }
  ctx.restore();

  // ── ENGINE START BUTTON ──
  const btnCX=W/2, btnCY=H*0.625;
  const pulse=fastSin(frameCount*0.050)*0.5+0.5; // 0..1 breathing cycle
  const btnR=68; // outer radius of entire button assembly
  const faceR=btnR-25;

  // Build all static button gradients once and cache them
  if(!GC.engHalo){
    GC.engHalo=ctx.createRadialGradient(btnCX,btnCY,btnR*0.5,btnCX,btnCY,btnR*1.35);
    GC.engHalo.addColorStop(0,'rgba(200,200,220,0.9)');GC.engHalo.addColorStop(1,'rgba(0,0,0,0)');

    const chromOuter=ctx.createLinearGradient(btnCX-btnR,btnCY-btnR,btnCX+btnR,btnCY+btnR);
    chromOuter.addColorStop(0.00,'#3a3a3a');chromOuter.addColorStop(0.12,'#9a9a9a');
    chromOuter.addColorStop(0.28,'#e8e8e8');chromOuter.addColorStop(0.45,'#b0b0b0');
    chromOuter.addColorStop(0.60,'#505050');chromOuter.addColorStop(0.78,'#d4d4d4');
    chromOuter.addColorStop(0.90,'#f0f0f0');chromOuter.addColorStop(1.00,'#444444');
    GC.engChromOuter=chromOuter;

    const chromInner=ctx.createLinearGradient(btnCX-(btnR-20),btnCY-(btnR-20),btnCX+(btnR-20),btnCY+(btnR-20));
    chromInner.addColorStop(0.00,'#2a2a2a');chromInner.addColorStop(0.15,'#888');
    chromInner.addColorStop(0.35,'#d8d8d8');chromInner.addColorStop(0.55,'#909090');
    chromInner.addColorStop(0.72,'#404040');chromInner.addColorStop(0.88,'#c8c8c8');
    chromInner.addColorStop(1.00,'#3a3a3a');
    GC.engChromInner=chromInner;

    const faceG=ctx.createRadialGradient(btnCX-faceR*0.28,btnCY-faceR*0.32,faceR*0.04,btnCX,btnCY,faceR);
    faceG.addColorStop(0.00,'#3c3c44');faceG.addColorStop(0.22,'#1a1a22');
    faceG.addColorStop(0.55,'#0d0d14');faceG.addColorStop(1.00,'#050508');
    GC.engFace=faceG;

    const indX2=btnCX-26, indY2=btnCY-faceR+11, indH2=13;
    const indG=ctx.createLinearGradient(indX2,indY2,indX2,indY2+indH2);
    indG.addColorStop(0,'#ffb040');indG.addColorStop(0.35,'#ff8000');
    indG.addColorStop(0.70,'#cc5500');indG.addColorStop(1,'#aa3800');
    GC.engIndG=indG;

    const indHL=ctx.createLinearGradient(indX2,indY2,indX2,indY2+indH2*0.55);
    indHL.addColorStop(0,'rgba(255,230,180,0.85)');indHL.addColorStop(1,'rgba(255,180,80,0)');
    GC.engIndHL=indHL;

    const glossG=ctx.createRadialGradient(btnCX-faceR*0.40,btnCY-faceR*0.46,0,btnCX-faceR*0.10,btnCY-faceR*0.15,faceR*0.82);
    glossG.addColorStop(0,'rgba(255,255,255,1)');glossG.addColorStop(0.45,'rgba(255,255,255,0.35)');
    glossG.addColorStop(1,'rgba(255,255,255,0)');
    GC.engGloss=glossG;

    const depthG=ctx.createRadialGradient(btnCX+faceR*0.30,btnCY+faceR*0.38,0,btnCX+faceR*0.10,btnCY+faceR*0.14,faceR*0.90);
    depthG.addColorStop(0,'rgba(255,255,255,0.18)');depthG.addColorStop(1,'rgba(255,255,255,0)');
    GC.engDepth=depthG;
  }

  // ── Outermost ambient glow halo ──
  ctx.save();ctx.globalAlpha=0.08+pulse*0.12;
  ctx.fillStyle=GC.engHalo;
  ctx.beginPath();ctx.arc(btnCX,btnCY,btnR*1.35,0,Math.PI*2);ctx.fill();
  ctx.restore();

  // ── LAYER 1: Outermost chrome ring ──
  ctx.save();
  ctx.strokeStyle=GC.engChromOuter;ctx.lineWidth=10;
  ctx.beginPath();ctx.arc(btnCX,btnCY,btnR-5,0,Math.PI*2);ctx.stroke();
  ctx.restore();

  // ── LAYER 2: Dark gap ring ──
  ctx.save();
  ctx.strokeStyle='rgba(20,20,30,0.95)';ctx.lineWidth=4;
  ctx.beginPath();ctx.arc(btnCX,btnCY,btnR-16,0,Math.PI*2);ctx.stroke();
  ctx.restore();

  // ── LAYER 3: Inner chrome bezel ring ──
  ctx.save();
  ctx.strokeStyle=GC.engChromInner;ctx.lineWidth=6.5;
  ctx.shadowColor='rgba(180,180,180,0.30)';ctx.shadowBlur=4;
  ctx.beginPath();ctx.arc(btnCX,btnCY,btnR-20,0,Math.PI*2);ctx.stroke();
  ctx.restore();

  // ── LAYER 4: Black glossy button face ──
  ctx.save();
  ctx.fillStyle=GC.engFace;
  ctx.shadowColor=`rgba(80,80,120,${0.15+pulse*0.10})`;ctx.shadowBlur=8+pulse*8;
  ctx.beginPath();ctx.arc(btnCX,btnCY,faceR,0,Math.PI*2);ctx.fill();
  ctx.restore();

  // ── ORANGE INDICATOR PILL ──
  const indW=52, indH=13, indX=btnCX-indW/2, indY=btnCY-faceR+11;
  ctx.save();
  ctx.shadowColor=`rgba(255,120,0,${0.50+pulse*0.45})`;ctx.shadowBlur=10+pulse*10;
  ctx.fillStyle=GC.engIndG;
  rr(indX,indY,indW,indH,indH/2);ctx.fill();
  ctx.globalAlpha=0.42;
  ctx.fillStyle=GC.engIndHL;
  rr(indX+3,indY+2,indW-6,indH*0.48,indH/2-2);ctx.fill();
  ctx.restore();

  // ── "START ENGINE" text ──
  const textCY=btnCY+4;
  ctx.save();ctx.textAlign='center';ctx.textBaseline='middle';
  ctx.font="900 17px 'Orbitron',impact,sans-serif";
  ctx.fillStyle='rgba(255,255,255,0.95)';
  ctx.shadowColor='rgba(255,255,255,0.25)';ctx.shadowBlur=4;
  ctx.fillText('START',btnCX,textCY-10);
  ctx.fillText('ENGINE',btnCX,textCY+12);
  ctx.restore();

  // ── Top-left dome gloss reflection ──
  ctx.save();ctx.globalAlpha=0.13;
  ctx.fillStyle=GC.engGloss;
  ctx.beginPath();ctx.arc(btnCX,btnCY,faceR,0,Math.PI*2);ctx.fill();
  ctx.restore();

  // ── Bottom-right depth shading ──
  ctx.save();ctx.globalAlpha=0.30;
  ctx.fillStyle=GC.engDepth;
  ctx.beginPath();ctx.arc(btnCX,btnCY,faceR,0,Math.PI*2);ctx.fill();
  ctx.restore();

  // ── "PRESS TO START" instruction ──
  ctx.save();
  ctx.globalAlpha=0.65+pulse*0.30;
  ctx.textAlign='center';ctx.textBaseline='middle';
  ctx.font="bold 13px 'Orbitron',sans-serif";
  ctx.fillStyle='#e8eeff';
  ctx.shadowColor='rgba(180,200,255,0.55)';ctx.shadowBlur=8;
  ctx.fillText('PRESS TO START',btnCX,btnCY+btnR+18);
  ctx.restore();

  ctx.save();
  ctx.globalAlpha=0.55+pulse*0.18;
  ctx.textAlign='center';ctx.textBaseline='middle';
  ctx.font="600 11px 'Rajdhani',sans-serif";
  ctx.fillStyle='#94a3b8';
  ctx.fillText('tap the button to rev your engine',W/2,btnCY+btnR+38);
  ctx.restore();

  // Store circle bounds for tap detection
  _engineBtnRect={cx:btnCX,cy:btnCY,r:btnR};
}

/* ══════════════════════════════════════════════
   DRAW — SPLASH SCREEN  (3-lane road, traffic signal, launch)
   Timeline (144 frames @ 60fps = 2.4s):
   t  0-18  : fade in, car static at bottom center, signal RED
   t 18-82  : signal RED (pulsing glow), car waiting, tyre smoke idle
   t 82-94  : signal YELLOW
   t 94-106 : signal GREEN flash → car revs (shake)
   t106-144 : car LAUNCHES toward horizon (fast zoom)
══════════════════════════════════════════════ */
function drawSplash(){
  const t=splashTimer; // increments freely; capped for visuals at 144
  const tVis=Math.min(t,144); // visual timer — freezes at 144
  const fadeIn=clamp(t/18,0,1);
  const alpha=fadeIn; // no fadeOut — scene stays visible permanently

  // ── Sky — cached gradient ──
  if(!GC.splashSky){
    const sky=ctx.createLinearGradient(0,0,0,H*0.52);
    sky.addColorStop(0,'#040609');sky.addColorStop(1,'#0a0d1e');
    GC.splashSky=sky;
  }
  ctx.fillStyle=GC.splashSky;ctx.fillRect(0,0,W,H);

  // Stars
  for(let i=0;i<32;i++){
    const sx=(i*137.5)%W,sy=(i*83.3)%(H*0.36);
    const sr=0.5+((i*31)%3)*0.5;
    const tw=fastSin(tVis*0.07+(i*0.9))*0.3+0.7;
    ctx.save();ctx.globalAlpha=alpha*tw*0.6;
    ctx.fillStyle='#e8eeff';ctx.beginPath();ctx.arc(sx,sy,sr,0,Math.PI*2);ctx.fill();ctx.restore();
  }

  // City skyline silhouette
  const HY=H*0.40;
  ctx.save();ctx.globalAlpha=alpha*0.5;ctx.fillStyle='#0d1122';
  [[0,52,24],[26,38,18],[46,62,20],[68,44,16],[86,56,22],
   [260,48,26],[288,64,18],[308,50,20],[330,42,16],[348,60,24],[374,46,18]]
  .forEach(([x,h,w])=>{
    ctx.fillStyle='#0d1122';ctx.fillRect(x,HY-h,w,h);
    ctx.fillStyle='rgba(255,240,140,0.20)';
    for(let r2=0;r2<Math.floor(h/10);r2++)for(let c2=0;c2<Math.floor(w/7);c2++)
      if((r2*13+c2*7)%5>1)ctx.fillRect(x+c2*7+2,HY-h+r2*10+3,3,5);
  });
  ctx.restore();

  // ── Road surface — proper perspective trapezoid (never narrows to a point) ──
  const RL=70, RR=330, RW=RR-RL;
  // Horizon edge: road stays ~44 px wide at the vanishing line
  const horizHW=22; // half-width of road at horizon
  const horizL=W/2-horizHW, horizR=W/2+horizHW;
  // Helper: x position at arbitrary y for a given bottom-x (linear perspective interp)
  const perspX=(bx,y)=>{
    const htx=W/2+(bx-W/2)*(horizHW/(RW/2));
    const prog=clamp((y-HY)/(H-HY),0,1);
    return htx+(bx-htx)*prog;
  };

  // Ground fill (sides)
  ctx.fillStyle='#10131c';
  ctx.fillRect(0,HY,W,H-HY);

  // Road trapezoid fill — cached gradient
  if(!GC.splashRoad){
    const roadG=ctx.createLinearGradient(RL,0,RR,0);
    roadG.addColorStop(0,'#1a1e2e');roadG.addColorStop(0.5,'#242a3a');roadG.addColorStop(1,'#1a1e2e');
    GC.splashRoad=roadG;
  }
  ctx.fillStyle=GC.splashRoad;
  ctx.beginPath();
  ctx.moveTo(horizL,HY);ctx.lineTo(horizR,HY);
  ctx.lineTo(RR,H);ctx.lineTo(RL,H);
  ctx.closePath();ctx.fill();

  // Road scroll offset — only accumulates once the car launches (t >= 106)
  // Before launch the car is stationary, so the road must appear still too.
  const roadScroll=Math.max(0, tVis-106)*3.5;

  // Idle menu scroll — road keeps moving at ~30% speed after car reaches horizon
  // Uses real timer (t), not capped tVis, so it keeps accumulating during menu
  const menuIdleScroll = t >= 144 ? (t - 144) * 1.1 : 0;
  const totalScroll = roadScroll + menuIdleScroll;

  // Kerb stripes — follow the perspective edges
  const strOff=totalScroll%18;
  for(let y=HY+strOff;y<H+18;y+=18){
    const ev=Math.floor(y/18)%2===0;
    ctx.fillStyle=ev?'#c0392b':'#ecf0f1';
    const lx=perspX(RL,Math.min(y,H-1));
    const rx=perspX(RR,Math.min(y,H-1));
    ctx.fillRect(lx-6,y,6,18);ctx.fillRect(rx,y,6,18);
  }

  // Amber road edge lines — along the trapezoid sides (static, no scroll needed)
  ctx.save();ctx.shadowColor='rgba(245,158,11,0.5)';ctx.shadowBlur=8;
  ctx.strokeStyle='#f59e0b';ctx.lineWidth=2.5;
  ctx.beginPath();ctx.moveTo(horizL,HY);ctx.lineTo(RL,H);ctx.stroke();
  ctx.beginPath();ctx.moveTo(horizR,HY);ctx.lineTo(RR,H);ctx.stroke();
  ctx.restore();

  // Perspective lane dividers — frozen while car waits, scroll during launch + idle in menu
  const laneDiv=[RL+RW/3, RL+2*RW/3];
  ctx.save();ctx.strokeStyle='rgba(255,255,255,0.50)';ctx.lineWidth=1.8;
  ctx.setLineDash([28,18]);ctx.lineDashOffset=-(totalScroll)%46;
  laneDiv.forEach(bx=>{
    const htx=W/2+(bx-W/2)*(horizHW/(RW/2));
    ctx.beginPath();ctx.moveTo(htx,HY);ctx.lineTo(bx,H);ctx.stroke();
  });
  ctx.setLineDash([]);ctx.restore();

  // ── TRAFFIC SIGNAL — left side, below title area ──
  let sigState='red';
  if(tVis>=106) sigState='go';
  else if(tVis>=94) sigState='green';
  else if(tVis>=82) sigState='yellow';

  const sigX=96, sigPostH=70, sigTopY=HY-sigPostH+8;
  const sigBoxW=22, sigBoxH=62, sigBoxX=sigX-sigBoxW/2, sigBoxY=sigTopY;
  const lightCY=[sigBoxY+12, sigBoxY+31, sigBoxY+50];

  // Dim signal to 30% once menu is shown — it's a background reminder, not the focus
  const sigMenuDim = t >= 144 ? clamp(1 - (t-144)/20, 0.28, 1) : 1;
  ctx.save();ctx.globalAlpha=alpha*sigMenuDim;
  ctx.fillStyle='#2a2f40';
  ctx.fillRect(sigX-2,sigTopY+sigBoxH,4,sigPostH-sigBoxH);
  ctx.fillStyle='#1a1e2a';rr(sigBoxX,sigBoxY,sigBoxW,sigBoxH,4);ctx.fill();
  ctx.strokeStyle='#3a3f55';ctx.lineWidth=1.2;rr(sigBoxX,sigBoxY,sigBoxW,sigBoxH,4);ctx.stroke();

  // Red light — stays dim once launched
  const redPulse=(sigState==='red')?(0.7+Math.sin(tVis*0.18)*0.3):0.15;
  ctx.save();
  if(sigState==='red'){ctx.shadowColor='#ff2222';ctx.shadowBlur=18*redPulse;}
  ctx.fillStyle=sigState==='red'?`rgba(255,${30+Math.floor(redPulse*20)},30,${0.7+redPulse*0.3})`:'rgba(80,20,20,0.9)';
  ctx.beginPath();ctx.arc(sigX,lightCY[0],7,0,Math.PI*2);ctx.fill();ctx.restore();

  // Yellow light
  ctx.save();
  if(sigState==='yellow'){ctx.shadowColor='#fbbf24';ctx.shadowBlur=16;}
  ctx.fillStyle=sigState==='yellow'?'#fbbf24':'rgba(60,50,15,0.9)';
  ctx.beginPath();ctx.arc(sigX,lightCY[1],7,0,Math.PI*2);ctx.fill();ctx.restore();

  // Green light — stays on after launch
  const grnOn=sigState==='green'||sigState==='go';
  const grnFlash=grnOn?(0.75+Math.sin((tVis-94)*0.35)*0.25):0;
  ctx.save();
  if(grnOn){ctx.shadowColor='#00e676';ctx.shadowBlur=grnOn&&sigState!=='go'?20*grnFlash:12;}
  ctx.fillStyle=grnOn?`rgba(0,${180+Math.floor(grnFlash*75)},${100+Math.floor(grnFlash*30)},${0.8+grnFlash*0.2})`:'rgba(10,40,20,0.9)';
  ctx.beginPath();ctx.arc(sigX,lightCY[2],7,0,Math.PI*2);ctx.fill();ctx.restore();
  ctx.restore();

  // ── Atmospheric horizon haze — cached gradient ──
  if(!GC.splashHaze){
    const hazeG=ctx.createLinearGradient(0,HY-8,0,HY+28);
    hazeG.addColorStop(0,'rgba(30,50,90,0)');
    hazeG.addColorStop(0.45,'rgba(40,60,110,0.38)');
    hazeG.addColorStop(1,'rgba(30,50,90,0)');
    GC.splashHaze=hazeG;
  }
  ctx.save();ctx.globalAlpha=alpha;ctx.fillStyle=GC.splashHaze;ctx.fillRect(0,HY-8,W,36);ctx.restore();

  // ── Road surface detail — subtle cross-hatch bands in perspective ──
  ctx.save();ctx.globalAlpha=alpha*0.07;ctx.strokeStyle='#fff';ctx.lineWidth=0.5;
  for(let band=0;band<6;band++){
    const py=HY+(H-HY)*((band+0.5)/6);
    const lx2=perspX(RL,py), rx2=perspX(RR,py);
    ctx.beginPath();ctx.moveTo(lx2,py);ctx.lineTo(rx2,py);ctx.stroke();
  }
  ctx.restore();

  // ── CAR — image-based top-down view ──
  const launchPhase=tVis>=106;
  const carX=W/2;
  let carY, carScale;
  if(!launchPhase){
    const revShake=sigState==='green'?Math.sin(tVis*1.4)*(tVis-94)*0.35:0;
    carY=H*0.84+revShake; carScale=1.05;
  } else {
    const lt=clamp((tVis-106)/38,0,1);
    const cp=lt*lt*lt;
    carY=lerp(H*0.84,HY+24,cp);
    carScale=lerp(1.05,0.28,cp);
  }
  const vanishFade=launchPhase?clamp(1-(clamp((tVis-106)/38,0,1)-0.70)/0.30,0,1):1;

  // Tyre smoke
  if(tVis>18&&tVis<114){
    const smokeIntensity=sigState==='green'?2.2:0.7;
    for(let s=0;s<22;s++){
      const sAge=(tVis-s*3.2); if(sAge<0)continue;
      const sx2=carX+Math.sin(s*1.9+tVis*0.06)*20*carScale;
      const sy2=carY+32*carScale+Math.abs(Math.sin(s*1.0+tVis*0.03))*12;
      const sr2=3+sAge*0.20*smokeIntensity;
      const sa=clamp((1-sAge*0.032)*0.32*smokeIntensity,0,0.50)*alpha*vanishFade;
      ctx.save();ctx.globalAlpha=sa;
      ctx.fillStyle=smokeIntensity>1?'rgba(160,155,150,1)':'rgba(185,185,190,1)';
      ctx.beginPath();ctx.arc(sx2,sy2,Math.min(sr2,28),0,Math.PI*2);ctx.fill();ctx.restore();
    }
  }

  // Draw car image
  {
    const carAlpha=alpha*(tVis<22?clamp((tVis-8)/14,0,1):1)*vanishFade;
    const _cW=46*carScale,_cH=88*carScale;
    ctx.save();ctx.globalAlpha=carAlpha;
    if(window._SPLASH_CAR&&window._SPLASH_CAR.complete&&window._SPLASH_CAR.naturalWidth>0){
      ctx.drawImage(window._SPLASH_CAR,carX-_cW/2,carY-_cH/2,_cW,_cH);
    }
    // Tail-light glow
    ctx.shadowColor='#ff2222';ctx.shadowBlur=12*carScale;ctx.fillStyle='rgba(255,60,60,0.45)';
    ctx.beginPath();ctx.ellipse(carX-10*carScale,carY+_cH/2-4*carScale,5*carScale,3*carScale,0,0,Math.PI*2);ctx.fill();
    ctx.beginPath();ctx.ellipse(carX+10*carScale,carY+_cH/2-4*carScale,5*carScale,3*carScale,0,0,Math.PI*2);ctx.fill();
    ctx.shadowBlur=0;ctx.restore();
  }

  // Launch trail — dramatic multi-layer streaks
  if(launchPhase){
    const lt=clamp((tVis-106)/38,0,1);
    const cp=lt*lt*lt;
    const trailBase=carY+carScale*38;
    // Wide outer glow streaks — solid colour with globalAlpha for fade (no per-loop gradient)
    for(let i=0;i<12;i++){
      const side=(i%2===0?-1:1);
      const sx2=carX+side*(3+i*2.8)*carScale;
      const trailLen=(40+i*14)*cp*(1-cp*0.4);
      const la=clamp(cp*2.2-0.3,0,0.65);
      ctx.save();ctx.globalAlpha=la*alpha*0.55*vanishFade;
      ctx.strokeStyle='rgba(0,255,140,0.9)';ctx.lineWidth=2.5+i*0.2;
      ctx.beginPath();ctx.moveTo(sx2,trailBase);ctx.lineTo(sx2,trailBase+trailLen);ctx.stroke();
      ctx.restore();
    }
    // Tight bright core streaks — solid colour
    for(let i=0;i<5;i++){
      const side=(i%2===0?-1:1);
      const sx2=carX+side*(1+i*3)*carScale;
      const trailLen=(55+i*8)*cp;
      const la=clamp(cp*3-0.5,0,0.90);
      ctx.save();ctx.globalAlpha=la*alpha*vanishFade;
      ctx.strokeStyle='rgba(200,255,230,0.95)';ctx.lineWidth=1.2;
      ctx.beginPath();ctx.moveTo(sx2,trailBase);ctx.lineTo(sx2,trailBase+trailLen);ctx.stroke();
      ctx.restore();
    }
    // Glow pool beneath car during launch — cached radial gradient (centre fixed at carX which barely moves)
    if(cp>0.1){
      ctx.save();ctx.globalAlpha=clamp(cp*0.5,0,0.35)*alpha*vanishFade;
      if(!GC.splashTrailPool){
        const pool=ctx.createRadialGradient(carX,trailBase,0,carX,trailBase,28);
        pool.addColorStop(0,'rgba(0,255,140,0.6)');pool.addColorStop(1,'transparent');
        GC.splashTrailPool=pool;
      }
      ctx.fillStyle=GC.splashTrailPool;ctx.beginPath();ctx.arc(carX,trailBase,28*carScale,0,Math.PI*2);ctx.fill();
      ctx.restore();
    }
  }

  // ── Title — Lane Havoc logo (animated scale-in) ──
  ctx.save();ctx.globalAlpha=alpha;
  const titleScale=tVis<22?(0.5+clamp((tVis-4)/18,0,1)*0.55):(1.0+Math.sin((tVis-22)*0.09)*0.012);
  if(window._LANE_HAVOC_LOGO&&window._LANE_HAVOC_LOGO.complete&&window._LANE_HAVOC_LOGO.naturalWidth>0){
    const _slW=320*titleScale,_slH=160*titleScale;
    ctx.drawImage(window._LANE_HAVOC_LOGO,W/2-_slW/2,H*0.06,_slW,_slH);
  }
  ctx.restore();

  // ── MENU OVERLAY — shown after car reaches horizon (t >= 144) ──
  // Design goal: the menu feels like an organic continuation of the cinematic world,
  // not a UI panel dropped on top. Buttons emerge from the road, staggered like arriving.
  if(tVis>=144){
    const menuFadeIn=clamp((t-148)/18,0,1); // master fade for the overlay vignette

    // ── Gradient vignette (bottom-heavy) instead of a flat dim overlay ──
    // This keeps the sky/city visible while creating contrast for the buttons below
    if(!GC.splashMenuVignette){
      const vg=ctx.createLinearGradient(0,H*0.22,0,H);
      vg.addColorStop(0,'rgba(2,4,12,0)');
      vg.addColorStop(0.28,'rgba(2,4,12,0.44)');
      vg.addColorStop(0.62,'rgba(2,4,12,0.72)');
      vg.addColorStop(1,'rgba(2,4,12,0.90)');
      GC.splashMenuVignette=vg;
    }
    ctx.save();ctx.globalAlpha=menuFadeIn;
    ctx.fillStyle=GC.splashMenuVignette;ctx.fillRect(0,0,W,H);
    ctx.restore();

    if(menuFadeIn<0.04)return; // don't draw buttons until overlay is forming

    // ── Button layout constants ──
    const pbW=160,pbH=50,pbX=W/2-pbW/2;
    const sbW=130,sbH=34,sbGapX=14,sbGapY=10;
    const sbLX=W/2-sbW-sbGapX/2, sbRX=W/2+sbGapX/2;

    // PLAY button resting Y — all other rows computed from this
    const pbRestY=344;
    const sbRow1Y=pbRestY+pbH+16, sbRow2Y=sbRow1Y+sbH+sbGapY;

    // ── PLAY button — slides up from below (tied to menuFadeIn) ──
    const playSlide=(1-menuFadeIn)*28; // starts 28px low, rises to resting position
    const pbY=pbRestY+playSlide;

    // Pulse glow once fully visible
    const playPulse=menuFadeIn>=1?1+fastSin(t*0.08)*0.28:1;

    ctx.save();ctx.globalAlpha=menuFadeIn;
    if(!GC.splashPlayBtn){
      const pbg=ctx.createLinearGradient(pbX,pbRestY,pbX,pbRestY+pbH);
      pbg.addColorStop(0,'rgba(0,180,80,0.65)');pbg.addColorStop(1,'rgba(0,100,50,0.55)');
      GC.splashPlayBtn=pbg;
    }
    ctx.shadowColor='#00e676';ctx.shadowBlur=24*playPulse;
    ctx.fillStyle=GC.splashPlayBtn;rr(pbX,pbY,pbW,pbH,12);ctx.fill();
    ctx.strokeStyle='#00e676';ctx.lineWidth=2;rr(pbX,pbY,pbW,pbH,12);ctx.stroke();
    ctx.shadowBlur=0;ctx.fillStyle='#ccffe8';
    ctx.font="900 20px 'Orbitron',impact,sans-serif";
    ctx.textAlign='center';ctx.textBaseline='middle';
    ctx.fillText('▶  PLAY',W/2,pbY+pbH/2);
    ctx.restore();

    // ── Best score & coin bank — plain glowing text above PLAY button ──
    const hudF=clamp((t-154)/12,0,1);
    if(hudF>0.01){
      const hudSlide=(1-hudF)*18;
      const hudY=pbY-22+hudSlide;

      ctx.save();ctx.globalAlpha=hudF*0.88;ctx.textAlign='center';ctx.textBaseline='middle';
      ctx.font="700 9px 'Orbitron',sans-serif";

      // 🏆 BEST — amber
      ctx.shadowColor='rgba(251,191,36,0.7)';ctx.shadowBlur=10;
      ctx.fillStyle='#fcd34d';
      ctx.fillText('\uD83C\uDFC6  BEST: '+bestScore, W/2-54, hudY);

      // Coin icon — small golden circle matching the in-game HUD coin
      const coinX=W/2+14, coinR=5;
      if(!GC.splashCoinIcon){
        const cg=ctx.createRadialGradient(coinX-coinR*0.35,hudY-coinR*0.35,0,coinX,hudY,coinR);
        cg.addColorStop(0,'#fff8d0');cg.addColorStop(0.38,'#f59e0b');
        cg.addColorStop(0.75,'#b45309');cg.addColorStop(1,'#7c2d00');
        GC.splashCoinIcon=cg;
      }
      ctx.shadowColor='rgba(251,191,36,0.80)';ctx.shadowBlur=8;
      ctx.fillStyle=GC.splashCoinIcon;
      ctx.beginPath();ctx.arc(coinX,hudY,coinR,0,Math.PI*2);ctx.fill();
      ctx.shadowBlur=0;

      // COINS value text — green, to the right of the coin icon
      ctx.shadowColor='rgba(74,222,128,0.7)';ctx.shadowBlur=10;
      ctx.fillStyle='#6ee7b7';
      ctx.textAlign='left';
      ctx.fillText(' COINS: '+coinBank, W/2+20, hudY);

      ctx.shadowBlur=0;
      ctx.restore();
    }

    // ── 4 smaller buttons — staggered slide-in (each arrives one after the other) ──
    const smBtns=[
      {label:'OBJECT GUIDE', x:sbLX, y:sbRow1Y, col:'#38bdf8', id:'guide', delay:158},
      {label:'STATS',        x:sbRX, y:sbRow1Y, col:'#a78bfa', id:'stats', delay:163},
      {label:'SHOP',         x:sbLX, y:sbRow2Y, col:'#fbbf24', id:'shop',  delay:168},
      {label:'HOW TO PLAY',  x:sbRX, y:sbRow2Y, col:'#fb923c', id:'howto', delay:173},
    ];

    smBtns.forEach(({label,x,y,col,delay})=>{
      const bf=clamp((t-delay)/13,0,1);
      if(bf<0.01)return;
      const slide=(1-bf)*20; // each button slides up 20px into position
      const dy=y+slide;
      ctx.save();ctx.globalAlpha=bf;
      ctx.shadowColor=col;ctx.shadowBlur=10;
      const rgb3=hexToRgb(col);
      ctx.fillStyle=`rgba(${rgb3.r*0.12|0},${rgb3.g*0.12|0},${rgb3.b*0.12|0},0.62)`;
      rr(x,dy,sbW,sbH,9);ctx.fill();
      ctx.strokeStyle=col;ctx.lineWidth=1.4;rr(x,dy,sbW,sbH,9);ctx.stroke();
      ctx.shadowBlur=0;ctx.fillStyle=col;
      ctx.font="bold 10px 'Orbitron',sans-serif";
      ctx.textAlign='center';ctx.textBaseline='middle';
      ctx.fillText(label,x+sbW/2,dy+sbH/2);
      ctx.restore();
    });

    // ── Horizon "engine idle" breath — subtle glow at the vanishing point ──
    // Pulses gently to hint that the world is still alive behind the buttons
    const idleBreath=0.06+fastSin(t*0.05)*0.04;
    if(!GC.splashIdleGlow){
      const ig=ctx.createRadialGradient(W/2,HY,0,W/2,HY,60);
      ig.addColorStop(0,'rgba(0,230,118,1)');ig.addColorStop(1,'rgba(0,230,118,0)');
      GC.splashIdleGlow=ig;
    }
    ctx.save();ctx.globalAlpha=menuFadeIn*idleBreath;
    ctx.fillStyle=GC.splashIdleGlow;ctx.beginPath();ctx.arc(W/2,HY,60,0,Math.PI*2);ctx.fill();
    ctx.restore();

    // Store button rects at their RESTING positions for touch/click hit-testing
    // (the slide finishes quickly, so resting coords are always safe to use)
    _splashMenuBtns={
      play:  {x:pbX,   y:pbRestY,  w:pbW,  h:pbH},
      guide: {x:sbLX,  y:sbRow1Y,  w:sbW,  h:sbH},
      stats: {x:sbRX,  y:sbRow1Y,  w:sbW,  h:sbH},
      shop:  {x:sbLX,  y:sbRow2Y,  w:sbW,  h:sbH},
      howto: {x:sbRX,  y:sbRow2Y,  w:sbW,  h:sbH},
    };
  } else {
    _splashMenuBtns=null;
    // Progress bar while launching
    ctx.save();ctx.globalAlpha=alpha*0.55;
    const barW=120,barH=2,barX=(W-barW)/2,barY=H-28;
    ctx.fillStyle='rgba(255,255,255,0.1)';ctx.fillRect(barX,barY,barW,barH);
    ctx.fillStyle='#00e676';ctx.fillRect(barX,barY,barW*(tVis/144),barH);
    ctx.restore();
  }
}



/* ══════════════════════════════════════════════
   DRAW — INTRO (menu) SCREEN
══════════════════════════════════════════════ */
// Small canvas-drawn icons for the legend
function _drawLegendIcon(type,cx,cy,sz){
  ctx.save();
  switch(type){
    case 'enemy': // red car (top-down)
      ctx.fillStyle='#e84118';rr(cx-sz*0.5,cy-sz*0.8,sz,sz*1.6,sz*0.18);ctx.fill();
      ctx.fillStyle='rgba(180,220,255,0.85)';rr(cx-sz*0.35,cy-sz*0.6,sz*0.7,sz*0.5,sz*0.1);ctx.fill();
      ctx.fillStyle='#ff2222';ctx.fillRect(cx-sz*0.4,cy+sz*0.55,sz*0.3,sz*0.2);ctx.fillRect(cx+sz*0.1,cy+sz*0.55,sz*0.3,sz*0.2);
      break;

    case 'police': // blue/white police car
      ctx.fillStyle='#c8d8e8';rr(cx-sz*0.5,cy-sz*0.8,sz,sz*1.6,sz*0.18);ctx.fill();
      ctx.fillStyle='#111';ctx.fillRect(cx-sz*0.5,cy-sz*0.08,sz,sz*0.28);
      ctx.fillStyle=Math.floor(frameCount/6)%2===0?'#ef4444':'#3b82f6';
      ctx.fillRect(cx-sz*0.38,cy-sz*0.78,sz*0.3,sz*0.18);
      ctx.fillStyle=Math.floor(frameCount/6)%2===0?'#3b82f6':'#ef4444';
      ctx.fillRect(cx+sz*0.07,cy-sz*0.78,sz*0.3,sz*0.18);
      break;
    case 'nitro': // lightning bolt
      ctx.fillStyle='#f59e0b';ctx.shadowColor='#f59e0b';ctx.shadowBlur=8;
      ctx.beginPath();ctx.moveTo(cx+sz*0.2,cy-sz*0.9);ctx.lineTo(cx-sz*0.15,cy-sz*0.02);ctx.lineTo(cx+sz*0.18,cy-sz*0.02);ctx.lineTo(cx-sz*0.2,cy+sz*0.9);ctx.lineTo(cx+sz*0.1,cy+sz*0.1);ctx.lineTo(cx-sz*0.12,cy+sz*0.1);ctx.closePath();ctx.fill();
      break;
    case 'ghost': // translucent ghost silhouette
      ctx.save();
      ctx.globalAlpha=0.85;
      ctx.fillStyle='#e2e8f0';ctx.shadowColor='#c7d2fe';ctx.shadowBlur=10;
      // Ghost body
      ctx.beginPath();
      ctx.arc(cx,cy-sz*0.18,sz*0.62,Math.PI,0);
      ctx.lineTo(cx+sz*0.62,cy+sz*0.62);
      // Wavy bottom — 3 bumps
      ctx.quadraticCurveTo(cx+sz*0.42,cy+sz*0.32,cx+sz*0.22,cy+sz*0.62);
      ctx.quadraticCurveTo(cx+sz*0.02,cy+sz*0.32,cx-sz*0.18,cy+sz*0.62);
      ctx.quadraticCurveTo(cx-sz*0.38,cy+sz*0.32,cx-sz*0.62,cy+sz*0.62);
      ctx.closePath();ctx.fill();
      // Eyes
      ctx.fillStyle='rgba(20,20,40,0.80)';
      ctx.beginPath();ctx.ellipse(cx-sz*0.22,cy-sz*0.12,sz*0.12,sz*0.16,0,0,Math.PI*2);ctx.fill();
      ctx.beginPath();ctx.ellipse(cx+sz*0.22,cy-sz*0.12,sz*0.12,sz*0.16,0,0,Math.PI*2);ctx.fill();
      ctx.restore();
      break;
    case 'shield': // hexagon
      ctx.strokeStyle='#3b82f6';ctx.lineWidth=sz*0.22;ctx.shadowColor='#3b82f6';ctx.shadowBlur=8;
      ctx.beginPath();for(let i=0;i<6;i++){const a=i*Math.PI/3-Math.PI/6;ctx.lineTo(cx+Math.cos(a)*sz*0.7,cy+Math.sin(a)*sz*0.7);}
      ctx.closePath();ctx.stroke();
      ctx.fillStyle='rgba(59,130,246,0.18)';ctx.fill();
      break;
    case 'coin': // gold coin
      ctx.shadowColor='#fbbf24';ctx.shadowBlur=8;
      const cg=ctx.createRadialGradient(cx-sz*0.2,cy-sz*0.2,sz*0.05,cx,cy,sz*0.72);
      cg.addColorStop(0,'#fef9c3');cg.addColorStop(0.5,'#f59e0b');cg.addColorStop(1,'#78350f');
      ctx.fillStyle=cg;ctx.beginPath();ctx.arc(cx,cy,sz*0.72,0,Math.PI*2);ctx.fill();
      ctx.fillStyle='#92400e';ctx.font=`bold ${sz*0.8}px sans-serif`;
      ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillText('$',cx,cy+sz*0.05);
      break;
    case 'speedbump': // yellow/black stripes
      for(let i=0;i<4;i++){ctx.fillStyle=i%2===0?'#f0c000':'#222';ctx.fillRect(cx-sz*0.7+i*sz*0.35,cy-sz*0.28,sz*0.35,sz*0.55);}
      ctx.strokeStyle='rgba(255,220,80,0.8)';ctx.lineWidth=sz*0.1;ctx.strokeRect(cx-sz*0.7,cy-sz*0.28,sz*1.4,sz*0.55);
      break;
    case 'brokencar': // wide sideways car
      ctx.fillStyle='#5a1a1a';rr(cx-sz*0.9,cy-sz*0.42,sz*1.8,sz*0.84,sz*0.14);ctx.fill();
      ctx.fillStyle='rgba(80,100,120,0.55)';rr(cx-sz*0.65,cy-sz*0.32,sz*0.5,sz*0.42,sz*0.08);ctx.fill();
      ctx.fillStyle='rgba(255,70,0,0.9)';ctx.beginPath();ctx.moveTo(cx+sz*0.1,cy-sz*0.75);ctx.lineTo(cx+sz*0.38,cy-sz*0.42);ctx.lineTo(cx-sz*0.18,cy-sz*0.42);ctx.closePath();ctx.fill();
      break;
    case 'cattle': { // cow matching actual in-game style
      const sc=sz/10; // scale factor relative to icon size
      ctx.save();
      ctx.translate(cx,cy);
      // Legs (animated stub legs)
      ctx.fillStyle='#c8b490';
      [[-sz*0.38,sz*0.18],[-sz*0.14,sz*0.18],[sz*0.08,sz*0.18],[sz*0.28,sz*0.18]]
        .forEach(([lx,ly])=>ctx.fillRect(lx,ly,sz*0.14,sz*0.3));
      // Body
      const bodyG2=ctx.createLinearGradient(-sz*0.55,0,sz*0.55,0);
      bodyG2.addColorStop(0,'#f0e4cc');bodyG2.addColorStop(1,'#d4c4a0');
      ctx.fillStyle=bodyG2;rr(-sz*0.55,-sz*0.28,sz*1.1,sz*0.52,sz*0.14);ctx.fill();
      // Spots
      ctx.fillStyle='rgba(50,30,15,0.65)';
      ctx.beginPath();ctx.ellipse(-sz*0.14,-sz*0.06,sz*0.18,sz*0.11,0.4,0,Math.PI*2);ctx.fill();
      ctx.beginPath();ctx.ellipse(sz*0.18,sz*0.1,sz*0.12,sz*0.16,-0.3,0,Math.PI*2);ctx.fill();
      // Udder
      ctx.fillStyle='#f5a0a0';ctx.beginPath();ctx.ellipse(-sz*0.08,sz*0.3,sz*0.22,sz*0.11,0,0,Math.PI*2);ctx.fill();
      // Head
      ctx.fillStyle='#f0e4cc';
      ctx.beginPath();ctx.ellipse(sz*0.72,-sz*0.14,sz*0.3,sz*0.22,0,0,Math.PI*2);ctx.fill();
      // Snout
      ctx.fillStyle='#ddc090';
      ctx.beginPath();ctx.ellipse(sz*0.98,-sz*0.04,sz*0.16,sz*0.13,0,0,Math.PI*2);ctx.fill();
      // Nostrils
      ctx.fillStyle='#333';
      ctx.beginPath();ctx.arc(sz*0.92,-sz*0.01,sz*0.04,0,Math.PI*2);ctx.fill();
      ctx.beginPath();ctx.arc(sz*1.04,-sz*0.01,sz*0.04,0,Math.PI*2);ctx.fill();
      // Eye
      ctx.fillStyle='#111';ctx.beginPath();ctx.arc(sz*0.58,-sz*0.24,sz*0.07,0,Math.PI*2);ctx.fill();
      ctx.fillStyle='rgba(255,255,255,0.9)';ctx.beginPath();ctx.arc(sz*0.56,-sz*0.26,sz*0.03,0,Math.PI*2);ctx.fill();
      // Horns
      ctx.strokeStyle='#d4c890';ctx.lineWidth=sz*0.09;ctx.lineCap='round';
      ctx.beginPath();ctx.moveTo(sz*0.48,-sz*0.35);ctx.quadraticCurveTo(sz*0.3,-sz*0.62,sz*0.36,-sz*0.72);ctx.stroke();
      ctx.beginPath();ctx.moveTo(sz*0.64,-sz*0.35);ctx.quadraticCurveTo(sz*0.82,-sz*0.62,sz*0.76,-sz*0.72);ctx.stroke();
      // Tail
      ctx.strokeStyle='#c8b490';ctx.lineWidth=sz*0.07;
      ctx.beginPath();ctx.moveTo(-sz*0.55,-sz*0.04);ctx.quadraticCurveTo(-sz*0.78,-sz*0.22,-sz*0.74,-sz*0.42);ctx.stroke();
      ctx.fillStyle='#444';ctx.beginPath();ctx.arc(-sz*0.74,-sz*0.42,sz*0.09,0,Math.PI*2);ctx.fill();
      ctx.restore();
      break;}
    case 'stone': { // rock
      const sg=ctx.createRadialGradient(cx-sz*0.25,cy-sz*0.25,sz*0.1,cx,cy,sz*0.82);
      sg.addColorStop(0,'#c8c8d0');sg.addColorStop(0.5,'#88889a');sg.addColorStop(1,'#3a3a45');
      ctx.fillStyle=sg;ctx.beginPath();ctx.arc(cx,cy,sz*0.78,0,Math.PI*2);ctx.fill();
      ctx.save();ctx.globalAlpha=0.35;ctx.fillStyle='#fff';
      ctx.beginPath();ctx.ellipse(cx-sz*0.25,cy-sz*0.25,sz*0.25,sz*0.15,Math.PI*0.3,0,Math.PI*2);ctx.fill();ctx.restore();
      break;}
    case 'manhole': { // orange-rimmed manhole
      ctx.fillStyle='#7a3a0a';ctx.beginPath();ctx.ellipse(cx,cy,sz*0.88,sz*0.55,0,0,Math.PI*2);ctx.fill();
      ctx.strokeStyle='#e67e22';ctx.lineWidth=sz*0.18;ctx.beginPath();ctx.ellipse(cx,cy,sz*0.88,sz*0.55,0,0,Math.PI*2);ctx.stroke();
      ctx.fillStyle='#3a2208';ctx.beginPath();ctx.ellipse(cx,cy,sz*0.6,sz*0.38,0,0,Math.PI*2);ctx.fill();
      ctx.fillStyle='#f0a040';ctx.beginPath();ctx.arc(cx,cy,sz*0.14,0,Math.PI*2);ctx.fill();
      break;}
    case 'roadwork': { // orange cone with stripes
      ctx.fillStyle='#e67e22';
      ctx.beginPath();ctx.moveTo(cx,cy-sz*0.9);ctx.lineTo(cx+sz*0.5,cy+sz*0.55);ctx.lineTo(cx-sz*0.5,cy+sz*0.55);ctx.closePath();ctx.fill();
      ctx.fillStyle='#fff';ctx.save();ctx.globalAlpha=0.7;
      ctx.fillRect(cx-sz*0.3,cy-sz*0.1,sz*0.6,sz*0.14);ctx.restore();
      ctx.fillStyle='#333';ctx.fillRect(cx-sz*0.55,cy+sz*0.55,sz*1.1,sz*0.18);
      break;}
    case 'oil': { // iridescent oil slick ellipse
      const oilG=ctx.createRadialGradient(cx-sz*0.15,cy-sz*0.1,sz*0.05,cx,cy,sz*0.88);
      oilG.addColorStop(0,'#c084fc');oilG.addColorStop(0.35,'#818cf8');
      oilG.addColorStop(0.65,'#34d399');oilG.addColorStop(1,'#60a5fa');
      ctx.fillStyle=oilG;
      ctx.beginPath();ctx.ellipse(cx,cy,sz*0.88,sz*0.52,0,0,Math.PI*2);ctx.fill();
      ctx.strokeStyle='rgba(192,132,252,0.55)';ctx.lineWidth=sz*0.12;
      ctx.beginPath();ctx.ellipse(cx,cy,sz*0.88,sz*0.52,0,0,Math.PI*2);ctx.stroke();
      ctx.save();ctx.globalAlpha=0.35;ctx.strokeStyle='#fff';ctx.lineWidth=sz*0.06;
      ctx.beginPath();ctx.ellipse(cx-sz*0.18,cy-sz*0.08,sz*0.3,sz*0.16,-0.3,0,Math.PI*2);ctx.stroke();
      ctx.restore();
      break;}
    case 'truck': { // top-down semi truck icon
      ctx.fillStyle='#374151';rr(cx-sz*0.48,cy-sz*0.45,sz*0.96,sz*1.1,sz*0.1);ctx.fill();
      ctx.strokeStyle='#6b7280';ctx.lineWidth=sz*0.08;rr(cx-sz*0.48,cy-sz*0.45,sz*0.96,sz*1.1,sz*0.1);ctx.stroke();
      ctx.fillStyle='#1e2433';rr(cx-sz*0.42,cy-sz*0.88,sz*0.84,sz*0.48,sz*0.1);ctx.fill();
      const wsG2=ctx.createLinearGradient(0,cy-sz*0.83,0,cy-sz*0.52);
      wsG2.addColorStop(0,'rgba(155,215,245,0.85)');wsG2.addColorStop(1,'rgba(70,145,205,0.5)');
      ctx.fillStyle=wsG2;rr(cx-sz*0.28,cy-sz*0.82,sz*0.56,sz*0.26,sz*0.06);ctx.fill();
      ctx.fillStyle='#c8e8ff';ctx.shadowColor='#c8e8ff';ctx.shadowBlur=4;
      ctx.fillRect(cx-sz*0.42,cy-sz*0.9,sz*0.14,sz*0.05);ctx.fillRect(cx+sz*0.28,cy-sz*0.9,sz*0.14,sz*0.05);
      ctx.shadowBlur=0;
      ctx.fillStyle='#ef4444';ctx.shadowColor='#ef4444';ctx.shadowBlur=5;
      ctx.font=`bold ${sz*0.48}px 'Orbitron',sans-serif`;
      ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillText('2×',cx,cy+sz*0.28);
      ctx.shadowBlur=0;
      break;}
    case 'magnet': { // U-shaped horseshoe magnet
      ctx.save();
      ctx.strokeStyle='#ef3349';ctx.lineWidth=sz*0.28;ctx.shadowColor='#06b6d4';ctx.shadowBlur=8;
      ctx.beginPath();ctx.arc(cx,cy-sz*0.05,sz*0.52,Math.PI,0);ctx.stroke();
      ctx.fillStyle='#ef3349';
      ctx.fillRect(cx-sz*0.66,cy-sz*0.05,sz*0.28,sz*0.7);
      ctx.fillRect(cx+sz*0.38,cy-sz*0.05,sz*0.28,sz*0.7);
      ctx.fillStyle='#e2e8f0';ctx.shadowColor='#e2e8f0';ctx.shadowBlur=5;
      ctx.fillRect(cx-sz*0.66,cy-sz*0.05,sz*0.28,sz*0.24);
      ctx.fillRect(cx+sz*0.38,cy-sz*0.05,sz*0.28,sz*0.24);
      ctx.shadowBlur=0;ctx.restore();
      break;}
    case 'gun': { // side-profile gun silhouette
      ctx.save();
      ctx.shadowColor='rgba(255,224,96,0.6)';ctx.shadowBlur=6;
      const gunSlG=ctx.createLinearGradient(cx-sz*0.58,cy-sz*0.22,cx-sz*0.58,cy+sz*0.14);
      gunSlG.addColorStop(0,'#9098a8');gunSlG.addColorStop(1,'#484858');
      ctx.fillStyle=gunSlG;rr(cx-sz*0.58,cy-sz*0.22,sz*1.05,sz*0.34,sz*0.07);ctx.fill();
      ctx.fillStyle='#d4a830';ctx.shadowColor='rgba(255,200,40,0.7)';ctx.shadowBlur=4;
      rr(cx-sz*0.82,cy-sz*0.12,sz*0.28,sz*0.12,sz*0.04);ctx.fill();
      ctx.shadowBlur=0;ctx.fillStyle='#484858';
      ctx.save();ctx.translate(cx+sz*0.3,cy);ctx.rotate(0.1);
      ctx.fillRect(-sz*0.13,0,sz*0.2,sz*0.48);ctx.restore();
      ctx.strokeStyle='#6a6a7a';ctx.lineWidth=sz*0.09;ctx.lineCap='round';
      ctx.beginPath();ctx.moveTo(cx+sz*0.08,cy);ctx.quadraticCurveTo(cx+sz*0.22,cy+sz*0.24,cx+sz*0.36,cy+sz*0.08);ctx.stroke();
      ctx.fillStyle='#ffffff';ctx.shadowColor='#fffce0';ctx.shadowBlur=3;
      ctx.fillRect(cx+sz*0.36,cy-sz*0.3,sz*0.05,sz*0.07);ctx.shadowBlur=0;
      ctx.strokeStyle='#c0c4d0';ctx.lineWidth=sz*0.07;rr(cx-sz*0.58,cy-sz*0.22,sz*1.05,sz*0.34,sz*0.07);ctx.stroke();
      ctx.restore();
      break;}
  }
  ctx.restore();
}

function drawIntro(){
  // ── Scrolling road background ──
  // Cache static gradients — created once, reused every frame
  if(!GC.introSky){
    const sky2=ctx.createLinearGradient(0,0,0,H*0.45);
    sky2.addColorStop(0,'#04060a');sky2.addColorStop(1,'#0b0e1e');
    GC.introSky=sky2;
  }
  if(!GC.introRoad){
    const rg2=ctx.createLinearGradient(0,H*0.42,0,H);
    rg2.addColorStop(0,'#14182a');rg2.addColorStop(1,'#1e222e');
    GC.introRoad=rg2;
  }
  ctx.fillStyle=GC.introSky;ctx.fillRect(0,0,W,H);
  ctx.fillStyle=GC.introRoad;ctx.fillRect(0,H*0.42,W,H);
  // Scrolling dashes
  ctx.save();ctx.globalAlpha=0.22;ctx.strokeStyle='rgba(255,255,255,0.5)';ctx.lineWidth=1.5;
  ctx.setLineDash([26,18]);
  [80,160,240,320].forEach(x=>{
    ctx.lineDashOffset=-(menuScrollY*1.4)%44;
    ctx.beginPath();ctx.moveTo(x,H*0.42);ctx.lineTo(x,H);ctx.stroke();
  });
  ctx.setLineDash([]);
  ctx.save();ctx.globalAlpha=0.3;ctx.shadowColor='rgba(245,158,11,0.4)';ctx.shadowBlur=6;
  ctx.strokeStyle='#f59e0b';ctx.lineWidth=2;
  ctx.beginPath();ctx.moveTo(40,0);ctx.lineTo(40,H);ctx.stroke();
  ctx.beginPath();ctx.moveTo(360,0);ctx.lineTo(360,H);ctx.stroke();
  ctx.restore();ctx.restore();

  ctx.fillStyle='rgba(4,6,14,0.60)';ctx.fillRect(0,0,W,H);

  // ── Main card ──
  const CW=352,CX=(W-CW)/2,CY=10;
  const cardH=H-20;
  ctx.save();
  ctx.fillStyle='rgba(6,9,22,0.94)';rr(CX,CY,CW,cardH,14);ctx.fill();
  ctx.shadowColor='#00e676';ctx.shadowBlur=18;
  ctx.strokeStyle='rgba(0,230,118,0.4)';ctx.lineWidth=1.5;rr(CX,CY,CW,cardH,14);ctx.stroke();
  ctx.shadowBlur=0;ctx.globalAlpha=0.07;ctx.strokeStyle='#fff';ctx.lineWidth=0.8;
  rr(CX+1,CY+1,CW-2,cardH-2,13);ctx.stroke();
  ctx.restore();

  // ── Header — Lane Havoc logo ──
  ctx.save();
  if(window._LANE_HAVOC_LOGO&&window._LANE_HAVOC_LOGO.complete&&window._LANE_HAVOC_LOGO.naturalWidth>0){
    ctx.drawImage(window._LANE_HAVOC_LOGO,W/2-100,CY+10,200,100);
  }
  ctx.textAlign='center';ctx.textBaseline='middle';
  ctx.font="600 7.5px 'Rajdhani',sans-serif";ctx.fillStyle='rgba(148,163,184,0.65)';ctx.shadowBlur=0;
  ctx.fillText('OBJECT  GUIDE',W/2,CY+82);
  ctx.restore();

  // ── Scroll hint ──
  ctx.save();ctx.textAlign='center';ctx.textBaseline='middle';
  ctx.font="600 7px 'Rajdhani',sans-serif";ctx.fillStyle='rgba(148,163,184,0.40)';
  ctx.fillText('↕ scroll to see all',W/2,CY+91);
  ctx.restore();

  // Divider
  ctx.save();ctx.strokeStyle='rgba(0,230,118,0.2)';ctx.lineWidth=1;
  ctx.beginPath();ctx.moveTo(CX+16,CY+97);ctx.lineTo(CX+CW-16,CY+97);ctx.stroke();
  ctx.restore();

  // ── Legend (scrollable) ──
  const items=[
    {type:'enemy',    name:'ENEMY CAR',    desc:'Oncoming red car — dodge left or right'},
    {type:'police',   name:'POLICE BOSS',  desc:'Pursuit car every 5 stages — survive 8s'},
    {type:'cattle',   name:'BULL / COW',   desc:'Crossing animal — jump over or switch lane'},
    {type:'stone',    name:'ROCK',         desc:'Blocks road — jump or switch lane'},
    {type:'manhole',  name:'MANHOLE',      desc:'Orange cover — avoid or jump over'},
    {type:'speedbump',name:'SPEED BUMP',   desc:'Safe to hit — slows you briefly'},
    {type:'brokencar',name:'BROKEN CAR',   desc:'Wreck spans 2 lanes — plan ahead'},
    {type:'truck',    name:'TRUCK',        desc:'2-hit obstacle — tank twice or dodge (Stage 3+)'},
    {type:'oil',      name:'OIL SLICK',    desc:'Locks lane-switching for ~2s (Stage 6+)'},
    {type:'roadwork', name:'ROAD WORK',    desc:'Cone closes lane 4 — stay in lanes 1–3'},
    {type:'nitro',    name:'NITRO',        desc:'2× score boost ~3s — tap NITRO button to fire'},
    {type:'ghost',    name:'GHOST',        desc:'Phase through all hazards for 3s'},
    {type:'shield',   name:'SHIELD',       desc:'Absorbs one crash — earns +30 pts'},
    {type:'magnet',   name:'MAGNET',       desc:'Auto-pulls all nearby coins to you'},
    {type:'gun',      name:'MACHINE GUN',  desc:'Pick up then tap FIRE to shoot enemy cars'},
    {type:'coin',     name:'COIN',         desc:'Collect coins — spend them in the Shop'},
  ];

  // Larger rows for better readability
  const rowH=44, iconSz=16;
  const tableTop=CY+100;
  const tableH=cardH-148; // available scroll area height
  const totalContentH=items.length*rowH;
  const maxScroll=Math.max(0,totalContentH-tableH);
  // Clamp scroll
  introScrollY=clamp(introScrollY,0,maxScroll);

  const colIcon=CX+26, colName=CX+58, colDesc=CX+58;
  const nameCol={enemy:'#ef4444',police:'#93c5fd',cattle:'#86efac',stone:'#94a3b8',
    manhole:'#fb923c',roadwork:'#fbbf24',speedbump:'#fde68a',
    brokencar:'#f97316',nitro:'#fbbf24',ghost:'#e2e8f0',shield:'#3b82f6',coin:'#fbbf24',
    oil:'#c084fc',truck:'#6b7280',magnet:'#06b6d4',gun:'#fef08a'};

  // Clip to scrollable area
  ctx.save();
  ctx.beginPath();ctx.rect(CX+4,tableTop,CW-8,tableH);ctx.clip();

  items.forEach((item,i)=>{
    const ry=tableTop+i*rowH-introScrollY;
    if(ry+rowH<tableTop-10||ry>tableTop+tableH+10)return;
    if(i%2===0){
      ctx.save();ctx.globalAlpha=0.055;ctx.fillStyle='#fff';
      rr(CX+6,ry+1,CW-12,rowH-2,5);ctx.fill();ctx.restore();
    }
    _drawLegendIcon(item.type,colIcon,ry+rowH/2,iconSz);
    ctx.save();ctx.textAlign='left';ctx.textBaseline='middle';
    // Name — larger font
    ctx.font="bold 11px 'Orbitron',sans-serif";
    ctx.fillStyle=nameCol[item.type]||'#e2e8f0';
    ctx.shadowColor=nameCol[item.type]||'#e2e8f0';ctx.shadowBlur=5;
    ctx.fillText(item.name,colName,ry+rowH/2-8);
    ctx.shadowBlur=0;
    // Description — larger font
    ctx.font="500 10px 'Rajdhani',sans-serif";ctx.fillStyle='rgba(148,163,184,0.90)';
    ctx.fillText(item.desc,colDesc,ry+rowH/2+8);
    ctx.restore();
  });
  ctx.restore();

  // Scroll indicator bar
  if(maxScroll>0){
    const barX=CX+CW-7,barY=tableTop,barH2=tableH;
    ctx.save();
    ctx.fillStyle='rgba(255,255,255,0.06)';rr(barX,barY,4,barH2,2);ctx.fill();
    const thumbH=Math.max(24,(barH2/totalContentH)*barH2);
    const thumbY=barY+(introScrollY/maxScroll)*(barH2-thumbH);
    ctx.fillStyle='rgba(0,230,118,0.4)';rr(barX,thumbY,4,thumbH,2);ctx.fill();
    ctx.restore();
  }

  // ── Footer buttons ──
  const footY=CY+cardH-42;
  ctx.save();ctx.strokeStyle='rgba(0,230,118,0.15)';ctx.lineWidth=1;
  ctx.beginPath();ctx.moveTo(CX+16,footY);ctx.lineTo(CX+CW-16,footY);ctx.stroke();
  ctx.restore();

  // PLAY button — center, pulsing green
  const pbW=110,pbH=34,pbX=W/2-pbW/2,pbY=footY-56;
  const pulse=0.80+fastSin(frameCount*0.10)*0.20;
  ctx.save();ctx.globalAlpha=pulse;
  if(!GC.shopPlayGrad){
    const pbGrad=ctx.createLinearGradient(pbX,pbY,pbX,pbY+pbH);
    pbGrad.addColorStop(0,'rgba(0,200,90,0.32)');pbGrad.addColorStop(1,'rgba(0,140,60,0.22)');
    GC.shopPlayGrad=pbGrad;
  }
  ctx.fillStyle=GC.shopPlayGrad;rr(pbX,pbY,pbW,pbH,9);ctx.fill();
  ctx.strokeStyle='#00e676';ctx.lineWidth=2;
  ctx.shadowColor='#00e676';ctx.shadowBlur=18;
  rr(pbX,pbY,pbW,pbH,9);ctx.stroke();
  ctx.textAlign='center';ctx.textBaseline='middle';
  ctx.font="bold 12px 'Orbitron',sans-serif";ctx.fillStyle='#00e676';ctx.shadowBlur=12;
  ctx.fillText('▶  PLAY',W/2,pbY+pbH/2);
  ctx.restore();

  // BACK button — bottom-left (goes to main menu / splash)
  const backW=76,backH=22,backX=CX+10,backY=footY+10;
  ctx.save();
  ctx.fillStyle='rgba(20,30,60,0.85)';rr(backX,backY,backW,backH,6);ctx.fill();
  ctx.strokeStyle='rgba(99,179,237,0.65)';ctx.lineWidth=1.2;rr(backX,backY,backW,backH,6);ctx.stroke();
  ctx.textAlign='center';ctx.textBaseline='middle';
  ctx.font="bold 8px 'Orbitron',sans-serif";ctx.fillStyle='#93c5fd';
  ctx.fillText('← BACK',backX+backW/2,backY+backH/2);
  ctx.restore();

  // STATS button — bottom-center
  const sbW=76,sbH=22,sbX=W/2-sbW/2,sbY=footY+10;
  ctx.save();
  ctx.fillStyle='rgba(20,40,30,0.85)';rr(sbX,sbY,sbW,sbH,6);ctx.fill();
  ctx.strokeStyle='rgba(74,222,128,0.65)';ctx.lineWidth=1.2;rr(sbX,sbY,sbW,sbH,6);ctx.stroke();
  ctx.textAlign='center';ctx.textBaseline='middle';
  ctx.font="bold 8px 'Orbitron',sans-serif";ctx.fillStyle='#4ade80';
  ctx.fillText('📊 STATS',sbX+sbW/2,sbY+sbH/2);
  ctx.restore();

  // HOWTO button — bottom-right (in footer)
  const ibW=76,ibH=22,ibX=CX+CW-ibW-10,ibY=footY+10;
  ctx.save();
  ctx.fillStyle='rgba(30,40,90,0.85)';rr(ibX,ibY,ibW,ibH,6);ctx.fill();
  ctx.strokeStyle='rgba(99,179,237,0.7)';ctx.lineWidth=1.2;rr(ibX,ibY,ibW,ibH,6);ctx.stroke();
  ctx.textAlign='center';ctx.textBaseline='middle';
  ctx.font="bold 8px 'Orbitron',sans-serif";ctx.fillStyle='#93c5fd';
  ctx.fillText('? HOW TO',ibX+ibW/2,ibY+ibH/2);
  ctx.restore();

  // Stats overlay panel (shown when showStats===true)
  if(showStats){
    ctx.save();
    ctx.fillStyle='rgba(4,8,20,0.96)';rr(CX+12,CY+80,CW-24,cardH-120,12);ctx.fill();
    ctx.shadowColor='#4ade80';ctx.shadowBlur=18;
    ctx.strokeStyle='rgba(74,222,128,0.55)';ctx.lineWidth=1.5;rr(CX+12,CY+80,CW-24,cardH-120,12);ctx.stroke();
    ctx.shadowBlur=0;
    ctx.textAlign='center';ctx.textBaseline='middle';
    ctx.font="900 15px 'Orbitron',impact,sans-serif";ctx.fillStyle='#4ade80';
    ctx.shadowColor='#4ade80';ctx.shadowBlur=12;
    ctx.fillText('YOUR STATS',W/2,CY+108);ctx.shadowBlur=0;
    // Divider
    ctx.strokeStyle='rgba(74,222,128,0.2)';ctx.lineWidth=1;
    ctx.beginPath();ctx.moveTo(CX+30,CY+122);ctx.lineTo(CX+CW-30,CY+122);ctx.stroke();
    // Stats rows
    const srows=[
      ['🏆 Best Score',    bestScore,          '#fbbf24'],
      ['📏 Best Distance', bestDistance.toFixed(2)+'km',   '#06b6d4'],
      ['🎮 Total Runs',    statTotalRuns,      '#93c5fd'],
      ['🪙 Total Coins',   coinBank,           '#fbbf24'],
      ['💨 Near-Misses',   statTotalMisses,    '#f97316'],
      ['⚡ Best Streak',    statBestCombo+'×',  '#ef4444'],
    ];
    srows.forEach(([label,val,col],i)=>{
      const ry=CY+138+i*38;
      ctx.save();
      if(i%2===0){ctx.globalAlpha=0.05;ctx.fillStyle='#fff';rr(CX+20,ry-12,CW-40,34,6);ctx.fill();}
      ctx.globalAlpha=1;
      ctx.font="bold 9px 'Orbitron',sans-serif";ctx.fillStyle='#94a3b8';
      ctx.textAlign='left';ctx.fillText(label,CX+36,ry+2);
      ctx.font="bold 14px 'Orbitron',impact,sans-serif";ctx.fillStyle=col;
      ctx.shadowColor=col;ctx.shadowBlur=8;
      ctx.textAlign='right';ctx.fillText(val,CX+CW-36,ry+4);
      ctx.shadowBlur=0;
      ctx.restore();
    });
    // Back button inside stats panel
    const sbbW=90,sbbH=20,sbbX=W/2-45,sbbY=CY+cardH-118;
    ctx.fillStyle='rgba(20,40,30,0.88)';rr(sbbX,sbbY,sbbW,sbbH,6);ctx.fill();
    ctx.strokeStyle='rgba(74,222,128,0.7)';ctx.lineWidth=1.2;rr(sbbX,sbbY,sbbW,sbbH,6);ctx.stroke();
    ctx.textAlign='center';ctx.textBaseline='middle';
    ctx.font="bold 8px 'Orbitron',sans-serif";ctx.fillStyle='#4ade80';
    ctx.fillText('← BACK',W/2,sbbY+sbbH/2);
    // Tap anywhere in panel to close
    ctx.textAlign='center';ctx.textBaseline='bottom';
    ctx.font="600 8px 'Rajdhani',sans-serif";ctx.fillStyle='rgba(100,116,139,0.75)';
    ctx.fillText('or tap STATS again to close',W/2,CY+cardH-58);
    ctx.restore();
  }

  // Mission strip
  if(activeMission){
    ctx.save();ctx.globalAlpha=0.85;
    ctx.textAlign='center';ctx.textBaseline='bottom';
    ctx.font="600 7px 'Rajdhani',sans-serif";ctx.fillStyle='#86efac';
    const _iMTxt='✦ TODAY: '+activeMission.text+' → +'+activeMission.reward+' ';
    const _iMTxtR=' coins';
    const _iMW=ctx.measureText(_iMTxt).width, _iMWR=ctx.measureText(_iMTxtR).width;
    const _iMTotalW=_iMW+8+_iMWR;
    const _iMStartX=W/2-_iMTotalW/2;
    ctx.textAlign='left';
    ctx.fillText(_iMTxt,_iMStartX,CY+cardH-4);
    _coinIco(_iMStartX+_iMW+4,CY+cardH-9,4);
    ctx.fillText(_iMTxtR,_iMStartX+_iMW+10,CY+cardH-4);
    ctx.textAlign='center';
    ctx.restore();
  }
}

/* ══════════════════════════════════════════════
   DRAW — HOW TO PLAY SCREEN  (5-page slideshow)
══════════════════════════════════════════════ */
function drawHowTo(){
  // Same scrolling bg as intro — reuse cached gradients
  if(!GC.introSky){const s=ctx.createLinearGradient(0,0,0,H*0.45);s.addColorStop(0,'#04060a');s.addColorStop(1,'#0b0e1e');GC.introSky=s;}
  if(!GC.introRoad){const r=ctx.createLinearGradient(0,H*0.42,0,H);r.addColorStop(0,'#14182a');r.addColorStop(1,'#1e222e');GC.introRoad=r;}
  ctx.fillStyle=GC.introSky;ctx.fillRect(0,0,W,H);
  ctx.fillStyle=GC.introRoad;ctx.fillRect(0,H*0.42,W,H);
  ctx.save();ctx.globalAlpha=0.18;ctx.strokeStyle='rgba(255,255,255,0.5)';ctx.lineWidth=1.5;
  ctx.setLineDash([26,18]);
  [80,160,240,320].forEach(x=>{
    ctx.lineDashOffset=-(menuScrollY*1.4)%44;
    ctx.beginPath();ctx.moveTo(x,H*0.42);ctx.lineTo(x,H);ctx.stroke();
  });
  ctx.setLineDash([]);ctx.restore();
  ctx.fillStyle='rgba(4,6,14,0.72)';ctx.fillRect(0,0,W,H);

  const pages=[
    {
      col:'#fbbf24', icon:'🎮', title:'CONTROLS',
      lines:[
        {icon:'←→', text:'Swipe left or right anywhere on screen to change lane'},
        {icon:'↑',  text:'Swipe up anywhere on screen to jump over obstacles'},
        {icon:'👆', text:'Tap left half of screen = move left  ·  Tap right half = move right'},
        {icon:'💡', text:'Tapping the top third of screen also triggers a jump'},
      ]
    },
    {
      col:'#4ade80', icon:'🎯', title:'OBJECTIVE',
      lines:[
        {icon:'⏱', text:'Survive as long as possible — your score climbs automatically'},
        {icon:'🚀', text:'Every new Stage increases your speed — things get harder fast'},
        {icon:'♥',  text:'Every 2 stages completed = +1 free life awarded (max 3 ♥)'},
        {icon:'💫', text:'Score 300+ on your last life? You get ONE LAST CHANCE — tap within 10s to revive (one per run)'},
      ]
    },
    {
      col:'#f97316', icon:'⚡', title:'SCORE FASTER',
      lines:[
        {icon:'😤', text:'CLOSE CALL — pass within 1 lane of an enemy = bonus points'},
        {icon:'🔥', text:'3 close calls in a row = COMBO ×2  (×3 at 6,  ×4 at 10)'},
        {icon:'⚡', text:'Grab a NITRO power-up for 2× score multiplier for ~3s'},
        {icon:'👻', text:'GHOST power-up phases through ALL hazards — cars, obstacles & cattle — for 3 seconds'},
      ]
    },
    {
      col:'#fbbf24', icon:'💰', title:'EARN COINS',
      lines:[
        {icon:'⭐', text:'Collect gold coins on the road — spend them in the Shop'},
        {icon:'🧲', text:'MAGNET power-up automatically pulls all nearby coins to you'},
        {icon:'📋', text:'Complete the daily Mission for bonus coins — see intro screen'},
        {icon:'🛡',  text:'Shield absorbs 1 crash and gives you a +30 score bonus — the blue bubble shows it is active'},
      ]
    },
    {
      col:'#ef4444', icon:'🚨', title:'SURVIVE TIPS',
      lines:[
        {icon:'🎓', text:'Stages 1–3: Learn lane-switching — only cars, then rocks & manholes'},
        {icon:'🐄', text:'Stage 4+: Cattle appear — choose to jump or switch before they cross'},
        {icon:'🛣', text:'Stage 6+: Oil slick locks lanes ~2s, Wrecks block TWO lanes at once'},
        {icon:'🚧', text:'Stage 8+: Roadworks close lane 4, Boss pursues — plan exits early'},
      ]
    },
  ];

  // Card
  const CW=352,CX=(W-CW)/2,CY=10,cardH=H-20;
  const page=pages[clamp(howtoPage,0,pages.length-1)];
  const col=page.col;

  ctx.save();
  ctx.fillStyle='rgba(6,9,22,0.97)';rr(CX,CY,CW,cardH,14);ctx.fill();
  ctx.shadowColor=col;ctx.shadowBlur=18;
  ctx.strokeStyle=col+'88';ctx.lineWidth=1.5;rr(CX,CY,CW,cardH,14);ctx.stroke();
  ctx.restore();

  // ── Header ──
  ctx.save();ctx.textAlign='center';ctx.textBaseline='middle';
  ctx.font="900 18px 'Orbitron',impact,sans-serif";
  ctx.shadowColor='#3b82f6';ctx.shadowBlur=14;ctx.fillStyle='#93c5fd';
  ctx.fillText('HOW  TO  PLAY',W/2,CY+26);
  ctx.shadowBlur=0;

  // Page indicator dots
  pages.forEach((_,i)=>{
    const dotX=W/2+(i-2)*18;
    ctx.beginPath();ctx.arc(dotX,CY+44,i===howtoPage?5:3,0,Math.PI*2);
    ctx.fillStyle=i===howtoPage?col:'rgba(255,255,255,0.18)';
    if(i===howtoPage){ctx.shadowColor=col;ctx.shadowBlur=10;}
    ctx.fill();ctx.shadowBlur=0;
  });
  ctx.restore();

  // Divider
  ctx.save();ctx.strokeStyle=col+'44';ctx.lineWidth=1;
  ctx.beginPath();ctx.moveTo(CX+16,CY+56);ctx.lineTo(CX+CW-16,CY+56);ctx.stroke();
  ctx.restore();

  // ── Page title ──
  const contentTop=CY+62;
  ctx.save();
  // Big central icon
  const igx=W/2,igy=contentTop+28;
  ctx.globalAlpha=1;
  ctx.font="44px -apple-system,'Segoe UI Emoji','Apple Color Emoji',sans-serif";
  ctx.textAlign='center';ctx.textBaseline='middle';
  ctx.fillStyle='#ffffff';
  ctx.fillText(page.icon,igx,igy);
  // Title
  ctx.font="900 20px 'Orbitron',impact,sans-serif";
  ctx.textBaseline='middle';
  ctx.fillStyle=col;ctx.shadowColor=col;ctx.shadowBlur=18;
  ctx.fillText(page.title,W/2,contentTop+70);
  ctx.shadowBlur=0;
  // Divider line under title
  ctx.strokeStyle=col+'44';ctx.lineWidth=1;
  ctx.beginPath();ctx.moveTo(CX+32,contentTop+85);ctx.lineTo(CX+CW-32,contentTop+85);ctx.stroke();
  ctx.restore();

  // ── Word-wrap helper ──
  function wrapText(text, maxW){
    const words=text.split(' ');
    const lines=[];
    let cur='';
    words.forEach(w=>{
      const test=cur?cur+' '+w:w;
      if(ctx.measureText(test).width<=maxW){cur=test;}
      else{if(cur)lines.push(cur);cur=w;}
    });
    if(cur)lines.push(cur);
    return lines;
  }

  // ── Bullet lines ──
  const lineStart=contentTop+96;
  const lineH=14;       // px per text line
  const rowPad=10;      // vertical padding inside each row
  const bsz=30;         // icon bubble size
  const textStartX=CX+18+bsz+10; // x where text begins
  const textMaxW=CW-18-bsz-10-14; // max text width before right edge

  // Pre-measure each item to get row heights
  ctx.font="600 11px 'Rajdhani',sans-serif";
  const rowData=page.lines.map(ln=>{
    const wrappedLines=wrapText(ln.text,textMaxW);
    const rowH=Math.max(bsz+rowPad*2, wrappedLines.length*lineH+rowPad*2);
    return{ln,wrappedLines,rowH};
  });

  let curY=lineStart;
  rowData.forEach(({ln,wrappedLines,rowH},i)=>{
    ctx.save();
    // Row background
    ctx.globalAlpha=i%2===0?0.08:0.04;
    ctx.fillStyle='#fff';
    rr(CX+10,curY,CW-20,rowH,6);ctx.fill();
    ctx.globalAlpha=1;

    // Icon bubble — vivid fill so it's clearly visible
    const bx=CX+18, by=curY+rowH/2-bsz/2;
    // Bubble background — solid tinted fill
    ctx.fillStyle=col+'44';rr(bx,by,bsz,bsz,7);ctx.fill();
    ctx.strokeStyle=col+'cc';ctx.lineWidth=1.5;
    ctx.shadowColor=col;ctx.shadowBlur=8;
    rr(bx,by,bsz,bsz,7);ctx.stroke();
    ctx.shadowBlur=0;
    // Emoji icon — explicit white fill + emoji font stack
    ctx.font="17px -apple-system,'Segoe UI Emoji','Apple Color Emoji',sans-serif";
    ctx.textAlign='center';ctx.textBaseline='middle';
    ctx.fillStyle='#ffffff';
    ctx.globalAlpha=1;
    ctx.fillText(ln.icon,bx+bsz/2,by+bsz/2);

    // Text lines — properly wrapped, fully opaque
    ctx.font="600 11px 'Rajdhani',sans-serif";
    ctx.textAlign='left';ctx.textBaseline='top';
    ctx.fillStyle='rgba(226,232,240,1)';
    const textBlockH=wrappedLines.length*lineH;
    const textTopY=curY+rowH/2-textBlockH/2;
    wrappedLines.forEach((wl,wi)=>{
      ctx.fillText(wl,textStartX,textTopY+wi*lineH);
    });

    ctx.restore();
    curY+=rowH+4;
  });

  // ── Left / Right nav buttons ──
  const navY=CY+cardH-70;
  ctx.save();ctx.strokeStyle=col+'22';ctx.lineWidth=1;
  ctx.beginPath();ctx.moveTo(CX+16,navY);ctx.lineTo(CX+CW-16,navY);ctx.stroke();
  ctx.restore();

  // Left arrow button
  const lbW=64,lbH=34,lbX=CX+16,lbY=navY+10;
  const hasLeft=howtoPage>0;
  ctx.save();
  ctx.fillStyle=hasLeft?'rgba(20,30,70,0.88)':'rgba(15,20,40,0.40)';
  rr(lbX,lbY,lbW,lbH,9);ctx.fill();
  ctx.strokeStyle=hasLeft?'rgba(99,179,237,0.70)':'rgba(99,179,237,0.20)';ctx.lineWidth=1.3;
  rr(lbX,lbY,lbW,lbH,9);ctx.stroke();
  ctx.textAlign='center';ctx.textBaseline='middle';
  ctx.font="bold 12px 'Orbitron',sans-serif";
  ctx.fillStyle=hasLeft?'#93c5fd':'rgba(147,197,253,0.28)';
  ctx.fillText('◀',lbX+lbW/2,lbY+lbH/2);
  ctx.restore();

  // Right arrow button
  const rbW=64,rbH=34,rbX=CX+CW-rbW-16,rbY=navY+10;
  const hasRight=howtoPage<pages.length-1;
  ctx.save();
  ctx.fillStyle=hasRight?'rgba(20,30,70,0.88)':'rgba(15,20,40,0.40)';
  rr(rbX,rbY,rbW,rbH,9);ctx.fill();
  ctx.strokeStyle=hasRight?'rgba(99,179,237,0.70)':'rgba(99,179,237,0.20)';ctx.lineWidth=1.3;
  rr(rbX,rbY,rbW,rbH,9);ctx.stroke();
  ctx.textAlign='center';ctx.textBaseline='middle';
  ctx.font="bold 12px 'Orbitron',sans-serif";
  ctx.fillStyle=hasRight?'#93c5fd':'rgba(147,197,253,0.28)';
  ctx.fillText('▶',rbX+rbW/2,rbY+rbH/2);
  ctx.restore();

  // Back button — center
  const bbW=100,bbH=34,bbX=W/2-bbW/2,bbY=navY+10;
  ctx.save();
  ctx.fillStyle='rgba(20,30,80,0.88)';rr(bbX,bbY,bbW,bbH,9);ctx.fill();
  ctx.strokeStyle='rgba(99,179,237,0.55)';ctx.lineWidth=1.2;rr(bbX,bbY,bbW,bbH,9);ctx.stroke();
  ctx.textAlign='center';ctx.textBaseline='middle';
  ctx.font="bold 9px 'Orbitron',sans-serif";ctx.fillStyle='#93c5fd';
  ctx.fillText('← BACK',W/2,bbY+bbH/2);
  ctx.restore();

  // Footer hint
  ctx.save();ctx.textAlign='center';ctx.textBaseline='bottom';
  ctx.font="600 8px 'Rajdhani',sans-serif";ctx.fillStyle='rgba(100,116,139,0.55)';
  ctx.fillText('page '+(howtoPage+1)+' / '+pages.length,W/2,CY+cardH-4);
  ctx.restore();
}

function drawRevive(){
  const secs=Math.ceil(reviveTimer/60);
  ctx.fillStyle='rgba(0,0,0,0.82)';ctx.fillRect(0,0,W,H);
  const PW=300,PH=220,PX=(W-PW)/2,PY=(H-PH)/2-10;
  drawGlassPanel(PX,PY,PW,PH,16,'#ef4444');
  ctx.textAlign='center';
  ctx.font="900 22px 'Orbitron',impact,sans-serif";ctx.fillStyle='#ef4444';ctx.shadowColor='#ef4444';ctx.shadowBlur=14;
  ctx.fillText('ONE LAST CHANCE',W/2,PY+42);ctx.shadowBlur=0;
  // Countdown ring
  const cx=W/2,cy=PY+110,radius=32;
  ctx.save();
  ctx.strokeStyle='rgba(255,255,255,0.15)';ctx.lineWidth=6;
  ctx.beginPath();ctx.arc(cx,cy,radius,0,Math.PI*2);ctx.stroke();
  const prog=(reviveTimer/600)*Math.PI*2;
  ctx.strokeStyle='#ef4444';ctx.lineWidth=6;ctx.shadowColor='#ef4444';ctx.shadowBlur=12;
  ctx.beginPath();ctx.arc(cx,cy,radius,-Math.PI/2,-Math.PI/2+prog);ctx.stroke();
  ctx.shadowBlur=0;
  ctx.font="900 20px 'Orbitron',impact,sans-serif";ctx.fillStyle='#f8fafc';ctx.textAlign='center';ctx.textBaseline='middle';
  ctx.fillText(secs,cx,cy);ctx.textBaseline='alphabetic';
  ctx.restore();
  ctx.font="bold 10px 'Orbitron',sans-serif";ctx.fillStyle='#94a3b8';ctx.textAlign='center';
  ctx.fillText('Score: '+Math.floor(score),W/2,PY+158);
  ctx.font="bold 12px 'Orbitron',sans-serif";ctx.fillStyle='#4ade80';
  ctx.shadowColor='#4ade80';ctx.shadowBlur=10;ctx.fillText('TAP to CONTINUE (FREE)',W/2,PY+185);ctx.shadowBlur=0;
  ctx.font="600 9px 'Rajdhani',sans-serif";ctx.fillStyle='#475569';
  ctx.fillText('or wait to end run',W/2,PY+202);
}

function drawGameOver(){
  const _finalScore=Math.floor(score);
  const isBest=_finalScore>=bestScore&&bestScore>0;
  const soClose=!isBest&&bestScore>0&&(bestScore-_finalScore)<bestScore*0.15&&_finalScore>0;
  const poorRun=bestScore>0&&_finalScore<bestScore*0.50&&!isBest&&!soClose;
  const PW=308,PH=410,PX=(W-PW)/2,PY=(H-PH)/2-20;
  // Background dim — muted for poor runs, dramatic for bests
  const _dimAlpha=poorRun?0.55:0.75;
  ctx.fillStyle=`rgba(0,0,0,${_dimAlpha})`;ctx.fillRect(0,0,W,H);
  const _panelCol=isBest?'#fbbf24':soClose?'#f59e0b':'#ef4444';
  drawGlassPanel(PX,PY,PW,PH,16,_panelCol);
  ctx.textAlign='center';
  // Headline — changes based on emotional context
  let _headline,_hlCol,_hlSize;
  if(isBest){       _headline='NEW RECORD!';  _hlCol='#fbbf24'; _hlSize='22';}
  else if(soClose){ _headline='SO CLOSE!';    _hlCol='#f59e0b'; _hlSize='26';}
  else if(poorRun){ _headline='GAME OVER';    _hlCol='#64748b'; _hlSize='22';}
  else{             _headline='GAME OVER';    _hlCol='#ef4444'; _hlSize='26';}
  ctx.font=`900 ${_hlSize}px 'Orbitron',impact,sans-serif`;
  ctx.fillStyle=_hlCol;ctx.shadowColor=_hlCol;ctx.shadowBlur=poorRun?8:18;
  ctx.fillText(_headline,W/2,PY+46);ctx.shadowBlur=0;
  // SO CLOSE — show the gap
  if(soClose){
    const _gap=bestScore-_finalScore;
    ctx.font="bold 9px 'Orbitron',sans-serif";ctx.fillStyle='#fcd34d';
    ctx.fillText(_gap+' MORE POINT'+(Math.abs(_gap)!==1?'S':'')+' FOR BEST!',W/2,PY+62);
  }

  // Score row
  const _scoreY=soClose?PY+80:PY+72;
  ctx.font="bold 18px 'Orbitron',impact,sans-serif";
  ctx.fillStyle=poorRun?'#94a3b8':'#f8fafc';
  ctx.fillText(_finalScore,W/2,_scoreY);
  ctx.font="600 9px 'Rajdhani',sans-serif";ctx.fillStyle='#64748b';
  ctx.fillText('SCORE',W/2,_scoreY+14);

  // Divider
  const _divY=soClose?PY+98:PY+96;
  ctx.strokeStyle='rgba(255,255,255,0.08)';ctx.lineWidth=1;
  ctx.beginPath();ctx.moveTo(PX+16,_divY);ctx.lineTo(PX+PW-16,_divY);ctx.stroke();

  // Run stats grid
  const runDist=parseFloat((distanceTravelled/15120).toFixed(2));
  const stats=[
    ['Near-Misses',runNearMisses,'#f97316'],
    ['Best Streak',runMaxCombo+'×','#ef4444'],
    ['Coins','+'+sessionCoins,'#fbbf24'],
    ['Cattle Dodged',runCattleDodged,'#4ade80'],
    ['Distance',runDist+'km','#06b6d4'],
  ];
  stats.forEach(([k,v,c],i)=>{
    const ry=(soClose?PY+118:PY+116)+i*22;
    ctx.font="600 10px 'Rajdhani',sans-serif";ctx.fillStyle='#94a3b8';ctx.textAlign='right';ctx.fillText(k,W/2-4,ry);
    ctx.font="bold 10px 'Orbitron',sans-serif";ctx.fillStyle=c;ctx.textAlign='left';ctx.fillText(v,W/2+6,ry);
  });

  // Divider
  ctx.strokeStyle='rgba(255,255,255,0.08)';ctx.lineWidth=1;
  ctx.beginPath();ctx.moveTo(PX+16,PY+230);ctx.lineTo(PX+PW-16,PY+230);ctx.stroke();

  // Best stats
  ctx.font="600 10px 'Rajdhani',sans-serif";ctx.fillStyle='#94a3b8';ctx.textAlign='right';ctx.fillText('Best Score',W/2-4,PY+252);
  ctx.font="bold 10px 'Orbitron',sans-serif";ctx.fillStyle=isBest?'#fbbf24':'#f8fafc';ctx.textAlign='left';ctx.fillText(bestScore,W/2+6,PY+252);
  ctx.font="600 10px 'Rajdhani',sans-serif";ctx.fillStyle='#94a3b8';ctx.textAlign='right';ctx.fillText('Best Distance',W/2-4,PY+272);
  ctx.font="bold 10px 'Orbitron',sans-serif";ctx.fillStyle='#06b6d4';ctx.textAlign='left';ctx.fillText(bestDistance.toFixed(2)+'km',W/2+6,PY+272);
  ctx.font="bold 10px 'Orbitron',sans-serif";ctx.fillStyle='#fbbf24';ctx.textAlign='right';ctx.fillText('Coins Bank',W/2-4,PY+292);
  ctx.textAlign='left';_coinIco(W/2+6+5,PY+292-3,5);ctx.fillStyle='#fbbf24';ctx.fillText(' '+coinBank,W/2+6+12,PY+292);

  // Mission reminder
  if(activeMission){
    ctx.font="600 9px 'Rajdhani',sans-serif";ctx.fillStyle='#475569';ctx.textAlign='center';
    ctx.fillText('MISSION: '+activeMission.text,W/2,PY+318);
  }

  // ── RETRY + MENU buttons ──
  const rbW=132,rbH=34,rbX=W/2-rbW-6,rbY=PY+PH-54;
  const mbW=132,mbH=34,mbX=W/2+6,mbY=PY+PH-54;
  if(!GC.goRetryGrad){
    const rG=ctx.createLinearGradient(rbX,rbY,rbX,rbY+rbH);
    rG.addColorStop(0,'rgba(220,30,30,0.35)');rG.addColorStop(1,'rgba(140,10,10,0.25)');
    GC.goRetryGrad=rG;
    const mG=ctx.createLinearGradient(mbX,mbY,mbX,mbY+mbH);
    mG.addColorStop(0,'rgba(20,80,180,0.35)');mG.addColorStop(1,'rgba(10,40,120,0.25)');
    GC.goMenuGrad=mG;
  }
  ctx.save();
  const retryPulse=0.80+fastSin(frameCount*0.09)*0.20;
  ctx.globalAlpha=retryPulse;
  ctx.fillStyle=GC.goRetryGrad;rr(rbX,rbY,rbW,rbH,9);ctx.fill();
  ctx.strokeStyle='#ef4444';ctx.lineWidth=1.8;
  ctx.shadowColor='#ef4444';ctx.shadowBlur=14;
  rr(rbX,rbY,rbW,rbH,9);ctx.stroke();
  ctx.shadowBlur=0;
  ctx.font="bold 11px 'Orbitron',sans-serif";ctx.fillStyle='#fca5a5';
  ctx.textAlign='center';ctx.textBaseline='middle';
  ctx.fillText('↺  RETRY',rbX+rbW/2,rbY+rbH/2);
  ctx.restore();
  // Menu button
  ctx.save();
  ctx.globalAlpha=0.88;
  ctx.fillStyle=GC.goMenuGrad;rr(mbX,mbY,mbW,mbH,9);ctx.fill();
  ctx.strokeStyle='#60a5fa';ctx.lineWidth=1.8;
  ctx.shadowColor='#3b82f6';ctx.shadowBlur=10;
  rr(mbX,mbY,mbW,mbH,9);ctx.stroke();
  ctx.shadowBlur=0;
  ctx.font="bold 11px 'Orbitron',sans-serif";ctx.fillStyle='#93c5fd';
  ctx.textAlign='center';ctx.textBaseline='middle';
  ctx.fillText('⌂  MENU',mbX+mbW/2,mbY+mbH/2);
  ctx.restore();
  ctx.textAlign='left';
  _drawGoBtns();
}

